// ============================================
// @elitegrid/core — Grid Events
// All events that flow through the Event Bus
// ============================================

export enum GridEvent {
  // ── Data Events ──────────────────────────
  // Fired when data is loaded or changed

  DATA_SET = 'data:set',
  // Fired when entirely new data is loaded into the grid
  // Payload: { rows: unknown[], totalCount: number }

  DATA_CHANGED = 'data:changed',
  // Fired when existing rows are mutated (add, update, delete)
  // Payload: { type: 'add' | 'update' | 'delete', rowId?: RowId }

  DATA_LOADING = 'data:loading',
  // Fired when an async data fetch starts
  // Payload: none

  DATA_LOAD_ERROR = 'data:loadError',
  // Fired when an async data fetch fails
  // Payload: { error: Error }

  DATA_REFRESH_REQUESTED = 'data:refreshRequested',
  // Fired when a manual refresh is requested
  // Payload: none

  ROW_ADDED = 'data:rowAdded',
  // Fired when a single row is added
  // Payload: { row: unknown, index: number }

  ROW_UPDATED = 'data:rowUpdated',
  // Fired when a single row is updated
  // Payload: { rowId: RowId, changes: Partial<unknown> }

  ROW_DELETED = 'data:rowDeleted',
  // Fired when a single row is deleted
  // Payload: { rowId: RowId }

  // ── Sort Events ───────────────────────────

  SORT_REQUESTED = 'sort:requested',
  // Fired when user clicks a column header or API sets sort
  // Payload: { sortModel: SortModel[] }

  SORT_COMPLETED = 'sort:completed',
  // Fired when sort pipeline finishes processing
  // Payload: { sortModel: SortModel[], rowCount: number }

  // ── Filter Events ─────────────────────────

  FILTER_REQUESTED = 'filter:requested',
  // Fired when user sets a filter or API sets filter model
  // Payload: { filterModel: FilterModel }

  FILTER_COMPLETED = 'filter:completed',
  // Fired when filter pipeline finishes processing
  // Payload: { filterModel: FilterModel, matchCount: number }

  // ── Pagination Events ─────────────────────

  PAGE_CHANGED = 'pagination:pageChanged',
  // Fired when the current page changes
  // Payload: { page: number, pageSize: number }

  PAGE_SIZE_CHANGED = 'pagination:pageSizeChanged',
  // Fired when the number of rows per page changes
  // Payload: { pageSize: number }

  PAGINATED_DATA_CHANGED = 'pagination:dataChanged',
  // Fired internally when paginated rows change
  // ViewportPlugin listens to this
  // Payload: none

  // ── Selection Events ──────────────────────

  ROW_CLICK_SELECTION = 'selection:rowClick',
  // Fired by adapter when a row is clicked (with modifier key state)
  // Payload: { rowId: RowId, shiftKey: boolean, ctrlKey: boolean, metaKey: boolean }

  CHECKBOX_ROW_CHANGED = 'selection:checkboxRow',
  // Fired by adapter when a row checkbox is toggled
  // Payload: { rowId: RowId, checked: boolean }

  SELECT_ALL_TOGGLED = 'selection:selectAllToggled',
  // Fired by adapter when the header select-all checkbox is toggled
  // Payload: { checked: boolean }

  SELECTION_CHANGED = 'selection:changed',
  // Fired by SelectionPlugin when any row selection changes
  // Payload: { selectedIds: Set<RowId>, count: number }

  SELECT_ALL_CHANGED = 'selection:selectAllChanged',
  // Fired by SelectionPlugin when isAllSelected / isIndeterminate changes
  // Payload: { isAllSelected: boolean, isIndeterminate: boolean }

  // ── Edit Events ───────────────────────────

  // ── Edit request events (fired by adapter) ──
  EDIT_START_REQUESTED = 'edit:startRequested',
  // Fired by adapter on double-click
  // Payload: { cell: CellPosition }

  EDIT_VALUE_CHANGED = 'edit:valueChanged',
  // Fired by adapter as user types
  // Payload: { cell: CellPosition, value: unknown }

  EDIT_COMMIT_REQUESTED = 'edit:commitRequested',
  // Fired by adapter on Enter / Tab / blur
  // Payload: { cell: CellPosition }

  EDIT_CANCEL_REQUESTED = 'edit:cancelRequested',
  // Fired by adapter on Escape
  // Payload: { cell: CellPosition }

  // ── Edit outcome events (fired by EditPlugin) ──
  EDIT_STARTED = 'edit:started',
  // Fired when a cell enters edit mode
  // Payload: { cell: CellPosition, originalValue: unknown, editorType: EditorType, editorConfig: ColumnEditorConfig | null }

  EDIT_COMMITTED = 'edit:committed',
  // Fired when an edit is saved successfully
  // Payload: { cell: CellPosition, newValue: unknown, oldValue: unknown }

  EDIT_CANCELLED = 'edit:cancelled',
  // Fired when an edit is discarded
  // Payload: { cell: CellPosition, originalValue: unknown }

  EDIT_VALIDATION_FAILED = 'edit:validationFailed',
  // Fired when validation rejects a value
  // Payload: { cell: CellPosition, value: unknown, error: string }

  // ROW_UPDATED already defined above ('data:rowUpdated')
  // EditPlugin reuses it — Payload adds columnId, newValue, oldValue

  // ── Column Events ─────────────────────────

  COLUMN_VISIBILITY_CHANGED = 'column:visibilityChanged',
  // Fired when a column is shown or hidden
  // Payload: { columnId: ColumnId, visible: boolean }

  COLUMN_RESIZED = 'column:resized',
  // Fired when a column width changes
  // Payload: { columnId: ColumnId, width: number }

  COLUMN_REORDERED = 'column:reordered',
  // Fired when columns are rearranged
  // Payload: { columnIds: ColumnId[] }

  COLUMN_PINNED_CHANGED = 'column:pinnedChanged',
  // Fired when a column pin state changes
  // Payload: { columnId: ColumnId, pinned: PinPosition }

  // ── Viewport Events ───────────────────────

  CONTAINER_RESIZED = 'viewport:containerResized',
  // Fired by adapter when grid container size changes
  // Adapter uses ResizeObserver to detect changes
  // Payload: { width: number, height: number }

  VIEWPORT_CHANGED = 'viewport:changed',
  // Fired when the set of visible rows or columns changes
  // Adapter must re-render when it receives this
  // Payload: { startRowIndex: number, endRowIndex: number }

  SCROLL_CHANGED = 'viewport:scrollChanged',
  // Fired when scroll position changes
  // Payload: { scrollTop: number, scrollLeft: number }

  // ── Focus Events ──────────────────────────

  FOCUS_SET_REQUESTED = 'focus:setRequested',
  // Request to move focus to a specific cell
  // Emitted by adapter (click) or EditPlugin (after commit)
  // Payload: { cell: CellPosition }

  FOCUS_MOVE_REQUESTED = 'focus:moveRequested',
  // Request to move focus relative to current position
  // Emitted by adapter keyboard handler and GridCellEditor (Tab)
  // Payload: { direction: 'up' | 'down' | 'left' | 'right' | 'next' | 'prev' | 'rowStart' | 'rowEnd' | 'first' | 'last', editableOnly?: boolean }

  FOCUS_CHANGED = 'focus:changed',
  // Fired by FocusPlugin when focused cell changes
  // Adapter updates tabIndex and DOM focus
  // EditPlugin listens — if editing, commits before focus moves
  // Payload: { cell: CellPosition | null, previousCell: CellPosition | null }

  FOCUS_CLEARED = 'focus:cleared',
  // Fired when focus leaves the grid entirely
  // Payload: {}

  // ── Export Events ────────────────────────

  EXPORT_REQUESTED = 'export:requested',
  // Fired by adapter (e.g. button click) to trigger an export
  // Payload: { format: 'csv', scope: 'all' | 'filtered' | 'selected' | 'page', filename?: string }

  EXPORT_STARTED = 'export:started',
  // Fired when ExportPlugin begins processing
  // Payload: { format: 'csv', rowCount: number }

  EXPORT_COMPLETED = 'export:completed',
  // Fired when export file is ready for download
  // Payload: { format: 'csv', rowCount: number, filename: string }

  // ── Accessibility Events ──────────────────

  ANNOUNCE = 'a11y:announce',
  // Fired when screen reader should announce something
  // Adapter updates aria-live region
  // Payload: { message: string, priority: 'polite' | 'assertive' }

  // ── Lifecycle Events ──────────────────────

  GRID_READY = 'lifecycle:ready',
  // Fired when engine is fully initialized
  // Adapter exposes Grid API to developer after this
  // Payload: none

  GRID_DESTROYED = 'lifecycle:destroyed',
  // Fired when engine is destroyed and cleaned up
  // Adapter removes DOM elements and event listeners
  // Payload: none
}
