// ============================================
// @elitegrid/vanilla — createGrid
// Factory function — builds and configures
// the engine kernel with all plugins.
//
// Identical kernel/plugin wiring as the React adapter,
// minus React-only types. The framework-free adapter
// just consumes the same engine via mount().
// ============================================

import {
  Kernel,
  DataSourcePlugin,
  RowModelPlugin,
  ColumnModelPlugin,
  FilterPlugin,
  SortPlugin,
  PaginationPlugin,
  ViewportPlugin,
  SelectionPlugin,
  EditPlugin,
  CellValuePlugin,
  FocusPlugin,
  AnnouncementPlugin,
  ExportPlugin,
  GridEvent,
} from '@elitegrid/core'

import type { IDataSource, SortDirection } from '@elitegrid/core'

// ─────────────────────────────────────────────
// SECTION 1 — Column Definition
// ─────────────────────────────────────────────

export interface ColumnDef<TData = unknown> {
  field: Extract<keyof TData, string> | string
  header: string

  size?: {
    width?: number
    minWidth?: number
    maxWidth?: number
    flex?: number
    resizable?: boolean
  }

  display?: {
    pinned?: 'left' | 'right' | null
    visible?: boolean
    cellClass?: string | ((value: unknown, row: TData) => string)
    headerClass?: string
    formatter?: (value: unknown, row: TData) => string
    exportFormatter?: (value: unknown, row: TData) => string
  }

  sort?: {
    enabled?: boolean
    defaultDirection?: SortDirection
    comparator?: (a: unknown, b: unknown) => number
    nullsFirst?: boolean
  }

  filter?: {
    enabled?: boolean
    type?: 'text' | 'number' | 'date' | 'boolean'
    customFilter?: (value: unknown, row: TData) => boolean
  }

  edit?: {
    enabled?: boolean | ((row: TData) => boolean)
    type?: 'text' | 'number' | 'dropdown' | 'date' | 'boolean'
    minDate?: Date
    maxDate?: Date
    options?: string[]
    min?: number
    max?: number
    parser?: (value: string) => unknown
    validator?: (
      value: unknown,
      row: TData
    ) => string | null | Promise<string | null>
  }

  value?: {
    getter?: (row: TData) => unknown
    setter?: (row: TData, value: unknown) => TData
  }
}

// ─────────────────────────────────────────────
// SECTION 2 — Grid Options
// ─────────────────────────────────────────────
// Note: appearance.emptyState.icon / loadingComponent / errorComponent
// are typed as `unknown` here (vs React.ReactNode / React.ComponentType
// in the React adapter). At render time, the vanilla overlay accepts a
// pre-built HTMLElement, a string, or a (container, ...args) renderer.

export type VanillaNode = HTMLElement | string | null | undefined

export type VanillaRenderer<TArgs extends unknown[] = []> = (
  container: HTMLElement,
  ...args: TArgs
) => void

export interface GridOptions<TData = unknown> {
  columns: ColumnDef<TData>[]
  data?: TData[]
  dataSource?: IDataSource<TData>

  rowId?: keyof TData | ((row: TData) => string)

  sorting?: {
    enabled?: boolean
    multiSort?: boolean
    multiSortKey?: 'shift' | 'ctrl'
    defaultDirection?: SortDirection
    nullsFirst?: boolean
  }

  filtering?: {
    enabled?: boolean
    caseSensitive?: boolean
    debounceMs?: number
    iconPosition?: 'left' | 'right'
    showIconOnHover?: boolean
    filterIcon?: VanillaNode
    activeFilterIcon?: VanillaNode
    popoverPlacement?: 'bottom' | 'top' | 'auto'
  }

  pagination?: {
    enabled?: boolean
    pageSize?: number
    pageSizeOptions?: number[]
    showPageSizeSelector?: boolean
    showRowCount?: boolean
    showPageNumbers?: boolean
  }

  selection?: {
    mode?: 'none' | 'single' | 'multiple'
    selectAllScope?: 'page' | 'all'
    showCheckboxes?: boolean
    selectOnRowClick?: boolean
    checkboxOnly?: boolean
  }

  editing?: {
    enabled?: boolean
    trigger?: 'click' | 'doubleClick'
    confirmOnEnter?: boolean
    cancelOnEscape?: boolean
    moveOnTab?: boolean
  }

  appearance?: {
    theme?: 'light' | 'dark' | 'auto'
    density?: 'compact' | 'normal' | 'comfortable'
    rowHeight?: number
    headerHeight?: number
    rowStriping?: boolean
    showColumnBorders?: boolean
    showHoverHighlight?: boolean
    className?: string
    style?: Partial<CSSStyleDeclaration>

    emptyState?: {
      title?: string
      description?: string
      icon?: VanillaNode
    }
    filteredEmptyState?: {
      title?: string
      description?: string
      icon?: VanillaNode
    }
    emptyStateComponent?: VanillaRenderer

    loadingState?: { message?: string }
    loadingComponent?: VanillaRenderer

    errorComponent?: VanillaRenderer<[Error]>
  }

  scroll?: { bufferSize?: number }

  export?: {
    filename?: string
    scope?: 'all' | 'filtered' | 'page' | 'selected'
  }

  accessibility?: {
    gridLabel?: string
    announceFocus?: boolean
    announceSort?: boolean
    announceFilter?: boolean
    announceSelection?: boolean
    announceEdit?: boolean
    announcePage?: boolean
  }

  events?: {
    onReady?: (api: GridAPI<TData>) => void
    onRowClick?: (row: TData, event: MouseEvent) => void
    onRowDoubleClick?: (row: TData, event: MouseEvent) => void
    onEditStart?: (rowId: string, field: string) => void
    onEditCommit?: (rowId: string, field: string, value: unknown) => void
    onEditCancel?: (rowId: string, field: string) => void
    onSortChange?: (
      model: Array<{ columnId: string; direction: SortDirection }>
    ) => void
    onFilterChange?: (model: Record<string, unknown>) => void
    onSelectionChange?: (rows: TData[]) => void
    onPageChange?: (page: number, pageSize: number) => void
    onColumnResize?: (columnId: string, width: number) => void
    onColumnReorder?: (columnIds: string[]) => void
    onColumnVisibilityChange?: (columnId: string, visible: boolean) => void
    onRowAdd?: (row: TData) => void
    onRowUpdate?: (id: string, changes: Partial<TData>) => void
    onRowDelete?: (id: string) => void
    onScrollChange?: (scrollTop: number, scrollLeft: number) => void
  }
}

// ─────────────────────────────────────────────
// SECTION 3 — Supporting Types
// ─────────────────────────────────────────────

export interface ColumnState {
  columnId: string
  width: number
  visible: boolean
  pinned: 'left' | 'right' | null
  index: number
}

export interface PaginationState {
  currentPage: number
  pageSize: number
  totalRows: number
  totalPages: number
  startRow: number
  endRow: number
  hasNextPage: boolean
  hasPreviousPage: boolean
}

// ─────────────────────────────────────────────
// SECTION 4 — Grid API (identical to React)
// ─────────────────────────────────────────────

export interface GridAPI<TData = unknown> {
  setData(rows: TData[]): void
  getData(): TData[]
  getDisplayedRows(): TData[]
  refreshData(): Promise<void>
  addRow(row: TData, index?: number): void
  updateRow(id: string, changes: Partial<TData>): void
  deleteRow(id: string): void
  deleteRows(ids: string[]): void

  setColumnVisible(id: string, visible: boolean): void
  setColumnWidth(id: string, width: number): void
  setColumnPinned(id: string, position: 'left' | 'right' | null): void
  moveColumn(id: string, toIndex: number): void
  getAllColumns(): ColumnDef<TData>[]
  getVisibleColumns(): ColumnDef<TData>[]
  getColumnState(): ColumnState[]
  applyColumnState(state: ColumnState[]): void

  setSortModel(
    model: Array<{ columnId: string; direction: SortDirection }>
  ): void
  getSortModel(): Array<{ columnId: string; direction: SortDirection }>
  clearSort(): void

  setFilterModel(model: Record<string, unknown>): void
  getFilterModel(): Record<string, unknown>
  setColumnFilter(columnId: string, filter: unknown): void
  clearColumnFilter(columnId: string): void
  clearFilters(): void

  selectRow(id: string): void
  deselectRow(id: string): void
  toggleRow(id: string): void
  selectAll(): void
  deselectAll(): void
  isRowSelected(id: string): boolean
  getSelectedRows(): TData[]
  getSelectedIds(): Set<string>

  startEditing(rowId: string, columnId: string): void
  stopEditing(save?: boolean): void
  isEditing(): boolean
  getEditingCell(): {
    rowId: string
    columnId: string
    rowIndex: number
    columnIndex: number
  } | null

  setPage(page: number): void
  setPageSize(size: number): void
  nextPage(): void
  previousPage(): void
  firstPage(): void
  lastPage(): void
  getPaginationState(): PaginationState

  scrollToRow(rowId: string): void
  scrollToColumn(columnId: string): void
  scrollToCell(rowId: string, columnId: string): void

  exportCSV(options?: {
    filename?: string
    scope?: 'all' | 'filtered' | 'page' | 'selected'
  }): void

  destroy(): void
}

// ─────────────────────────────────────────────
// SECTION 5 — Grid Instance
// ─────────────────────────────────────────────

export interface GridInstance<TData = unknown> {
  readonly kernel: Kernel
  readonly options: GridOptions<TData>
  readonly plugins: {
    dataSource: DataSourcePlugin<TData>
    rowModel: RowModelPlugin
    columnModel: ColumnModelPlugin
    filter: FilterPlugin
    sort: SortPlugin
    pagination: PaginationPlugin
    viewport: ViewportPlugin
    selection: SelectionPlugin
    edit: EditPlugin
    cellValue: CellValuePlugin
    focus: FocusPlugin
    announcement: AnnouncementPlugin
    export: ExportPlugin
  }
  updateEvents(events: GridOptions<TData>['events']): void
}

// ─────────────────────────────────────────────
// SECTION 6 — Row-id accessor
// ─────────────────────────────────────────────
// Honours all three forms of GridOptions.rowId: a field name, a function,
// or the default 'id' field. Returns undefined when the field is missing so
// callers can fall back to a synthetic key. Shared by createGrid internals,
// buildGridAPI, and GridBody so the adapter and engine always agree on IDs.

export function makeRowIdAccessor<TData>(
  rowId: GridOptions<TData>['rowId']
): (row: TData) => string | undefined {
  if (typeof rowId === 'function') {
    return (row) => String(rowId(row))
  }
  const field = (rowId as string | undefined) ?? 'id'
  return (row) => {
    const v = (row as Record<string, unknown>)?.[field]
    return v == null ? undefined : String(v)
  }
}

// ─────────────────────────────────────────────
// SECTION 6b — normalizeColumns (internal)
// ─────────────────────────────────────────────

function normalizeColumns<TData>(
  columns: ColumnDef<TData>[],
  options: GridOptions<TData>
) {
  return columns.map((col) => ({
    id: col.field as string,
    field: col.field as string,
    header: col.header,
    width: col.size?.width,
    minWidth: col.size?.minWidth,
    maxWidth: col.size?.maxWidth,
    flex: col.size?.flex,
    resizable: col.size?.resizable ?? true,
    pinned: col.display?.pinned ?? null,
    visible: col.display?.visible ?? true,
    sortable: col.sort?.enabled ?? options.sorting?.enabled ?? true,
    filterable: col.filter?.enabled ?? options.filtering?.enabled ?? true,
    comparator: col.sort?.comparator,
    editable: col.edit?.enabled
      ? typeof col.edit.enabled === 'function'
        ? true
        : col.edit.enabled
      : false,
  }))
}

// ─────────────────────────────────────────────
// SECTION 7 — createGrid
// ─────────────────────────────────────────────

export function createGrid<TData = unknown>(
  options: GridOptions<TData>
): GridInstance<TData> {
  const kernel = new Kernel()

  const dataSourcePlugin = new DataSourcePlugin<TData>()
  const rowModelPlugin = new RowModelPlugin()
  const columnModelPlugin = new ColumnModelPlugin()
  const filterPlugin = new FilterPlugin()
  const sortPlugin = new SortPlugin()
  const paginationPlugin = new PaginationPlugin()
  const viewportPlugin = new ViewportPlugin()
  const selectionPlugin = new SelectionPlugin()
  const editPlugin = new EditPlugin()
  const cellValuePlugin = new CellValuePlugin()
  const focusPlugin = new FocusPlugin()
  const exportPlugin = new ExportPlugin()
  const announcementPlugin = new AnnouncementPlugin({
    announce: {
      focus: options.accessibility?.announceFocus ?? true,
      sort: options.accessibility?.announceSort ?? true,
      filter: options.accessibility?.announceFilter ?? true,
      page: options.accessibility?.announcePage ?? true,
      selection: options.accessibility?.announceSelection ?? true,
      edit: options.accessibility?.announceEdit ?? true,
    },
  })

  dataSourcePlugin.configure({
    data: options.data,
    dataSource: options.dataSource,
    pageSize: options.pagination?.pageSize,
    // Pass rowId so DataSourcePlugin.updateRow/deleteRow match rows by the
    // configured id field — otherwise they default to 'id' and silently fail
    // when a custom rowId is used (mirrors the React and Vue adapters).
    rowId: options.rowId as string | ((row: unknown) => string) | undefined,
  })

  rowModelPlugin.configure({
    rowId: options.rowId as string | ((row: unknown) => string) | undefined,
  })

  columnModelPlugin.configure({
    columns: normalizeColumns(options.columns, options),
    defaultWidth: 150,
    defaultMinWidth: 50,
    defaultResizable: true,
    defaultSortable: options.sorting?.enabled ?? true,
    defaultFilterable: options.filtering?.enabled ?? true,
  })

  filterPlugin.configure({
    caseSensitive: options.filtering?.caseSensitive ?? false,
    debounceMs: options.filtering?.debounceMs ?? 300,
  })

  sortPlugin.configure({
    multiSort: options.sorting?.multiSort ?? true,
    multiSortKey: options.sorting?.multiSortKey ?? 'shift',
    defaultDirection: options.sorting?.defaultDirection ?? 'asc',
    nullsFirst: options.sorting?.nullsFirst ?? false,
  })

  paginationPlugin.configure({
    enabled: options.pagination?.enabled ?? false,
    pageSize: options.pagination?.pageSize ?? 25,
    pageSizeOptions: options.pagination?.pageSizeOptions ?? [10, 25, 50, 100],
  })

  editPlugin.configure({ validator: undefined })

  selectionPlugin.configure({
    mode: options.selection?.mode ?? 'none',
    selectAllScope: options.selection?.selectAllScope ?? 'page',
    deselectOnClick: true,
  })

  viewportPlugin.configure({
    rowHeight: options.appearance?.rowHeight ?? 40,
    headerHeight: options.appearance?.headerHeight ?? 44,
    bufferSize: options.scroll?.bufferSize ?? 10,
  })

  kernel.register(dataSourcePlugin)
  kernel.register(rowModelPlugin)
  kernel.register(columnModelPlugin)
  kernel.register(filterPlugin)
  kernel.register(sortPlugin)
  kernel.register(paginationPlugin)
  kernel.register(viewportPlugin)
  kernel.register(selectionPlugin)
  kernel.register(focusPlugin)
  kernel.register(announcementPlugin)
  kernel.register(cellValuePlugin)
  kernel.register(exportPlugin)
  kernel.register(editPlugin)

  kernel.init()

  const getRowId = makeRowIdAccessor<TData>(options.rowId)

  // O(1) row lookup — kept in sync via raw-namespace subscription below.
  const rowIndexMap = new Map<string, number>()
  const rebuildRowIndexMap = (rows: unknown[]) => {
    rowIndexMap.clear()
    rows.forEach((r, i) => {
      const id = getRowId(r as TData)
      if (id !== undefined) rowIndexMap.set(id, i)
    })
  }
  rebuildRowIndexMap(kernel.store.read('raw').rows)
  // Keep map in sync whenever the raw dataset changes (add/remove/setData).
  kernel.store.subscribe('raw', () => {
    rebuildRowIndexMap(kernel.store.read('raw').rows)
  })

  // Tab-edit chain: FOCUS_MOVE_REQUESTED(editableOnly) → focus moves →
  // FOCUS_CHANGED → open editor on the new cell. Counter-based so rapid Tabs
  // do not collapse into a single edit-start.
  let pendingEditCount = 0
  kernel.eventBus.on(GridEvent.FOCUS_MOVE_REQUESTED, (payload: any) => {
    if (payload.editableOnly) pendingEditCount++
  })
  kernel.eventBus.on(GridEvent.FOCUS_CHANGED, (payload: any) => {
    if (pendingEditCount <= 0) return
    pendingEditCount--
    const { cell } = payload
    if (!cell) return
    kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
  })

  // Register per-column value config from ColumnDef into CellValuePlugin
  options.columns.forEach((col) => {
    const hasConfig =
      col.value?.getter ||
      col.value?.setter ||
      col.display?.formatter ||
      col.display?.exportFormatter ||
      col.edit?.parser
    if (!hasConfig) return
    cellValuePlugin.registerColumnConfig(col.field as string, {
      getter: col.value?.getter
        ? (row) => col.value!.getter!(row as any)
        : undefined,
      setter: col.value?.setter
        ? (row, value) => col.value!.setter!(row as any, value as any)
        : undefined,
      formatter: col.display?.formatter
        ? (value, row) => col.display!.formatter!(value, row as any)
        : undefined,
      exportFormatter: col.display?.exportFormatter
        ? (value, row) => col.display!.exportFormatter!(value, row as any)
        : undefined,
      parser: col.edit?.parser ? (raw) => col.edit!.parser!(raw) : undefined,
    })
  })

  // Register column editors for editable columns
  options.columns.forEach((col) => {
    if (!col.edit?.enabled) return
    const colDef = kernel.store
      .read('columns')
      .definitions.find((d) => d.field === col.field)
    if (!colDef) return
    const typeMap: Record<string, string> = {
      text: 'text',
      number: 'number',
      dropdown: 'select',
      date: 'date',
      boolean: 'boolean',
    }
    const editorType = typeMap[col.edit.type ?? 'text'] ?? 'text'
    editPlugin.registerColumnEditor(colDef.id, {
      type: editorType as any,
      options: col.edit.options?.map((o) => ({ label: String(o), value: o })),
      min: col.edit.min,
      max: col.edit.max,
      minDate: col.edit.minDate,
      maxDate: col.edit.maxDate,
      validator: async (value, cell) => {
        // O(1) lookup via rowIndexMap (raw rows flow through the pipeline by
        // reference) instead of an O(n) scan per keystroke.
        const idx = rowIndexMap.get(cell.rowId)
        const row =
          idx !== undefined
            ? ((kernel.store.read('raw').rows as any[])[idx] ?? {})
            : {}

        if (
          col.edit?.type === 'number' &&
          value !== null &&
          value !== undefined &&
          value !== ''
        ) {
          if (typeof value === 'number' && !Number.isFinite(value)) {
            return { valid: false, error: 'Must be a valid number' }
          }
          const num = Number(value)
          if (isNaN(num)) {
            return { valid: false, error: 'Must be a valid number' }
          }
          if (col.edit.min !== undefined && num < col.edit.min) {
            return { valid: false, error: `Must be at least ${col.edit.min}` }
          }
          if (col.edit.max !== undefined && num > col.edit.max) {
            return { valid: false, error: `Must be at most ${col.edit.max}` }
          }
        }

        if (col.edit?.type === 'date' && value) {
          const date = value instanceof Date ? value : new Date(value as string)
          if (isNaN(date.getTime()))
            return { valid: false, error: 'Invalid date' }
          if (col.edit.minDate && date < col.edit.minDate) {
            return {
              valid: false,
              error: `Date must be after ${col.edit.minDate.toLocaleDateString()}`,
            }
          }
          if (col.edit.maxDate && date > col.edit.maxDate) {
            return {
              valid: false,
              error: `Date must be before ${col.edit.maxDate.toLocaleDateString()}`,
            }
          }
        }

        if (col.edit?.validator) {
          const err = await col.edit.validator(value, row as any)
          if (err) return { valid: false, error: err }
        }
        return { valid: true }
      },
    })
  })

  // ── Developer callback wiring ───────────────────────────────────
  kernel.eventBus.on(GridEvent.SORT_COMPLETED, (payload: any) => {
    options.events?.onSortChange?.(payload.sortModel ?? [])
  })
  kernel.eventBus.on(GridEvent.FILTER_COMPLETED, (payload: any) => {
    options.events?.onFilterChange?.(payload.filterModel ?? {})
  })
  // onPageChange — wired to the engine so it fires for BOTH programmatic
  // navigation (api.nextPage(), api.setPage(), …) and UI button clicks.
  // The GridPagination component must NOT also fire this, or it would
  // double-call the developer callback (mirrors the React adapter).
  kernel.eventBus.on(GridEvent.PAGE_CHANGED, (payload: any) => {
    options.events?.onPageChange?.(payload.page, payload.pageSize)
  })
  kernel.eventBus.on(GridEvent.PAGE_SIZE_CHANGED, (payload: any) => {
    const { currentPage } = kernel.store.read('paginated')
    options.events?.onPageChange?.(currentPage, payload.pageSize)
  })
  // onColumnResize — wired to the engine so it fires for both drag and API
  // (setColumnWidth). GridHeader must NOT also fire it (mirrors React).
  kernel.eventBus.on(GridEvent.COLUMN_RESIZED, (payload: any) => {
    options.events?.onColumnResize?.(payload.columnId, payload.width)
  })
  // onColumnReorder — fires when a column moves (drag or api.moveColumn())
  kernel.eventBus.on(GridEvent.COLUMN_REORDERED, (payload: any) => {
    options.events?.onColumnReorder?.(payload.columnIds)
  })
  // onColumnVisibilityChange — fires when a column is shown or hidden
  kernel.eventBus.on(GridEvent.COLUMN_VISIBILITY_CHANGED, (payload: any) => {
    options.events?.onColumnVisibilityChange?.(payload.columnId, payload.visible)
  })
  // onScrollChange — wired to the engine SCROLL_CHANGED event (GridBody emits
  // it on scroll); GridBody must NOT also fire it, or it would double-call.
  kernel.eventBus.on(GridEvent.SCROLL_CHANGED, (payload: any) => {
    options.events?.onScrollChange?.(payload.scrollTop, payload.scrollLeft)
  })
  // onRowAdd — fires when a row is added via addRow()
  kernel.eventBus.on(GridEvent.ROW_ADDED, (payload: any) => {
    options.events?.onRowAdd?.(payload.row as TData)
  })
  // onRowDelete — fires when a row is deleted via deleteRow()/deleteRows()
  kernel.eventBus.on(GridEvent.ROW_DELETED, (payload: any) => {
    options.events?.onRowDelete?.(payload.rowId)
  })
  // onRowUpdate — fires for programmatic updateRow() only, NOT internal edit
  // commits. ROW_UPDATED serves both; the programmatic path carries `changes`
  // while edit commits carry columnId + newValue (mirrors React).
  kernel.eventBus.on(GridEvent.ROW_UPDATED, (payload: any) => {
    if (payload?.changes !== undefined) {
      options.events?.onRowUpdate?.(payload.rowId, payload.changes)
    }
  })
  kernel.eventBus.on(GridEvent.EDIT_STARTED, (payload: any) => {
    options.events?.onEditStart?.(payload.cell.rowId, payload.cell.columnId)
  })
  kernel.eventBus.on(GridEvent.EDIT_COMMITTED, (payload: any) => {
    options.events?.onEditCommit?.(
      payload.cell.rowId,
      payload.cell.columnId,
      payload.newValue
    )
  })
  kernel.eventBus.on(GridEvent.EDIT_CANCELLED, (payload: any) => {
    options.events?.onEditCancel?.(payload.cell.rowId, payload.cell.columnId)
  })

  // ROW_UPDATED — persist edits into the raw store and rerun pipeline.
  // Uses rowIndexMap for O(1) lookup instead of scanning all rows.
  kernel.eventBus.on(GridEvent.ROW_UPDATED, (payload: any) => {
    const { rowId, columnId, newValue } = payload
    const { definitions } = kernel.store.read('columns')
    const col = definitions.find((d: any) => d.id === columnId)
    if (!col) return
    const idx = rowIndexMap.get(rowId)
    if (idx === undefined) return
    const { rows } = kernel.store.read('raw')
    const updated = [...(rows as any[])]
    updated[idx] = { ...(updated[idx] as any), [col.field]: newValue }
    // rowIndexMap is rebuilt by the raw-namespace subscriber triggered below.
    kernel.store.write('raw', { rows: updated })
    kernel.eventBus.emit(GridEvent.DATA_CHANGED, {})
  })

  // Selection change — map IDs back to plain TData and notify the developer.
  // Uses O(1) index lookups into raw rows instead of filtering all sorted rows.
  if (options.events?.onSelectionChange) {
    kernel.eventBus.on(GridEvent.SELECTION_CHANGED, () => {
      const selectedIds = selectionPlugin.getSelectedIds()
      const { rows } = kernel.store.read('raw')
      const rawRows = rows as TData[]
      const selected: TData[] = []
      for (const id of selectedIds) {
        const idx = rowIndexMap.get(id)
        if (idx !== undefined) selected.push(rawRows[idx]!)
      }
      options.events!.onSelectionChange!(selected)
    })
  }

  return {
    kernel,
    options,
    plugins: {
      dataSource: dataSourcePlugin,
      rowModel: rowModelPlugin,
      columnModel: columnModelPlugin,
      filter: filterPlugin,
      sort: sortPlugin,
      pagination: paginationPlugin,
      viewport: viewportPlugin,
      selection: selectionPlugin,
      edit: editPlugin,
      cellValue: cellValuePlugin,
      focus: focusPlugin,
      announcement: announcementPlugin,
      export: exportPlugin,
    },
    updateEvents(events: GridOptions<TData>['events']) {
      options.events = { ...options.events, ...events }
    },
  }
}

// ─────────────────────────────────────────────
// SECTION 8 — buildGridAPI
// ─────────────────────────────────────────────
// Pure data-API surface. Built once by mount() and handed to onReady.
// Mirrors React's Grid.tsx buildGridAPI exactly.

export function buildGridAPI<TData>(grid: GridInstance<TData>): GridAPI<TData> {
  const { plugins, kernel, options } = grid

  const getRowId = makeRowIdAccessor<TData>(options.rowId)

  const plainRows = (namespace: 'raw' | 'sorted' | 'paginated') =>
    kernel.store.read(namespace).rows as TData[]

  const rowId = (r: any): string => getRowId(r) ?? ''

  return {
    setData: (rows) => plugins.dataSource.setData(rows),
    getData: () => plainRows('raw'),
    getDisplayedRows: () => plainRows('paginated'),
    refreshData: async () => {
      kernel.eventBus.emit(GridEvent.DATA_REFRESH_REQUESTED)
    },
    addRow: (row, index) => plugins.dataSource.addRow(row, index),
    updateRow: (id, changes) =>
      plugins.dataSource.updateRow(id, changes as any),
    deleteRow: (id) => plugins.dataSource.deleteRow(id),
    deleteRows: (ids) => {
      if (ids.length === 0) return
      const idSet = new Set(ids)
      const { rows } = kernel.store.read('raw')
      const remaining = (rows as any[]).filter(
        (r: any) => !idSet.has(rowId(r))
      )
      kernel.store.write('raw', {
        rows: remaining,
        totalCount: remaining.length,
      })
      ids.forEach((id) =>
        kernel.eventBus.emit(GridEvent.ROW_DELETED, { rowId: id })
      )
      kernel.eventBus.emit(GridEvent.DATA_CHANGED, { type: 'delete' })
    },

    setColumnVisible: (id, visible) =>
      plugins.columnModel.setVisible(id, visible),
    setColumnWidth: (id, width) => plugins.columnModel.setWidth(id, width),
    setColumnPinned: (id, position) =>
      plugins.columnModel.setPinned(id, position),
    moveColumn: (id, toIndex) => plugins.columnModel.moveColumn(id, toIndex),
    getAllColumns: () => options.columns,
    getVisibleColumns: () => {
      const visibleIds = new Set(
        plugins.columnModel.getVisibleColumns().map((c: any) => c.id)
      )
      return options.columns.filter((c) => visibleIds.has(c.field as string))
    },
    getColumnState: () => plugins.columnModel.getColumnState() as any,
    applyColumnState: (state) =>
      plugins.columnModel.applyColumnState(state as any),

    setSortModel: (model) => plugins.sort.setSortModel(model as any),
    getSortModel: () => plugins.sort.getSortModel() as any,
    clearSort: () => plugins.sort.clearSort(),

    setFilterModel: (model) => plugins.filter.setFilterModel(model as any),
    getFilterModel: () => plugins.filter.getFilterModel() as any,
    setColumnFilter: (columnId, filter) =>
      plugins.filter.setColumnFilter(columnId, filter as any),
    clearColumnFilter: (columnId) => plugins.filter.clearColumnFilter(columnId),
    clearFilters: () => plugins.filter.clearAll(),

    selectRow: (id) => plugins.selection.selectRow(id),
    deselectRow: (id) => plugins.selection.deselectRow(id),
    toggleRow: (id) => plugins.selection.toggleRow(id),
    selectAll: () => plugins.selection.selectAll(),
    deselectAll: () => plugins.selection.deselectAll(),
    isRowSelected: (id) => plugins.selection.isSelected(id),
    getSelectedRows: () => {
      const ids = new Set(plugins.selection.getSelectedIds())
      return plainRows('sorted').filter((r) => ids.has(rowId(r)))
    },
    getSelectedIds: () => new Set(plugins.selection.getSelectedIds()),

    startEditing: (rId, columnId) => {
      const rows = plainRows('paginated')
      const rowIndex = rows.findIndex((r) => rowId(r) === rId)
      const { definitions } = kernel.store.read('columns')
      const columnIndex = (definitions as any[]).findIndex(
        (c: any) => c.id === columnId
      )
      if (rowIndex === -1 || columnIndex === -1) return
      plugins.edit.startEdit({ rowId: rId, columnId, rowIndex, columnIndex })
    },
    stopEditing: (save = true) => {
      if (save) plugins.edit.commitEdit()
      else plugins.edit.cancelEdit()
    },
    isEditing: () => plugins.edit.isEditing(),
    getEditingCell: () => plugins.edit.getEditingCell(),

    setPage: (page) => plugins.pagination.setPage(page),
    setPageSize: (size) => plugins.pagination.setPageSize(size),
    nextPage: () => plugins.pagination.nextPage(),
    previousPage: () => plugins.pagination.previousPage(),
    firstPage: () => plugins.pagination.firstPage(),
    lastPage: () => plugins.pagination.lastPage(),
    getPaginationState: () => plugins.pagination.getPaginationState() as any,

    scrollToRow: (rId) => {
      let index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
      if (index === -1) {
        const allRows = plainRows('sorted')
        const globalIndex = allRows.findIndex((r) => rowId(r) === rId)
        if (globalIndex === -1) return
        const pageSize = kernel.store.read('paginated').pageSize ?? 0
        if (pageSize > 0) {
          const targetPage = Math.floor(globalIndex / pageSize) + 1
          plugins.pagination.setPage(targetPage)
          index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
        }
      }
      if (index !== -1) plugins.viewport.scrollToRow(index)
    },
    scrollToColumn: (columnId) => plugins.viewport.scrollToColumn(columnId),
    scrollToCell: (rId, columnId) => {
      let index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
      if (index === -1) {
        const globalIndex = plainRows('sorted').findIndex(
          (r) => rowId(r) === rId
        )
        if (globalIndex !== -1) {
          const pageSize = kernel.store.read('paginated').pageSize ?? 0
          if (pageSize > 0) {
            plugins.pagination.setPage(Math.floor(globalIndex / pageSize) + 1)
            index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
          }
        }
      }
      if (index !== -1) plugins.viewport.scrollToRow(index)
      plugins.viewport.scrollToColumn(columnId)
    },

    exportCSV: (exportOptions) => {
      plugins.export.export({
        filename:
          exportOptions?.filename ?? options.export?.filename ?? 'export',
        scope: exportOptions?.scope ?? options.export?.scope ?? 'filtered',
      })
    },

    destroy: () => kernel.destroy(),
  }
}
