// ============================================
// @elitegrid/vanilla — GridPagination
// Page count, page size selector, and nav buttons.
// P-08: build DOM once in constructor; subsequent renders only mutate
// cached element refs instead of tearing down and rebuilding.
// ============================================

import { applyStyle, h, type Unsub } from '../utils/dom'
import type { GridInstance } from '../create-grid'

export class GridPagination {
  el: HTMLElement
  private unsubs: Unsub[] = []
  private renderRaf: number | null = null

  // Memoised page-number array — recomputed only when page or total changes.
  private cachedPageNums: Array<number | '...'> = []
  private cachedPageNumsTotal = -1
  private cachedPageNumsCurrent = -1

  // P-08: cached refs for in-place updates.
  private rowCountSpan: HTMLElement | null = null
  private rowCountRange: HTMLElement | null = null
  private rowCountTotal: HTMLElement | null = null
  private pageSizeSelect: HTMLSelectElement | null = null
  private btnFirst: HTMLButtonElement | null = null
  private btnPrev: HTMLButtonElement | null = null
  private btnNext: HTMLButtonElement | null = null
  private btnLast: HTMLButtonElement | null = null
  private pageButtonsContainer: HTMLElement | null = null
  private leftSection: HTMLElement | null = null
  private rightSection: HTMLElement | null = null
  private built = false

  constructor(private grid: GridInstance<unknown>) {
    this.el = h('div', {
      class: 'yg-pagination',
      style: {
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '8px 12px',
        borderTop: 'var(--eg-header-border, 1px solid #e5e7eb)',
        backgroundColor: 'var(--eg-header-bg, #f9fafb)',
        flexShrink: '0',
        gap: '8px',
        flexWrap: 'wrap',
      },
    })
    this.unsubs.push(
      grid.kernel.store.subscribe('paginated', () => this.scheduleRender())
    )
    this.render()
  }

  private scheduleRender(): void {
    if (this.renderRaf !== null) return
    this.renderRaf = requestAnimationFrame(() => {
      this.renderRaf = null
      this.render()
    })
  }

  private buttonBase(): Partial<CSSStyleDeclaration> {
    return {
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      height: '32px',
      minWidth: '32px',
      padding: '0 8px',
      border: '1px solid var(--eg-border, #e5e7eb)',
      borderRadius: '6px',
      backgroundColor: 'var(--eg-btn-bg, #ffffff)',
      color: 'var(--eg-btn-text, #374151)',
      fontSize: '0.875rem',
      cursor: 'pointer',
      userSelect: 'none',
      fontFamily: 'inherit',
    }
  }

  private getPageNumbers(
    currentPage: number,
    totalPages: number
  ): Array<number | '...'> {
    if (
      currentPage === this.cachedPageNumsCurrent &&
      totalPages === this.cachedPageNumsTotal
    ) {
      return this.cachedPageNums
    }
    this.cachedPageNumsCurrent = currentPage
    this.cachedPageNumsTotal = totalPages

    let pages: Array<number | '...'>
    if (totalPages <= 7) {
      pages = Array.from({ length: totalPages }, (_, i) => i + 1)
    } else {
      pages = []
      const showLeftEllipsis = currentPage > 3
      const showRightEllipsis = currentPage < totalPages - 2
      pages.push(1)
      if (showLeftEllipsis) pages.push('...')
      const start = Math.max(2, currentPage - 1)
      const end = Math.min(totalPages - 1, currentPage + 1)
      for (let i = start; i <= end; i++) pages.push(i)
      if (showRightEllipsis) pages.push('...')
      pages.push(totalPages)
    }
    this.cachedPageNums = pages
    return pages
  }

  private makeNavButton(label: string, title: string): HTMLButtonElement {
    const btn = h('button', {
      attrs: { title, 'aria-label': title },
      style: this.buttonBase(),
      text: label,
    }) as HTMLButtonElement
    return btn
  }

  private applyButtonEnabled(btn: HTMLButtonElement, enabled: boolean): void {
    btn.disabled = !enabled
    btn.style.opacity = enabled ? '' : '0.4'
    btn.style.cursor = enabled ? 'pointer' : 'not-allowed'
  }

  // Build the full DOM once — subsequent renders only mutate cached refs.
  private buildDOM(): void {
    const { options } = this.grid
    const pageSizeOptions = options.pagination?.pageSizeOptions ?? [
      10, 25, 50, 100,
    ]
    const showPageSizeSelector =
      options.pagination?.showPageSizeSelector ?? true
    const showRowCount = options.pagination?.showRowCount ?? true

    // ── Left section ──
    this.leftSection = h('div', {
      style: { display: 'flex', alignItems: 'center', gap: '12px' },
    })

    if (showRowCount) {
      // Built once as elements; render() only updates the two textContents —
      // no innerHTML parsing per pagination change.
      const strongStyle: Partial<CSSStyleDeclaration> = {
        color: 'var(--eg-text, #111827)',
      }
      this.rowCountRange = h('strong', { style: strongStyle })
      this.rowCountTotal = h('strong', { style: strongStyle })
      this.rowCountSpan = h(
        'span',
        {
          style: {
            fontSize: '0.875rem',
            color: 'var(--eg-muted-text, #6b7280)',
            whiteSpace: 'nowrap',
          },
        },
        ['Showing ', this.rowCountRange, ' of ', this.rowCountTotal]
      )
      this.leftSection.appendChild(this.rowCountSpan)
    }

    if (showPageSizeSelector) {
      const sel = h('select', {
        style: {
          height: '32px',
          padding: '0 8px',
          border: '1px solid var(--eg-border, #e5e7eb)',
          borderRadius: '6px',
          backgroundColor: 'var(--eg-btn-bg, #ffffff)',
          color: 'var(--eg-btn-text, #374151)',
          fontSize: '0.875rem',
          cursor: 'pointer',
          fontFamily: 'inherit',
        },
        on: {
          change: (e) => {
            const newSize = Number((e.target as HTMLSelectElement).value)
            this.grid.plugins.pagination.setPageSize(newSize)
            // onPageChange fires from the create-grid PAGE_SIZE_CHANGED
            // listener — not here — so it isn't double-called.
          },
        },
      }) as HTMLSelectElement
      pageSizeOptions.forEach((size: number) => {
        const opt = document.createElement('option')
        opt.value = String(size)
        opt.textContent = String(size)
        sel.appendChild(opt)
      })
      this.pageSizeSelect = sel
      const wrapper = h(
        'div',
        { style: { display: 'flex', alignItems: 'center', gap: '6px' } },
        [
          h('span', {
            style: {
              fontSize: '0.875rem',
              color: 'var(--eg-muted-text, #6b7280)',
              whiteSpace: 'nowrap',
            },
            text: 'Rows per page',
          }),
          sel,
        ]
      )
      this.leftSection.appendChild(wrapper)
    }

    // ── Right section ──
    this.rightSection = h('div', {
      style: { display: 'flex', alignItems: 'center', gap: '4px' },
    })

    this.btnFirst = this.makeNavButton('«', 'First page')
    this.btnFirst.addEventListener('click', () => {
      this.grid.plugins.pagination.firstPage()
    })

    this.btnPrev = this.makeNavButton('‹', 'Previous page')
    this.btnPrev.addEventListener('click', () => {
      this.grid.plugins.pagination.previousPage()
    })

    this.pageButtonsContainer = h('div', {
      style: { display: 'contents' },
    })

    this.btnNext = this.makeNavButton('›', 'Next page')
    this.btnNext.addEventListener('click', () => {
      this.grid.plugins.pagination.nextPage()
    })

    this.btnLast = this.makeNavButton('»', 'Last page')
    this.btnLast.addEventListener('click', () => {
      this.grid.plugins.pagination.lastPage()
    })

    this.rightSection.appendChild(this.btnFirst)
    this.rightSection.appendChild(this.btnPrev)
    this.rightSection.appendChild(this.pageButtonsContainer)
    this.rightSection.appendChild(this.btnNext)
    this.rightSection.appendChild(this.btnLast)

    this.el.appendChild(this.leftSection)
    this.el.appendChild(this.rightSection)

    this.built = true
  }

  private render(): void {
    const { options } = this.grid
    const pagination = this.grid.plugins.pagination.getPaginationState() as any
    const {
      currentPage,
      pageSize,
      totalPages,
      totalRows,
      startRow,
      endRow,
      hasNextPage,
      hasPreviousPage,
    } = pagination

    if (!options.pagination?.enabled) {
      this.el.style.display = 'none'
      return
    }
    this.el.style.display = 'flex'

    // Build skeleton once.
    if (!this.built) this.buildDOM()

    const showRowCount = options.pagination?.showRowCount ?? true
    const showPageNumbers = options.pagination?.showPageNumbers ?? true

    // ── Row count text ──
    if (showRowCount && this.rowCountSpan) {
      if (totalRows > 0) {
        if (this.rowCountRange)
          this.rowCountRange.textContent = `${startRow}–${endRow}`
        if (this.rowCountTotal)
          this.rowCountTotal.textContent = totalRows.toLocaleString()
        this.rowCountSpan.style.display = ''
      } else {
        this.rowCountSpan.style.display = 'none'
      }
    }

    // ── Page size selector ──
    if (this.pageSizeSelect) {
      const cur = String(pageSize)
      if (this.pageSizeSelect.value !== cur) this.pageSizeSelect.value = cur
    }

    // ── Nav buttons ──
    if (this.btnFirst) this.applyButtonEnabled(this.btnFirst, hasPreviousPage)
    if (this.btnPrev) this.applyButtonEnabled(this.btnPrev, hasPreviousPage)
    if (this.btnNext) this.applyButtonEnabled(this.btnNext, hasNextPage)
    if (this.btnLast) this.applyButtonEnabled(this.btnLast, hasNextPage)

    // ── Page number buttons — rebuild only when page/total changes ──
    if (showPageNumbers && this.pageButtonsContainer) {
      const pages = this.getPageNumbers(currentPage, totalPages)
      const container = this.pageButtonsContainer

      // Reconcile: reuse existing button children, add/remove as needed.
      const existingChildren = Array.from(container.childNodes)
      let i = 0
      for (const p of pages) {
        if (p === '...') {
          const el = existingChildren[i] as HTMLElement | undefined
          if (!el || el.tagName === 'BUTTON') {
            const span = h('span', {
              style: {
                padding: '0 4px',
                color: 'var(--eg-muted-text, #6b7280)',
                fontSize: '0.875rem',
                userSelect: 'none',
              },
              text: '...',
            })
            if (el) container.replaceChild(span, el)
            else container.appendChild(span)
            existingChildren[i] = span
          }
        } else {
          let btn = existingChildren[i] as HTMLButtonElement | undefined
          if (!btn || btn.tagName !== 'BUTTON') {
            btn = this.makeNavButton(String(p), `Page ${p}`)
            if (existingChildren[i])
              container.replaceChild(btn, existingChildren[i]!)
            else container.appendChild(btn)
            existingChildren[i] = btn
          }
          const isActive = p === currentPage
          btn.textContent = String(p)
          btn.title = `Page ${p}`
          btn.setAttribute('aria-label', `Page ${p}`)
          // Presence of aria-current is what AT keys on — it must be removed
          // (not set to '') on inactive buttons.
          if (isActive) btn.setAttribute('aria-current', 'page')
          else btn.removeAttribute('aria-current')
          btn.disabled = false
          btn.style.opacity = ''
          btn.style.cursor = 'pointer'
          btn.style.backgroundColor = isActive
            ? 'var(--eg-primary, #6366f1)'
            : 'var(--eg-btn-bg, #ffffff)'
          btn.style.borderColor = isActive
            ? 'var(--eg-primary, #6366f1)'
            : 'var(--eg-border, #e5e7eb)'
          btn.style.color = isActive
            ? 'var(--eg-primary-text, #ffffff)'
            : 'var(--eg-btn-text, #374151)'
          btn.style.fontWeight = isActive ? '600' : ''
          // Re-wire click for the correct page value.
          const pageNum = p as number
          btn.onclick = () => {
            this.grid.plugins.pagination.setPage(pageNum)
          }
        }
        i++
      }
      // Remove surplus children.
      while (container.childNodes.length > pages.length) {
        container.removeChild(container.lastChild!)
      }
    }
  }

  destroy(): void {
    if (this.renderRaf !== null) {
      cancelAnimationFrame(this.renderRaf)
      this.renderRaf = null
    }
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.el.remove()
  }
}
