// ============================================
// @elitegrid/vanilla — mount.ts
// Drops a fully-wired grid view into a container.
//
//   const grid = createGrid({ data, columns });
//   const dispose = mount(grid, document.getElementById('app')!);
//   // ...
//   dispose();
// ============================================

import type { GridInstance } from './create-grid'
import { buildGridAPI } from './create-grid'
import { GridView } from './components/Grid'

export interface MountOptions {
  // If true, calling dispose() will also destroy the kernel.
  // Default: false — kernel lifecycle is owned by the caller.
  destroyOnDispose?: boolean
}

export function mount<TData = unknown>(
  grid: GridInstance<TData>,
  container: HTMLElement,
  opts: MountOptions = {}
): () => void {
  if (!container) {
    throw new Error('[EliteGrid] mount() requires a non-null container element')
  }

  const api = buildGridAPI(grid)
  const view = new GridView(grid as GridInstance<unknown>, api as any)
  container.appendChild(view.el)

  let disposed = false

  // onReady fires once after the view is in the DOM so size-dependent
  // calls (scrollToRow, getPaginationState) see real measurements. Skipped
  // if dispose() ran before the microtask (e.g. an immediate unmount) —
  // otherwise the developer would receive an API bound to a destroyed view.
  queueMicrotask(() => {
    if (disposed) return
    grid.options.events?.onReady?.(api)
  })

  return function dispose() {
    if (disposed) return
    disposed = true
    view.destroy()
    if (opts.destroyOnDispose) grid.kernel.destroy()
  }
}
