// Minimal DOM helpers used across the vanilla adapter.
// No framework runtime, no diffing — just ergonomic creation
// and style application on real DOM nodes.

export type StyleProps = Partial<CSSStyleDeclaration> & Record<string, unknown>

export interface HProps {
  class?: string
  className?: string
  style?: StyleProps
  attrs?: Record<string, string | number | boolean | null | undefined>
  dataset?: Record<string, string | number | boolean | null | undefined>
  on?: Record<string, EventListenerOrEventListenerObject>
  text?: string
  html?: string
}

export function h<K extends keyof HTMLElementTagNameMap>(
  tag: K,
  props?: HProps,
  children?: Array<Node | string | null | undefined | false>
): HTMLElementTagNameMap[K] {
  const el = document.createElement(tag)
  if (props) applyProps(el, props)
  if (children) {
    for (const c of children) appendChild(el, c)
  }
  return el
}

export function applyProps(el: HTMLElement, props: HProps): void {
  if (props.class) el.className = props.class
  if (props.className) el.className = props.className
  if (props.style) applyStyle(el, props.style)
  if (props.attrs) {
    for (const k in props.attrs) {
      const v = props.attrs[k]
      if (v === false || v === null || v === undefined) el.removeAttribute(k)
      else el.setAttribute(k, String(v))
    }
  }
  if (props.dataset) {
    for (const k in props.dataset) {
      const v = props.dataset[k]
      if (v === null || v === undefined || v === false) delete el.dataset[k]
      else el.dataset[k] = String(v)
    }
  }
  if (props.on) {
    for (const k in props.on) {
      el.addEventListener(k, props.on[k]!)
    }
  }
  if (props.text !== undefined) el.textContent = props.text
  if (props.html !== undefined) el.innerHTML = props.html
}

export function applyStyle(el: HTMLElement, style: StyleProps): void {
  for (const k in style) {
    const v = style[k]
    if (v === undefined || v === null) {
      ;(el.style as any)[k] = ''
    } else {
      ;(el.style as any)[k] = typeof v === 'number' ? `${v}px` : String(v)
    }
  }
}

export function appendChild(
  parent: HTMLElement,
  child: Node | string | null | undefined | false
): void {
  if (child === null || child === undefined || child === false) return
  if (typeof child === 'string') {
    parent.appendChild(document.createTextNode(child))
  } else {
    parent.appendChild(child)
  }
}

export function clear(el: HTMLElement): void {
  while (el.firstChild) el.removeChild(el.firstChild)
}

export function setText(el: HTMLElement, text: string): void {
  if (el.textContent !== text) el.textContent = text
}

// Resolve capability once at module load — avoids a typeof check on every call.
const _cssEscape: (s: string) => string =
  typeof CSS !== 'undefined' && typeof CSS.escape === 'function'
    ? (s) => CSS.escape(s)
    : (s) => s.replace(/["\\[\]]/g, '\\$&')

export function cssEscape(s: string): string {
  return _cssEscape(s)
}

// Fast style writer for internal callers that already provide string values.
// Skips the typeof-number check that applyStyle performs on every property.
export function applyStyleRaw(
  el: HTMLElement,
  style: Record<string, string>
): void {
  for (const k in style) {
    ;(el.style as any)[k] = style[k]
  }
}

// Build an SVG element with attributes — used for icons.
export function svg(
  attrs: Record<string, string | number>,
  childrenHtml: string
): SVGSVGElement {
  const ns = 'http://www.w3.org/2000/svg'
  const el = document.createElementNS(ns, 'svg')
  for (const k in attrs) el.setAttribute(k, String(attrs[k]))
  el.innerHTML = childrenHtml
  return el
}

export type Unsub = () => void
