// ============================================
// @elitegrid/vanilla — GridHeader
// Column header row: labels, sort indicator, filter
// icon, resize handle, select-all checkbox.
// ============================================

import { GridEvent } from '@elitegrid/core'
import type { ColumnDefinition } from '@elitegrid/core'
import type { GridInstance } from '../create-grid'
import { clear, h, type Unsub } from '../utils/dom'
import { calculateColumnWidths } from '../utils/columnWidths'
import { GridFilterPopover, type FilterType } from './GridFilterPopover'

// Parse the default filter icon once at module load — cloneNode(true) on every
// header render instead of re-parsing the innerHTML string each time.
const _defaultFilterIconTemplate = (() => {
  const wrap = document.createElement('span')
  wrap.innerHTML =
    '<svg width="12" height="12" viewBox="0 0 12 12" fill="currentColor"><path d="M1 2h10L7 6.5V10.5L5 9.5V6.5L1 2z" /></svg>'
  return wrap
})()

function defaultFilterIcon(): HTMLElement {
  return _defaultFilterIconTemplate.cloneNode(true) as HTMLElement
}

function cloneIcon(node: unknown): HTMLElement {
  if (node instanceof HTMLElement) return node.cloneNode(true) as HTMLElement
  if (typeof node === 'string') {
    const wrap = document.createElement('span')
    wrap.textContent = node
    return wrap
  }
  return defaultFilterIcon()
}

export class GridHeader {
  el: HTMLElement
  private unsubs: Unsub[] = []
  private activeFilterColumnId: string | null = null
  private hoveredColumnId: string | null = null
  private resizingColumnId: string | null = null
  private didResize = false
  private dragAbort: AbortController | null = null
  private popover: GridFilterPopover | null = null
  private filterIconRefs = new Map<string, HTMLElement>()
  // Tracked sub-elements for partial in-place updates.
  private headerCellRefs = new Map<string, HTMLElement>()
  private sortIndicatorRefs = new Map<string, HTMLElement>()
  private resizeIndicatorRefs = new Map<string, HTMLElement>()
  private selectAllInput: HTMLInputElement | null = null
  // Column-width cache — avoids recalculating on every render call.
  private cachedHeaderContainerWidth = -1
  private cachedHeaderWidths = new Map<string, number>()
  // P-01: last containerWidth seen — skip full rebuild on scroll-only updates.
  private lastContainerWidth = -1
  // Last totalWidth seen — a column resize keeps containerWidth constant but
  // changes totalWidth, and the sticky header's minWidth must track it so the
  // header stays as wide as the scrollable body content.
  private lastTotalWidth = -1

  constructor(private grid: GridInstance<unknown>) {
    const { options } = grid
    const headerHeight = options.appearance?.headerHeight ?? 44
    // role="row" (not rowgroup): the cells appended directly to this element
    // are columnheaders, and the ARIA grid pattern requires columnheader to
    // sit inside a row. A grid may own rows directly, so no extra wrapper.
    this.el = h('div', {
      class: 'yg-header',
      attrs: { role: 'row' },
      style: {
        // Sticky inside the body's scroll container — stays pinned at the top
        // during vertical scroll and moves horizontally with the rows (same
        // scroll container), so header and rows stay aligned with zero JS sync.
        position: 'sticky',
        top: '0',
        zIndex: '2',
        height: `${headerHeight}px`,
        minHeight: `${headerHeight}px`,
        display: 'flex',
        flexDirection: 'row',
        borderBottom: 'var(--eg-header-border, 1px solid #e5e7eb)',
        backgroundColor: 'var(--eg-header-bg, #f9fafb)',
        flexShrink: '0',
        // minWidth (set in render) keeps the header at least as wide as the
        // scrollable content so columns extend to the right edge when scrolled.
      },
    })

    // Full re-render only when columns change or containerWidth changes.
    // Viewport fires on every scroll frame; guard with lastContainerWidth so
    // the header DOM is not rebuilt on scroll-only updates (P-01).
    this.unsubs.push(
      grid.kernel.store.subscribe('columns', () => {
        this.cachedHeaderContainerWidth = -1 // invalidate width cache
        this.render()
      }),
      grid.kernel.store.subscribe('viewport', () => {
        const { containerWidth, totalWidth } = grid.kernel.store.read('viewport')
        if (
          containerWidth === this.lastContainerWidth &&
          totalWidth === this.lastTotalWidth
        )
          return
        this.lastContainerWidth = containerWidth
        this.lastTotalWidth = totalWidth
        this.render()
      })
    )
    // Partial in-place updates for sort/filter/selection — avoids clearing and
    // rebuilding the entire header DOM on every page interaction.
    this.unsubs.push(
      grid.kernel.eventBus.on(GridEvent.SORT_COMPLETED, () =>
        this.updateSortIndicators()
      ),
      grid.kernel.eventBus.on(GridEvent.FILTER_COMPLETED, () =>
        this.updateFilterIcons()
      ),
      grid.kernel.eventBus.on(GridEvent.SELECTION_CHANGED, () =>
        this.updateSelectAll()
      )
    )

    this.render()
  }

  private render(): void {
    const { options } = this.grid
    const { definitions, order } = this.grid.kernel.store.read('columns')
    const { sortModel } = this.grid.kernel.store.read('sorted')
    const { containerWidth, totalWidth } =
      this.grid.kernel.store.read('viewport')
    const { filterModel } = this.grid.kernel.store.read('filtered')
    const { isAllSelected, isIndeterminate, mode } =
      this.grid.kernel.store.read('selection')

    const showCheckboxes =
      mode !== 'none' && (options.selection?.showCheckboxes ?? true)
    const filteringOptions = options.filtering
    const iconPosition = filteringOptions?.iconPosition ?? 'right'
    const showIconOnHover = filteringOptions?.showIconOnHover ?? false
    const popoverPlacement = filteringOptions?.popoverPlacement ?? 'auto'

    // P-07: cache column widths keyed by containerWidth.
    if (containerWidth !== this.cachedHeaderContainerWidth) {
      this.cachedHeaderContainerWidth = containerWidth
      this.cachedHeaderWidths = calculateColumnWidths(
        definitions,
        options.columns,
        containerWidth
      )
    }
    const columnWidths = this.cachedHeaderWidths

    // Keep the sticky header at least as wide as the scrollable body content
    // (data columns + checkbox column), so its columns extend to the right edge
    // and stay aligned with the rows as the user scrolls horizontally. Matches
    // the body spacer's scrollableWidth.
    const scrollableWidth = totalWidth + (showCheckboxes ? 48 : 0)
    this.lastTotalWidth = totalWidth
    this.el.style.minWidth = `${scrollableWidth}px`

    clear(this.el)
    // Reset tracked sub-element maps on full re-render.
    this.headerCellRefs.clear()
    this.sortIndicatorRefs.clear()
    this.resizeIndicatorRefs.clear()
    this.selectAllInput = null
    const validIds = new Set(definitions.map((d) => d.id))
    for (const key of this.filterIconRefs.keys()) {
      if (!validIds.has(key)) this.filterIconRefs.delete(key)
    }

    if (showCheckboxes) {
      this.el.appendChild(this.renderSelectAll(isAllSelected, isIndeterminate))
    }

    // P-06: build lookup maps once instead of O(n×m) per-column scans.
    const defMap = new Map(definitions.map((d) => [d.id, d]))
    const sortMap = new Map(
      (sortModel as Array<{ columnId: string; direction: string }>).map(
        (s, i) => [
          s.columnId,
          {
            direction: s.direction,
            index: sortModel.length > 1 ? i + 1 : null,
          },
        ]
      )
    )

    const visibleColumns = order
      .map((id) => defMap.get(id))
      .filter((c): c is ColumnDefinition => c != null && c.visible)

    visibleColumns.forEach((col) => {
      const sortEntry = sortMap.get(col.id)
      const direction = sortEntry?.direction ?? null
      const sortIndex = sortEntry?.index ?? null
      const isSorted = direction !== null
      const isSortable = col.sortable && options.sorting?.enabled !== false
      const isFilterable =
        col.filterable && options.filtering?.enabled !== false
      const isFiltered = col.id in filterModel.columns
      const isHovered = this.hoveredColumnId === col.id
      const isResizing = this.resizingColumnId === col.id
      const isResizable = col.resizable !== false
      const colWidth = columnWidths.get(col.id) ?? 150

      const showFilterIcon =
        isFilterable &&
        (!showIconOnHover ||
          isHovered ||
          isFiltered ||
          this.activeFilterColumnId === col.id)

      const cell = h('div', {
        class: [
          'yg-header-cell',
          isSorted ? 'yg-header-cell--sorted' : '',
          isSortable ? 'yg-header-cell--sortable' : '',
          isFiltered ? 'yg-header-cell--filtered' : '',
          isResizing ? 'yg-header-cell--resizing' : '',
        ]
          .filter(Boolean)
          .join(' '),
        attrs: {
          role: 'columnheader',
          'aria-sort':
            direction === 'asc'
              ? 'ascending'
              : direction === 'desc'
                ? 'descending'
                : 'none',
        },
        style: {
          width: `${colWidth}px`,
          minWidth: `${colWidth}px`,
          maxWidth: `${colWidth}px`,
          height: '100%',
          display: 'flex',
          alignItems: 'center',
          padding: '0 12px',
          cursor: isSortable ? 'pointer' : 'default',
          userSelect: 'none',
          fontWeight: '600',
          fontSize: '0.875rem',
          color: 'var(--eg-header-text, #374151)',
          borderRight: options.appearance?.showColumnBorders
            ? 'var(--eg-cell-border, 1px solid #e5e7eb)'
            : '',
          boxSizing: 'border-box',
          flexShrink: '0',
          gap: '4px',
          position: 'relative',
          backgroundColor: isResizing
            ? 'var(--eg-header-active-bg, #f3f4f6)'
            : '',
        },
        on: {
          mouseenter: () => {
            this.hoveredColumnId = col.id
            if (showIconOnHover) this.updateHoverIcon(col.id, true)
            this.updateResizeIndicatorHover(col.id, true)
          },
          mouseleave: () => {
            const prev = this.hoveredColumnId
            this.hoveredColumnId = null
            if (showIconOnHover && prev) this.updateHoverIcon(prev, false)
            if (prev) this.updateResizeIndicatorHover(prev, false)
          },
          click: () => {
            if (!isSortable) return
            if (options.sorting?.enabled === false) return
            if (this.didResize) return
            this.grid.plugins.sort.cycleSort(col.id)
          },
        },
      })

      // Filter icon. When the icon is NOT rendered this pass (hover-only mode,
      // column not hovered) drop its ref — otherwise the map keeps a detached
      // element and the filter popover would anchor to a node with a zero rect.
      let filterIcon: HTMLElement | null = null
      if (showFilterIcon) {
        filterIcon = this.renderFilterIcon(col, isFiltered, popoverPlacement)
      } else {
        this.filterIconRefs.delete(col.id)
        if (showIconOnHover) {
          filterIcon = h('div', { style: { width: '20px', flexShrink: '0' } })
        }
      }

      if (iconPosition === 'left' && filterIcon) cell.appendChild(filterIcon)

      // Label
      cell.appendChild(
        h('span', {
          style: {
            flex: '1',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          },
          text: col.header,
        })
      )

      // Sort indicator
      if (isSortable) {
        const ind = h('span', {
          class: 'yg-sort-indicator',
          attrs: { 'aria-hidden': 'true' },
          style: {
            opacity: isSorted ? '1' : '0.3',
            fontSize: '0.75rem',
            color: isSorted
              ? 'var(--eg-sort-active-color, #6366f1)'
              : 'var(--eg-sort-icon-color, #9ca3af)',
            display: 'flex',
            alignItems: 'center',
            gap: '2px',
            flexShrink: '0',
          },
          text:
            direction === 'asc' ? '↑' : direction === 'desc' ? '↓' : '',
        })
        if (sortIndex !== null) {
          ind.appendChild(
            h('span', {
              class: 'yg-sort-order',
              style: { fontSize: '0.65rem' },
              text: String(sortIndex),
            })
          )
        }
        cell.appendChild(ind)
        this.sortIndicatorRefs.set(col.id, ind)
      }

      if (iconPosition === 'right' && filterIcon) cell.appendChild(filterIcon)

      // Resize handle
      if (isResizable) {
        cell.appendChild(this.renderResizeHandle(col, isHovered, isResizing))
      }

      this.headerCellRefs.set(col.id, cell)
      this.el.appendChild(cell)
    })

    // The header rebuilt — the popover's anchor reference is now stale
    // (replaced by a fresh wrap element with the same column id). The
    // getter resolves to the new one, but the popover's *position* is still
    // computed from the previous render. Force a recalculation so the
    // popover stays glued to the (potentially moved) anchor.
    if (this.popover) this.popover.reposition()
  }

  // ── Partial in-place update methods (called by targeted event listeners) ──

  // P-04: targeted icon visibility on hover — avoids full header rebuild.
  private updateHoverIcon(columnId: string, hovered: boolean): void {
    const icon = this.filterIconRefs.get(columnId)
    if (!icon) return
    const { filterModel } = this.grid.kernel.store.read('filtered')
    const isFiltered = columnId in filterModel.columns
    const isActive = this.activeFilterColumnId === columnId
    if (isFiltered || isActive) return // already visible — nothing to change
    icon.style.opacity = hovered ? '1' : '0'
  }

  // Resize-handle hover feedback — the full render() only runs on column /
  // width changes, so hover state must be applied via the cached indicator
  // refs (same pattern as updateHoverIcon).
  private updateResizeIndicatorHover(columnId: string, hovered: boolean): void {
    if (this.resizingColumnId === columnId) return // drag styling owns it
    const ind = this.resizeIndicatorRefs.get(columnId)
    if (!ind) return
    ind.style.height = hovered ? '60%' : '30%'
    ind.style.backgroundColor = hovered
      ? 'var(--eg-border-hover, #d1d5db)'
      : 'var(--eg-border, #e5e7eb)'
  }

  private updateSortIndicators(): void {
    const { sortModel } = this.grid.kernel.store.read('sorted')
    // Mirror the full-render mapping: include the 1-based priority index, but
    // only when more than one column is sorted (matches render()).
    const sortMap = new Map(
      (sortModel as Array<{ columnId: string; direction: string }>).map(
        (s, i) => [
          s.columnId,
          {
            direction: s.direction,
            index: sortModel.length > 1 ? i + 1 : null,
          },
        ]
      )
    )
    this.sortIndicatorRefs.forEach((ind, colId) => {
      const entry = sortMap.get(colId)
      const direction = entry?.direction ?? null
      const sortIndex = entry?.index ?? null
      const isSorted = direction !== null
      ind.style.opacity = isSorted ? '1' : '0.3'
      ind.style.color = isSorted
        ? 'var(--eg-sort-active-color, #6366f1)'
        : 'var(--eg-sort-icon-color, #9ca3af)'
      // Update the arrow character (first text node). When the column starts
      // unsorted the arrow text is empty, so no text node exists yet — create
      // one so the arrow can appear on the first sort.
      let textNode = ind.firstChild
      if (!textNode || textNode.nodeType !== Node.TEXT_NODE) {
        textNode = document.createTextNode('')
        ind.insertBefore(textNode, ind.firstChild)
      }
      textNode.textContent =
        direction === 'asc' ? '↑' : direction === 'desc' ? '↓' : ''
      // Sync the multi-sort priority number — the full render adds it, but the
      // partial-update path must add/update/remove it as the model changes.
      let orderEl = ind.querySelector('.yg-sort-order') as HTMLElement | null
      if (sortIndex !== null) {
        if (!orderEl) {
          orderEl = h('span', {
            class: 'yg-sort-order',
            style: { fontSize: '0.65rem' },
          })
          ind.appendChild(orderEl)
        }
        orderEl.textContent = String(sortIndex)
      } else if (orderEl) {
        orderEl.remove()
      }
      // Update aria-sort on the parent header cell.
      const cell = this.headerCellRefs.get(colId)
      if (cell) {
        cell.setAttribute(
          'aria-sort',
          direction === 'asc'
            ? 'ascending'
            : direction === 'desc'
              ? 'descending'
              : 'none'
        )
        if (isSorted) cell.classList.add('yg-header-cell--sorted')
        else cell.classList.remove('yg-header-cell--sorted')
      }
    })
  }

  private updateFilterIcons(): void {
    const { filterModel } = this.grid.kernel.store.read('filtered')
    this.filterIconRefs.forEach((iconWrap, colId) => {
      const isFiltered = colId in filterModel.columns
      iconWrap.style.color = isFiltered
        ? 'var(--eg-primary, #6366f1)'
        : 'var(--eg-muted-text, #9ca3af)'
      iconWrap.style.backgroundColor = isFiltered
        ? 'var(--eg-primary-light, #eef2ff)'
        : this.activeFilterColumnId === colId
          ? 'var(--eg-hover-bg, #f3f4f6)'
          : 'transparent'
      const cell = this.headerCellRefs.get(colId)
      if (cell) {
        if (isFiltered) cell.classList.add('yg-header-cell--filtered')
        else cell.classList.remove('yg-header-cell--filtered')
      }
    })
  }

  private updateSelectAll(): void {
    if (!this.selectAllInput) return
    const { isAllSelected, isIndeterminate } =
      this.grid.kernel.store.read('selection')
    this.selectAllInput.checked = isAllSelected
    this.selectAllInput.indeterminate = isIndeterminate
  }

  // ──────────────────────────────────────────────────────────────────────────

  private renderSelectAll(
    isAllSelected: boolean,
    isIndeterminate: boolean
  ): HTMLElement {
    const { options } = this.grid
    const input = h('input', {
      attrs: {
        type: 'checkbox',
        'aria-label': 'Select all rows',
      },
      style: {
        cursor: 'pointer',
        width: '16px',
        height: '16px',
        accentColor: 'var(--eg-primary, #6366f1)',
      },
      on: {
        change: (e) => {
          this.grid.kernel.eventBus.emit(GridEvent.SELECT_ALL_TOGGLED, {
            checked: (e.target as HTMLInputElement).checked,
          })
        },
      },
    }) as HTMLInputElement
    input.checked = isAllSelected
    input.indeterminate = isIndeterminate
    this.selectAllInput = input
    return h(
      'div',
      {
        class: 'yg-header-cell yg-header-cell--checkbox',
        attrs: { role: 'columnheader', 'aria-label': 'Select all rows' },
        style: {
          width: '48px',
          minWidth: '48px',
          maxWidth: '48px',
          height: '100%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: '0',
          boxSizing: 'border-box',
          borderRight: options.appearance?.showColumnBorders
            ? 'var(--eg-cell-border, 1px solid #e5e7eb)'
            : '',
        },
      },
      [input]
    )
  }

  private renderFilterIcon(
    col: ColumnDefinition,
    isFiltered: boolean,
    placement: 'bottom' | 'top' | 'auto'
  ): HTMLElement {
    const { options } = this.grid
    const filteringOptions = options.filtering
    const showIconOnHover = filteringOptions?.showIconOnHover ?? false

    const iconSource = isFiltered
      ? (filteringOptions?.activeFilterIcon ?? filteringOptions?.filterIcon)
      : filteringOptions?.filterIcon
    const iconEl = cloneIcon(iconSource)

    const wrap = h('div', {
      attrs: {
        'aria-label': `Filter ${col.header}`,
        title: `Filter ${col.header}`,
      },
      style: {
        flexShrink: '0',
        width: '20px',
        height: '20px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        borderRadius: '4px',
        cursor: 'pointer',
        fontSize: '0.75rem',
        color: isFiltered
          ? 'var(--eg-primary, #6366f1)'
          : 'var(--eg-muted-text, #9ca3af)',
        backgroundColor: isFiltered
          ? 'var(--eg-primary-light, #eef2ff)'
          : this.activeFilterColumnId === col.id
            ? 'var(--eg-hover-bg, #f3f4f6)'
            : 'transparent',
        opacity:
          showIconOnHover && !isFiltered && this.hoveredColumnId !== col.id
            ? '0'
            : '1',
      },
      on: {
        click: (e) => {
          e.stopPropagation()
          if (this.activeFilterColumnId === col.id) {
            this.closePopover()
          } else {
            this.openPopover(col.id, placement)
          }
        },
      },
    })
    wrap.appendChild(iconEl)
    this.filterIconRefs.set(col.id, wrap)
    return wrap
  }

  private renderResizeHandle(
    col: ColumnDefinition,
    isHovered: boolean,
    isResizing: boolean
  ): HTMLElement {
    const indicator = h('div', {
      style: {
        width: '2px',
        height: isHovered || isResizing ? '60%' : '30%',
        borderRadius: '1px',
        backgroundColor: isResizing
          ? 'var(--eg-primary, #6366f1)'
          : isHovered
            ? 'var(--eg-border-hover, #d1d5db)'
            : 'var(--eg-border, #e5e7eb)',
      },
    })
    this.resizeIndicatorRefs.set(col.id, indicator)
    return h(
      'div',
      {
        class: 'yg-resize-handle',
        attrs: { 'aria-hidden': 'true' },
        style: {
          position: 'absolute',
          right: '-4px',
          top: '0',
          bottom: '0',
          width: '12px',
          cursor: 'col-resize',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: '2',
        },
        on: {
          mousedown: (e) => this.handleResizeMouseDown(e as MouseEvent, col),
          click: (e) => e.stopPropagation(),
        },
      },
      [indicator]
    )
  }

  private handleResizeMouseDown(e: MouseEvent, col: ColumnDefinition): void {
    e.preventDefault()
    e.stopPropagation()

    // Freeze every visible flex column at its CURRENT displayed pixel width
    // before the drag begins. Without this, the engine redistributes the
    // resized column's flex share across the other flex columns (so resizing
    // the last column would also widen the first). Once all columns are fixed,
    // dragging changes only the dragged column — the rest stay put and a
    // horizontal scrollbar absorbs the size change. The widths used here match
    // what's on screen, so freezing is visually seamless.
    const { definitions } = this.grid.kernel.store.read('columns')
    const { containerWidth } = this.grid.kernel.store.read('viewport')
    const displayWidths = calculateColumnWidths(
      definitions,
      this.grid.options.columns,
      containerWidth
    )
    const toFreeze = definitions
      .filter((d) => d.visible !== false && d.width == null)
      .map((d) => ({ columnId: d.id, width: displayWidths.get(d.id) ?? 150 }))
    if (toFreeze.length > 0) {
      this.grid.plugins.columnModel.applyColumnState(toFreeze)
    }

    // Use the displayed width as the drag origin — store.widths holds the
    // engine default (e.g. 150) for not-yet-frozen flex columns, which would
    // otherwise cause a jump on the first mouse move.
    const currentWidth = displayWidths.get(col.id) ?? col.width ?? 150
    const minWidth = col.minWidth ?? 50
    const maxWidth = col.maxWidth

    const state = {
      columnId: col.id,
      startX: e.clientX,
      startWidth: currentWidth,
      minWidth,
      maxWidth,
    }
    this.resizingColumnId = col.id
    this.didResize = false

    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'

    // B-04: update resize-state appearance via cached refs instead of full render.
    const cell = this.headerCellRefs.get(col.id)
    const ind = this.resizeIndicatorRefs.get(col.id)
    if (cell) cell.classList.add('yg-header-cell--resizing')
    if (ind) {
      ind.style.height = '60%'
      ind.style.backgroundColor = 'var(--eg-primary, #6366f1)'
    }

    const controller = new AbortController()
    this.dragAbort = controller
    const { signal } = controller

    // P-10: RAF-throttle engine writes so we cap at ~60 writes/s regardless
    // of mouse polling rate.
    let pendingWidth: number | null = null
    let moveRaf: number | null = null

    const handleMove = (mv: MouseEvent) => {
      this.didResize = true
      const delta = mv.clientX - state.startX
      let w = state.startWidth + delta
      w = Math.max(state.minWidth, w)
      if (state.maxWidth !== undefined) w = Math.min(state.maxWidth, w)
      pendingWidth = Math.floor(w)
      if (moveRaf !== null) return
      moveRaf = requestAnimationFrame(() => {
        moveRaf = null
        if (pendingWidth === null) return
        const cw = this.grid.kernel.store.read('viewport').containerWidth
        this.grid.plugins.columnModel.setWidth(state.columnId, pendingWidth, cw)
        pendingWidth = null
      })
    }

    const handleUp = (up: MouseEvent) => {
      if (moveRaf !== null) {
        cancelAnimationFrame(moveRaf)
        moveRaf = null
      }
      const delta = up.clientX - state.startX
      let finalWidth = state.startWidth + delta
      finalWidth = Math.max(state.minWidth, finalWidth)
      if (state.maxWidth !== undefined) {
        finalWidth = Math.min(state.maxWidth, finalWidth)
      }
      const cw = this.grid.kernel.store.read('viewport').containerWidth
      this.grid.plugins.columnModel.setWidth(
        state.columnId,
        Math.floor(finalWidth),
        cw
      )
      // onColumnResize fires from the create-grid COLUMN_RESIZED listener
      // (setWidth emits it) — not here — so it isn't double-called.
      this.resizingColumnId = null
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
      controller.abort()
      this.dragAbort = null

      // B-04: revert resize-state appearance via cached refs — no full rebuild.
      if (cell) cell.classList.remove('yg-header-cell--resizing')
      if (ind) {
        ind.style.height = '30%'
        ind.style.backgroundColor = 'var(--eg-border, #e5e7eb)'
      }

      if (this.didResize) {
        const blockClick = (ce: MouseEvent) => {
          ce.stopPropagation()
          ce.preventDefault()
          document.removeEventListener('click', blockClick, true)
        }
        document.addEventListener('click', blockClick, true)
        setTimeout(() => {
          this.didResize = false
          document.removeEventListener('click', blockClick, true)
        }, 100)
      }
    }

    document.addEventListener('mousemove', handleMove, { signal })
    document.addEventListener('mouseup', handleUp, { signal })
  }

  private openPopover(
    columnId: string,
    placement: 'bottom' | 'top' | 'auto'
  ): void {
    this.closePopover()
    const colOption = this.grid.options.columns.find(
      (c) => (c.field as string) === columnId
    )
    const filterType: FilterType =
      (colOption?.filter?.type as FilterType) ?? 'text'
    this.activeFilterColumnId = columnId
    this.popover = new GridFilterPopover({
      grid: this.grid,
      columnId,
      filterType,
      // Pass a live getter so the popover always reads the current anchor
      // from the icon-ref map — every header render replaces the anchor
      // element, but the map's value is updated in lockstep.
      getAnchor: () => this.filterIconRefs.get(columnId) ?? null,
      placement,
      onClose: () => this.closePopover(),
    })
    // P-05: update just the active icon's background — no full header rebuild.
    const icon = this.filterIconRefs.get(columnId)
    if (icon) icon.style.backgroundColor = 'var(--eg-hover-bg, #f3f4f6)'
  }

  private closePopover(): void {
    if (this.popover) {
      this.popover.destroy()
      this.popover = null
    }
    if (this.activeFilterColumnId !== null) {
      // P-05: revert the active icon's background — no full header rebuild.
      const icon = this.filterIconRefs.get(this.activeFilterColumnId)
      if (icon) {
        const { filterModel } = this.grid.kernel.store.read('filtered')
        const isFiltered = this.activeFilterColumnId in filterModel.columns
        icon.style.backgroundColor = isFiltered
          ? 'var(--eg-primary-light, #eef2ff)'
          : 'transparent'
      }
      this.activeFilterColumnId = null
    }
  }

  destroy(): void {
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.dragAbort?.abort()
    document.body.style.cursor = ''
    document.body.style.userSelect = ''
    this.closePopover()
    this.el.remove()
  }
}
