// ============================================
// @elitegrid/vanilla — Grid (root view)
// Mirrors the React adapter's Grid.tsx — composes
// toolbar, header, body, pagination, and aria-live
// regions inside a single container element.
// ============================================

import { GridEvent } from '@elitegrid/core'
import type { GridInstance, GridAPI } from '../create-grid'
import { h, type Unsub } from '../utils/dom'
import { GridHeader } from './GridHeader'
import { GridBody } from './GridBody'
import { GridPagination } from './GridPagination'

const SR_ONLY: Partial<CSSStyleDeclaration> = {
  position: 'absolute',
  width: '1px',
  height: '1px',
  padding: '0',
  margin: '-1px',
  overflow: 'hidden',
  clip: 'rect(0, 0, 0, 0)',
  whiteSpace: 'nowrap',
  border: '0',
}

// Replace characters illegal in Windows/macOS filenames (/ \ : * ? " < > |)
// and control chars with '_', and strip leading dots. Without this, a
// developer-supplied filename like "2024/Q1:report.csv" makes the browser's
// save dialog fail silently. Control chars are stripped via char-code check
// rather than a regex range to avoid embedding literal control bytes here.
function sanitizeFilename(name: unknown): string {
  let out = ''
  const raw = String(name ?? 'export.csv')
    .replace(/[/\\:*?"<>|]/g, '_')
    .replace(/^\.+/, '_')
  for (const ch of raw) {
    out += ch.charCodeAt(0) < 0x20 ? '_' : ch
  }
  return out || 'export.csv'
}

export class GridView {
  el: HTMLElement
  private header: GridHeader
  private body: GridBody
  private pagination: GridPagination | null
  private ariaPolite: HTMLElement
  private ariaAssertive: HTMLElement
  private unsubs: Unsub[] = []

  constructor(
    private grid: GridInstance<unknown>,
    private api: GridAPI<unknown>
  ) {
    const { options } = grid
    const theme = options.appearance?.theme ?? 'light'
    const density = options.appearance?.density ?? 'normal'
    const className = [
      'yg-grid',
      `yg-theme-${theme}`,
      `yg-density-${density}`,
      options.appearance?.className,
    ]
      .filter(Boolean)
      .join(' ')

    // Initial ARIA counts/state — kept reactive below so screen readers hear
    // "N rows" matching the filtered view, and "loading" while data resolves.
    const initialRowCount = grid.kernel.store.read('filtered').matchCount
    const initialLoading = grid.kernel.store.read('raw').loading

    this.el = h('div', {
      className,
      attrs: {
        role: 'grid',
        'aria-label': options.accessibility?.gridLabel ?? 'Data grid',
        // aria-rowcount reflects the filtered row total (what the user sees
        // counted), not the raw dataset length.
        'aria-rowcount': String(initialRowCount),
        // aria-busy announces "loading" once; omitted entirely when idle.
        'aria-busy': initialLoading ? 'true' : null,
        'data-density': density,
        'data-theme': theme === 'dark' ? 'dark' : null,
      },
      style: {
        flex: '1',
        width: '100%',
        position: 'relative',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden',
        ...(options.appearance?.style ?? {}),
      },
    })

    // ── Toolbar (export button) ──────────────────────────────────────
    if (options.export != null) {
      this.el.appendChild(this.buildToolbar())
    }

    // ── Header + Body ──────────────────────────────────────────────
    // The header is mounted INSIDE the body's scroll container (as a sticky
    // first child), not as a separate sibling — this lets horizontal scroll
    // move the header and rows together natively, with zero JS sync.
    this.header = new GridHeader(grid)
    this.body = new GridBody(grid, this.header.el)
    this.el.appendChild(this.body.el)

    // ── Pagination ────────────────────────────────────────────────
    // Always mount — GridPagination hides itself when not enabled. This
    // matches the React adapter and lets pagination flip on without an
    // adapter remount.
    this.pagination = new GridPagination(grid)
    this.el.appendChild(this.pagination.el)

    // ── ARIA live regions ─────────────────────────────────────────
    this.ariaPolite = h('div', {
      attrs: { role: 'status', 'aria-live': 'polite', 'aria-atomic': 'true' },
      style: SR_ONLY,
    })
    this.ariaAssertive = h('div', {
      attrs: { role: 'alert', 'aria-live': 'assertive', 'aria-atomic': 'true' },
      style: SR_ONLY,
    })
    this.el.appendChild(this.ariaPolite)
    this.el.appendChild(this.ariaAssertive)

    this.unsubs.push(
      grid.kernel.eventBus.on(GridEvent.ANNOUNCE, (payload: any) => {
        const target =
          payload.priority === 'assertive' ? this.ariaAssertive : this.ariaPolite
        target.textContent = payload.message
      })
    )

    // ── Export download (delayed revoke for Safari) ────────────────
    this.unsubs.push(
      grid.kernel.eventBus.on(GridEvent.EXPORT_COMPLETED, (payload: any) => {
        const blob = new Blob([payload.content], {
          type: 'text/csv;charset=utf-8;',
        })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        // Browser save dialogs fail silently on illegal filename
        // characters — sanitizeFilename() strips them (see helper).
        a.download = sanitizeFilename(payload.filename)
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        setTimeout(() => URL.revokeObjectURL(url), 1000)
      })
    )

    // ── Reactive ARIA: rowcount (filtered total) + busy (loading) ───
    this.unsubs.push(
      grid.kernel.store.subscribe('filtered', () => {
        this.el.setAttribute(
          'aria-rowcount',
          String(grid.kernel.store.read('filtered').matchCount)
        )
      }),
      grid.kernel.store.subscribe('raw', () => {
        if (grid.kernel.store.read('raw').loading) {
          this.el.setAttribute('aria-busy', 'true')
        } else {
          this.el.removeAttribute('aria-busy')
        }
      })
    )
  }

  private buildToolbar(): HTMLElement {
    const exportConfig = this.grid.options.export
    const triggerExport = () => {
      this.grid.plugins.export.export({
        scope: exportConfig?.scope ?? 'filtered',
        filename: exportConfig?.filename ?? 'export',
      })
    }
    const btn = h(
      'button',
      {
        attrs: { title: 'Export visible rows as CSV', 'aria-label': 'Export CSV' },
        style: {
          display: 'flex',
          alignItems: 'center',
          gap: '5px',
          fontSize: '0.75rem',
          fontWeight: '600',
          padding: '4px 12px',
          borderRadius: '6px',
          border: '1px solid var(--eg-border, #e5e7eb)',
          background: 'var(--eg-btn-bg, #ffffff)',
          cursor: 'pointer',
          color: 'var(--eg-btn-text, #374151)',
          lineHeight: '1.4',
        },
        on: { click: triggerExport },
      },
      [
        (() => {
          const wrap = document.createElement('span')
          wrap.innerHTML =
            '<svg width="13" height="13" viewBox="0 0 13 13" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M6.5 1v7M3.5 5.5l3 3 3-3M1.5 9.5v1a1 1 0 001 1h8a1 1 0 001-1v-1" stroke-linecap="round" stroke-linejoin="round"/></svg>'
          return wrap
        })(),
        'Export CSV',
      ]
    )
    return h(
      'div',
      {
        style: {
          display: 'flex',
          justifyContent: 'flex-end',
          alignItems: 'center',
          padding: '6px 8px',
          gap: '6px',
          borderBottom: '1px solid var(--eg-border-color, #e5e7eb)',
          backgroundColor: 'var(--eg-toolbar-bg, #ffffff)',
          flexShrink: '0',
        },
      },
      [btn]
    )
  }

  destroy(): void {
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.header.destroy()
    this.body.destroy()
    this.pagination?.destroy()
    this.el.remove()
  }
}
