// ============================================
// @elitegrid/core — Event Bus
// Central communication system for the engine
// All plugins communicate through this
// No plugin ever imports another plugin directly
// ============================================

import { GridEvent } from './events'

// ── Types ────────────────────────────────────

// A function that handles an event payload
export type EventHandler<T = unknown> = (payload: T) => void

// Calling this function removes the subscription
export type Unsubscribe = () => void

// Internal storage — one entry per event
type HandlerMap = Map<GridEvent, Set<EventHandler>>

// ── Interface ─────────────────────────────────

export interface IEventBus {
  on<T>(event: GridEvent, handler: EventHandler<T>): Unsubscribe
  once<T>(event: GridEvent, handler: EventHandler<T>): void
  emit<T>(event: GridEvent, payload?: T): void
  off(event: GridEvent, handler: EventHandler): void
  clear(event: GridEvent): void
  clearAll(): void
}

// ── Implementation ────────────────────────────

export class EventBus implements IEventBus {
  // Stores all handlers
  // Key: GridEvent
  // Value: Set of handler functions
  private handlers: HandlerMap = new Map()

  // ── Subscribe ──────────────────────────────

  on<T>(event: GridEvent, handler: EventHandler<T>): Unsubscribe {
    // Get existing handlers for this event
    // If none exist yet, create an empty Set
    if (!this.handlers.has(event)) {
      this.handlers.set(event, new Set())
    }

    // Add the handler to the Set
    // Set automatically prevents duplicate handlers
    const handlers = this.handlers.get(event)!
    handlers.add(handler as EventHandler)

    // Return an unsubscribe function
    // Calling this removes the handler cleanly
    return () => {
      this.off(event, handler as EventHandler)
    }
  }

  // ── Subscribe Once ─────────────────────────

  once<T>(event: GridEvent, handler: EventHandler<T>): void {
    // Wrap the handler in a self-removing wrapper
    // The wrapper fires the original handler
    // then immediately removes itself
    const wrapper: EventHandler<T> = (payload: T) => {
      // Remove first — guarantees exactly-once even if handler throws
      this.off(event, wrapper as EventHandler)
      handler(payload)
    }

    this.on(event, wrapper)
  }

  // ── Emit ───────────────────────────────────

  emit<T>(event: GridEvent, payload?: T): void {
    // Get all handlers for this event
    const handlers = this.handlers.get(event)

    // If no handlers registered — do nothing
    // This is intentional — emitting to nobody is fine
    if (!handlers || handlers.size === 0) {
      return
    }

    // Snapshot handlers into an array before iterating.
    // This gives two guarantees:
    //   1. Handlers added inside an emit do NOT fire in the current cycle —
    //      the edge-case contract the tests assert on.
    //   2. Handlers removed inside an emit are excluded because the snapshot
    //      was taken before any handler ran.
    // Array.from is one allocation per emit — acceptable because emit is
    // not called at 60fps like scroll; scroll goes through DataStore.notify
    // which uses for...of on a stable subscriber set.
    // Try-catch per handler: one throwing handler must not block the rest.
    const snapshot = Array.from(handlers)
    for (const handler of snapshot) {
      try {
        handler(payload)
      } catch (err) {
        // Surface in dev — never silently drop errors
        //console.error('[EliteGrid] EventBus handler threw:', err)
      }
    }
  }

  // ── Unsubscribe ────────────────────────────

  off(event: GridEvent, handler: EventHandler): void {
    const handlers = this.handlers.get(event)

    if (!handlers) {
      return
    }

    // Remove this specific handler from the Set
    handlers.delete(handler)

    // If no handlers remain for this event
    // clean up the empty Set from the Map
    if (handlers.size === 0) {
      this.handlers.delete(event)
    }
  }

  // ── Clear One Event ────────────────────────

  clear(event: GridEvent): void {
    // Remove all handlers for a specific event
    this.handlers.delete(event)
  }

  // ── Clear All Events ───────────────────────

  clearAll(): void {
    // Remove all handlers for all events
    // Called when engine is destroyed
    this.handlers.clear()
  }
}
