// ============================================
// @elitegrid/core — Announcement Plugin
// Screen reader announcements via aria-live
//
// Owns:
//   - ANNOUNCE event emission
//
// Listens to:
//   - FOCUS_CHANGED     → announces focused cell position
//   - SORT_COMPLETED    → announces sort field and direction
//   - FILTER_COMPLETED  → announces result count
//   - PAGE_CHANGED      → announces current page
//   - SELECTION_CHANGED → announces selected row count
//   - EDIT_STARTED      → announces field being edited
//   - EDIT_COMMITTED    → announces saved value
//   - EDIT_CANCELLED    → announces cancellation
//
// Does NOT:
//   - Own any store namespace
//   - Touch the DOM (the adapter owns the aria-live region)
//   - Know about React or any framework
//
// Adapter responsibility:
//   - Listen to ANNOUNCE event
//   - Write payload.message into aria-live region
//   - 'polite'    → aria-live="polite"   (navigation, sort, filter)
//   - 'assertive' → aria-live="assertive" (validation errors)
//
// i18n:
//   - Every message has a built-in English default
//   - Pass message formatter overrides in AnnouncementConfig.messages
//   - Formatters receive typed arguments — no string parsing required
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { CellPosition } from '../../types/index'

// ── Plugin ID ─────────────────────────────────

export const ANNOUNCEMENT_PLUGIN_ID = 'announcement'

// ── Announce priority ──────────────────────────

export type AnnouncePriority = 'polite' | 'assertive'

// ── ANNOUNCE event payload ─────────────────────

export interface AnnouncePayload {
  message: string
  priority: AnnouncePriority
}

// ── Message formatters ─────────────────────────
// All fields are optional — English defaults apply for any omitted formatter.

export interface AnnouncementMessages {
  // Focus — "Row 3, Name column"
  focusCell?: (
    rowIndex: number,
    columnId: string,
    columnHeader: string
  ) => string

  // Sort — "Sorted by Salary, descending" / "Sort cleared for Salary"
  sortApplied?: (field: string, direction: 'asc' | 'desc') => string
  sortCleared?: (field: string) => string
  allSortsCleared?: () => string

  // Filter — "12 results found" / "Filter cleared, showing all rows"
  filterApplied?: (matchCount: number) => string
  filterCleared?: () => string

  // Pagination — "Page 2 of 8"
  pageChanged?: (page: number, totalPages: number) => string

  // Selection — "3 rows selected" / "Selection cleared"
  selectionChanged?: (count: number) => string
  selectionCleared?: () => string

  // Edit — "Editing Salary, current value $80,000"
  editStarted?: (columnId: string, currentValue: string) => string
  // "Saved. Salary updated to $95,000"
  editCommitted?: (columnId: string, newValue: string) => string
  // "Edit cancelled"
  editCancelled?: () => string
}

// ── Feature flags ──────────────────────────────

export interface AnnouncementToggles {
  focus?: boolean
  sort?: boolean
  filter?: boolean
  page?: boolean
  selection?: boolean
  edit?: boolean
}

// ── Full plugin config ─────────────────────────

export interface AnnouncementConfig {
  // Feature flags — all default to true (opt-out rather than opt-in)
  announce?: AnnouncementToggles
  // i18n message overrides
  messages?: AnnouncementMessages
}

// ── Built-in English defaults ──────────────────

const DEFAULT_MESSAGES: Required<AnnouncementMessages> = {
  focusCell: (rowIndex, columnId, columnHeader) =>
    `Row ${rowIndex + 1}, ${columnHeader} column`,

  sortApplied: (field, direction) =>
    `Sorted by ${field}, ${direction === 'asc' ? 'ascending' : 'descending'}`,

  sortCleared: (field) => `Sort cleared for ${field}`,

  allSortsCleared: () => `All sorts cleared`,

  filterApplied: (matchCount) =>
    matchCount === 1 ? `1 result found` : `${matchCount} results found`,

  filterCleared: () => `Filter cleared, showing all rows`,

  pageChanged: (page, totalPages) => `Page ${page} of ${totalPages}`,

  selectionChanged: (count) =>
    count === 1 ? `1 row selected` : `${count} rows selected`,

  selectionCleared: () => `Selection cleared`,

  editStarted: (columnId, currentValue) =>
    `Editing ${columnId}. Current value: ${currentValue || 'empty'}`,

  editCommitted: (columnId, newValue) =>
    `Saved. ${columnId} updated to ${newValue || 'empty'}`,

  editCancelled: () => `Edit cancelled`,
}

// ── Implementation ─────────────────────────────

export class AnnouncementPlugin implements Plugin {
  readonly id = ANNOUNCEMENT_PLUGIN_ID

  private context!: PluginContext
  private config: AnnouncementConfig
  private messages: Required<AnnouncementMessages>
  private toggles: Required<AnnouncementToggles>

  constructor(config: AnnouncementConfig = {}) {
    this.config = config

    // Merge caller's messages over the English defaults
    this.messages = { ...DEFAULT_MESSAGES, ...config.messages }

    // All toggles default to true
    this.toggles = {
      focus: config.announce?.focus ?? true,
      sort: config.announce?.sort ?? true,
      filter: config.announce?.filter ?? true,
      page: config.announce?.page ?? true,
      selection: config.announce?.selection ?? true,
      edit: config.announce?.edit ?? true,
    }
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context
    this.subscribe()
  }

  // ── Subscriptions ─────────────────────────

  private subscribe(): void {
    const { eventBus } = this.context

    // All handlers check this.toggles at call time — not at subscription time.
    // This allows updateToggles() to take effect immediately at runtime.

    // ── Focus ────────────────────────────────
    eventBus.on(GridEvent.FOCUS_CHANGED, (payload: unknown) => {
      if (!this.toggles.focus) return
      const { cell } = payload as { cell: CellPosition | null }
      if (!cell) return
      // Resolve the display header so formatters show "Name" not "name"
      const columnHeader = this.getHeaderById(cell.columnId)
      this.announce(
        this.messages.focusCell(cell.rowIndex, cell.columnId, columnHeader),
        'polite'
      )
    })

    // ── Sort ─────────────────────────────────
    eventBus.on(GridEvent.SORT_COMPLETED, (payload: unknown) => {
      if (!this.toggles.sort) return
      const { sortModel } = payload as {
        sortModel: Array<{ columnId: string; direction: 'asc' | 'desc' }>
      }
      if (sortModel.length === 0) {
        this.announce(this.messages.allSortsCleared(), 'polite')
        return
      }
      const primary = sortModel[0]!
      const sortHeader = this.getHeaderById(primary.columnId)
      this.announce(
        this.messages.sortApplied(sortHeader, primary.direction),
        'polite'
      )
    })

    // ── Filter ───────────────────────────────
    eventBus.on(GridEvent.FILTER_COMPLETED, (payload: unknown) => {
      if (!this.toggles.filter) return
      const { matchCount, filterModel } = payload as {
        matchCount: number
        filterModel: Record<string, unknown>
      }
      const hasActiveFilter = Object.keys(filterModel).length > 0
      if (!hasActiveFilter) {
        this.announce(this.messages.filterCleared(), 'polite')
        return
      }
      this.announce(this.messages.filterApplied(matchCount), 'polite')
    })

    // ── Pagination ───────────────────────────
    eventBus.on(GridEvent.PAGE_CHANGED, (payload: unknown) => {
      if (!this.toggles.page) return
      const { page } = payload as { page: number }
      const { totalPages } = this.context.store.read('paginated')
      this.announce(this.messages.pageChanged(page, totalPages), 'polite')
    })

    // ── Selection ────────────────────────────
    eventBus.on(GridEvent.SELECTION_CHANGED, (payload: unknown) => {
      if (!this.toggles.selection) return
      const { count } = payload as { count: number }
      if (count === 0) {
        this.announce(this.messages.selectionCleared(), 'polite')
        return
      }
      this.announce(this.messages.selectionChanged(count), 'polite')
    })

    // ── Edit ─────────────────────────────────
    eventBus.on(GridEvent.EDIT_STARTED, (payload: unknown) => {
      if (!this.toggles.edit) return
      const { cell, originalValue } = payload as {
        cell: CellPosition
        originalValue: unknown
      }
      const editStartHeader = this.getHeaderById(cell.columnId)
      this.announce(
        this.messages.editStarted(editStartHeader, String(originalValue ?? '')),
        'polite'
      )
    })

    eventBus.on(GridEvent.EDIT_COMMITTED, (payload: unknown) => {
      if (!this.toggles.edit) return
      const { cell, newValue } = payload as {
        cell: CellPosition
        newValue: unknown
      }
      const editCommitHeader = this.getHeaderById(cell.columnId)
      this.announce(
        this.messages.editCommitted(editCommitHeader, String(newValue ?? '')),
        'polite'
      )
    })

    eventBus.on(GridEvent.EDIT_CANCELLED, () => {
      if (!this.toggles.edit) return
      this.announce(this.messages.editCancelled(), 'polite')
    })
  }

  // ── Announce ──────────────────────────────
  // Central emit — all announcements go through here.
  // Also callable directly for custom announcements from the adapter.
  //
  // Screen readers only re-read an aria-live region when the DOM text
  // actually changes. If the same message fires twice in a row the
  // adapter's setState() is a no-op → no DOM update → silent.
  //
  // Fix: alternate appending a zero-width space (U+200B) on every other
  // call. The character is invisible and non-breaking, so it never
  // appears in speech or braille, but it makes the string technically
  // different every time — guaranteeing a DOM text update each emission.

  private announceToggle: boolean = false

  announce(message: string, priority: AnnouncePriority = 'polite'): void {
    if (!message) return

    this.announceToggle = !this.announceToggle
    const dedupedMessage = this.announceToggle ? message : message + '\u200B'

    this.context.eventBus.emit(GridEvent.ANNOUNCE, {
      message: dedupedMessage,
      priority,
    } satisfies AnnouncePayload)
  }

  // ── Config updaters ───────────────────────
  // Allow runtime updates (e.g. user changes language preference)

  updateMessages(messages: Partial<AnnouncementMessages>): void {
    this.messages = { ...this.messages, ...messages }
  }

  updateToggles(toggles: Partial<AnnouncementToggles>): void {
    this.toggles = { ...this.toggles, ...toggles }
  }

  // ── Column header resolver ───────────────
  private getHeaderById(columnId: string): string {
    const { definitions } = this.context.store.read('columns')
    const col = definitions.find((d) => d.id === columnId)
    return col?.header ?? columnId
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    // Event bus cleanup is handled by the kernel
    // Nothing plugin-specific to tear down
  }
}
