// ============================================
// @elitegrid/vanilla — GridOverlay
// Error and empty state overlays. Loading uses the
// shimmer skeleton inside GridBody instead.
// ============================================

import { applyStyle, clear, h, type Unsub } from '../utils/dom'
import type { GridInstance } from '../create-grid'

export class GridOverlay {
  el: HTMLElement
  private unsubs: Unsub[] = []
  private renderRaf: number | null = null

  constructor(private grid: GridInstance<unknown>) {
    this.el = h('div', { class: 'yg-overlay-host' })
    applyStyle(this.el, {
      position: 'absolute',
      top: '0',
      left: '0',
      right: '0',
      bottom: '0',
      pointerEvents: 'none',
      display: 'none',
    })
    // Debounce via RAF — all three namespaces can fire in the same pipeline pass;
    // only one render per animation frame.
    const schedule = () => this.scheduleRender()
    this.unsubs.push(
      grid.kernel.store.subscribe('raw', schedule),
      grid.kernel.store.subscribe('paginated', schedule),
      grid.kernel.store.subscribe('filtered', schedule)
    )
    this.render()
  }

  private scheduleRender(): void {
    if (this.renderRaf !== null) return
    this.renderRaf = requestAnimationFrame(() => {
      this.renderRaf = null
      this.render()
    })
  }

  private overlayHost(): HTMLElement {
    return h('div', {
      class: 'yg-overlay',
      style: {
        position: 'absolute',
        top: '0',
        left: '0',
        right: '0',
        bottom: '0',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        backgroundColor: 'var(--eg-overlay-bg, rgba(255,255,255,0.9))',
        zIndex: '5',
        gap: '12px',
        pointerEvents: 'auto',
      },
    })
  }

  private render(): void {
    const { loading, error, rows } = this.grid.kernel.store.read('raw')
    const { rows: paginatedRows } = this.grid.kernel.store.read('paginated')
    const appearance = this.grid.options.appearance

    // P-15: when data is loaded and visible, the overlay is hidden. Skip the
    // DOM clear + rebuild entirely — the element is already empty/hidden.
    if (!loading && !error && paginatedRows.length > 0) {
      if (this.el.style.display !== 'none') {
        this.el.style.display = 'none'
        clear(this.el)
      }
      return
    }

    clear(this.el)

    if (loading && appearance?.loadingComponent) {
      const host = this.overlayHost()
      host.classList.add('yg-overlay--loading')
      appearance.loadingComponent(host)
      this.el.style.display = 'block'
      this.el.appendChild(host)
      return
    }

    if (error) {
      const host = this.overlayHost()
      host.classList.add('yg-overlay--error')
      host.setAttribute('role', 'alert')
      host.setAttribute('aria-live', 'assertive')
      if (appearance?.errorComponent) {
        appearance.errorComponent(host, error)
      } else {
        host.appendChild(
          h('div', {
            style: {
              width: '40px',
              height: '40px',
              borderRadius: '50%',
              backgroundColor: 'var(--eg-error-bg, #fee2e2)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '1.25rem',
            },
            text: '⚠️',
          })
        )
        host.appendChild(
          h('div', { style: { textAlign: 'center' } }, [
            h('p', {
              style: {
                margin: '0',
                fontSize: '0.875rem',
                fontWeight: '600',
                color: 'var(--eg-error, #dc2626)',
              },
              text: 'Failed to load data',
            }),
            h('p', {
              style: {
                margin: '4px 0 0',
                fontSize: '0.8rem',
                color: 'var(--eg-muted-text, #6b7280)',
              },
              text: (error as Error).message,
            }),
          ])
        )
      }
      this.el.style.display = 'block'
      this.el.appendChild(host)
      return
    }

    if (loading) {
      this.el.style.display = 'none'
      return
    }

    const host = this.overlayHost()
    host.classList.add('yg-overlay--empty')
    host.setAttribute('role', 'status')
    host.setAttribute('aria-live', 'polite')

    if (appearance?.emptyStateComponent) {
      appearance.emptyStateComponent(host)
      this.el.style.display = 'block'
      this.el.appendChild(host)
      return
    }

    const hasSourceData = (rows as unknown[]).length > 0
    const isFilteredEmpty = hasSourceData && paginatedRows.length === 0

    const config = isFilteredEmpty
      ? appearance?.filteredEmptyState
      : appearance?.emptyState
    const title =
      config?.title ?? (isFilteredEmpty ? 'No matching results' : 'No data')
    const description =
      config?.description ??
      (isFilteredEmpty ? 'Try adjusting your filters' : 'No rows to display')
    const icon = config?.icon

    host.setAttribute('aria-label', title)

    if (icon instanceof HTMLElement) {
      host.appendChild(icon)
    } else if (typeof icon === 'string') {
      host.appendChild(h('div', { text: icon }))
    } else {
      host.appendChild(
        h('div', {
          style: {
            width: '56px',
            height: '56px',
            borderRadius: '50%',
            backgroundColor: 'var(--eg-empty-icon-bg, #f3f4f6)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '1.5rem',
          },
          text: isFilteredEmpty ? '🔍' : '📭',
        })
      )
    }

    host.appendChild(
      h('div', { style: { textAlign: 'center' } }, [
        h('p', {
          style: {
            margin: '0',
            fontSize: '0.9375rem',
            fontWeight: '600',
            color: 'var(--eg-text, #111827)',
          },
          text: title,
        }),
        h('p', {
          style: {
            margin: '4px 0 0',
            fontSize: '0.8125rem',
            color: 'var(--eg-muted-text, #6b7280)',
          },
          text: description,
        }),
      ])
    )

    this.el.style.display = 'block'
    this.el.appendChild(host)
  }

  destroy(): void {
    if (this.renderRaf !== null) {
      cancelAnimationFrame(this.renderRaf)
      this.renderRaf = null
    }
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.el.remove()
  }
}
