// ============================================
// @elitegrid/vanilla — GridRow
// Renders one row: optional checkbox cell + one GridCell per
// visible column. Owns per-row selection subscription so a
// single selection change only re-renders the affected rows.
// ============================================

import { GridEvent } from '@elitegrid/core'
import type {
  ColumnDefinition,
  ColumnId,
} from '@elitegrid/core'
import type { ColumnDef, GridInstance } from '../create-grid'
import { h } from '../utils/dom'
import { GridCell } from './GridCell'

export interface GridRowOptions {
  grid: GridInstance<unknown>
  rowId: string
  row: Record<string, unknown>
  rowIndex: number
  rowHeight: number
  visibleColumnIds: ColumnId[]
  columnWidths: Map<string, number>
  columnDefMap: Map<string, ColumnDefinition>
  columnOptionsMap: Map<string, ColumnDef>
  cellRegistry: Map<string, GridCell>
}

export interface GridRowUpdate {
  row?: Record<string, unknown>
  rowIndex?: number
  rowHeight?: number
  visibleColumnIds?: ColumnId[]
  columnWidths?: Map<string, number>
  columnDefMap?: Map<string, ColumnDefinition>
  columnOptionsMap?: Map<string, ColumnDef>
}

export class GridRow {
  el: HTMLElement

  private checkboxCell: HTMLElement | null = null
  private checkboxInput: HTMLInputElement | null = null

  private cells = new Map<ColumnId, GridCell>()

  private grid: GridInstance<unknown>
  private rowId: string
  private row: Record<string, unknown>
  private rowIndex: number
  private rowHeight: number
  private visibleColumnIds: ColumnId[]
  private columnWidths: Map<string, number>
  private columnDefMap: Map<string, ColumnDefinition>
  private columnOptionsMap: Map<string, ColumnDef>

  private isSelected: boolean
  private cellRegistry: Map<string, GridCell>

  // Selection config doesn't change after init — resolve "show a checkbox?"
  // once instead of re-reading two options on every update()/mountCheckbox().
  private wantCheckbox: boolean

  // P-11: cached appearance state — skip DOM writes when nothing changed.
  private lastBg = ''
  private lastBorder = ''
  private lastCursor = ''
  private lastOutlineStyle = ''

  constructor(opts: GridRowOptions) {
    this.grid = opts.grid
    this.rowId = opts.rowId
    this.row = opts.row
    this.rowIndex = opts.rowIndex
    this.rowHeight = opts.rowHeight
    this.visibleColumnIds = opts.visibleColumnIds
    this.columnWidths = opts.columnWidths
    this.columnDefMap = opts.columnDefMap
    this.columnOptionsMap = opts.columnOptionsMap
    this.cellRegistry = opts.cellRegistry

    this.isSelected = this.grid.kernel.store
      .read('selection')
      .selectedIds.has(this.rowId)

    const sel = this.grid.options.selection
    this.wantCheckbox =
      (sel?.mode ?? 'none') !== 'none' && (sel?.showCheckboxes ?? true)

    this.el = h('div', {
      class: 'yg-row',
      attrs: {
        role: 'row',
        'aria-rowindex': String(this.rowIndex + 1),
      },
      style: {
        display: 'flex',
        flexDirection: 'row',
        alignItems: 'center',
        boxSizing: 'border-box',
        userSelect: 'none',
        height: `${this.rowHeight}px`,
        minHeight: `${this.rowHeight}px`,
        maxHeight: `${this.rowHeight}px`,
      },
      on: {
        click: (e) => this.onRowClick(e as MouseEvent),
        dblclick: (e) => this.onRowDoubleClick(e as MouseEvent),
      },
    })

    this.applyAppearance()
    this.applyAria()
    this.mountCheckbox()
    this.renderCells()
  }

  // P-03: called by GridBody's single delegated selection subscriber.
  setSelected(selected: boolean): void {
    if (selected === this.isSelected) return
    this.isSelected = selected
    this.applyAppearance()
    this.applyAria()
    if (this.checkboxInput) this.checkboxInput.checked = selected
  }

  update(opts: GridRowUpdate): void {
    if (opts.row) this.row = opts.row
    if (opts.rowIndex !== undefined && opts.rowIndex !== this.rowIndex) {
      this.rowIndex = opts.rowIndex
      this.el.setAttribute('aria-rowindex', String(this.rowIndex + 1))
      // Keep the checkbox label in sync — rows are reused by the keyed diff,
      // so a stale label would announce the wrong row number after scrolling.
      this.checkboxInput?.setAttribute(
        'aria-label',
        `Select row ${this.rowIndex + 1}`
      )
    }
    if (opts.rowHeight !== undefined && opts.rowHeight !== this.rowHeight) {
      this.rowHeight = opts.rowHeight
      this.el.style.height = `${opts.rowHeight}px`
      this.el.style.minHeight = `${opts.rowHeight}px`
      this.el.style.maxHeight = `${opts.rowHeight}px`
    }
    if (opts.columnWidths) this.columnWidths = opts.columnWidths
    if (opts.columnDefMap) this.columnDefMap = opts.columnDefMap
    if (opts.columnOptionsMap) this.columnOptionsMap = opts.columnOptionsMap
    if (opts.visibleColumnIds) this.visibleColumnIds = opts.visibleColumnIds

    this.applyAppearance()
    this.mountCheckbox()
    this.renderCells()
  }

  destroy(): void {
    this.cells.forEach((c) => c.destroy())
    this.cells.clear()
    this.el.remove()
  }

  // ── Internal ───────────────────────────────────────────────────────

  private applyAppearance(): void {
    const { options } = this.grid
    const showStriping = options.appearance?.rowStriping ?? true
    const isEven = this.rowIndex % 2 === 0

    const bg = this.isSelected
      ? 'var(--eg-row-selected-bg, #eef2ff)'
      : showStriping && isEven
        ? 'var(--eg-row-striped-bg, #f9fafb)'
        : 'var(--eg-row-bg, #ffffff)'
    const border = this.isSelected
      ? 'var(--eg-row-selected-border, 1px solid #c7d2fe)'
      : 'var(--eg-row-border, 1px solid #f3f4f6)'
    const selectionMode = options.selection?.mode ?? 'none'
    const interactive = selectionMode !== 'none' || !!options.events?.onRowClick
    const cursor = interactive ? 'pointer' : 'default'
    const outline = this.isSelected
      ? '1px solid var(--eg-row-selected-outline, transparent)'
      : ''

    // P-11: skip DOM writes when nothing changed.
    if (bg !== this.lastBg) { this.lastBg = bg; this.el.style.backgroundColor = bg }
    if (border !== this.lastBorder) { this.lastBorder = border; this.el.style.borderBottom = border }
    if (cursor !== this.lastCursor) { this.lastCursor = cursor; this.el.style.cursor = cursor }
    if (outline !== this.lastOutlineStyle) { this.lastOutlineStyle = outline; this.el.style.outline = outline }
  }

  private applyAria(): void {
    const selectionMode = this.grid.options.selection?.mode ?? 'none'
    if (selectionMode !== 'none') {
      this.el.setAttribute('aria-selected', this.isSelected ? 'true' : 'false')
    } else {
      this.el.removeAttribute('aria-selected')
    }
  }

  private mountCheckbox(): void {
    const wantCheckbox = this.wantCheckbox

    if (wantCheckbox && !this.checkboxCell) {
      const input = h('input', {
        attrs: {
          type: 'checkbox',
          'aria-label': `Select row ${this.rowIndex + 1}`,
        },
        style: {
          cursor: 'pointer',
          width: '16px',
          height: '16px',
          accentColor: 'var(--eg-primary, #6366f1)',
        },
        on: {
          change: (e) => {
            this.grid.kernel.eventBus.emit(GridEvent.CHECKBOX_ROW_CHANGED, {
              rowId: this.rowId,
              checked: (e.target as HTMLInputElement).checked,
            })
          },
        },
      }) as HTMLInputElement
      input.checked = this.isSelected

      const cell = h(
        'div',
        {
          class: 'yg-cell yg-cell--checkbox',
          attrs: { role: 'gridcell', 'aria-colindex': '1' },
          style: {
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            flexShrink: '0',
            boxSizing: 'border-box',
            width: '48px',
            minWidth: '48px',
            maxWidth: '48px',
            height: '100%',
          },
          on: {
            click: (e) => e.stopPropagation(),
          },
        },
        [input]
      )
      this.checkboxCell = cell
      this.checkboxInput = input
      // Insert as first child.
      this.el.insertBefore(cell, this.el.firstChild)
    } else if (!wantCheckbox && this.checkboxCell) {
      this.checkboxCell.remove()
      this.checkboxCell = null
      this.checkboxInput = null
    }
  }

  private renderCells(): void {
    // Drop cells for columns no longer visible.
    const nextSet = new Set(this.visibleColumnIds)
    for (const [colId, inst] of this.cells) {
      if (!nextSet.has(colId)) {
        inst.destroy()
        this.cells.delete(colId)
      }
    }

    // Insertion anchor — checkbox cell stays first; cells go after it.
    let cursor: Node | null = this.checkboxCell

    for (let i = 0; i < this.visibleColumnIds.length; i++) {
      const colId = this.visibleColumnIds[i]!
      let inst = this.cells.get(colId)
      if (!inst) {
        inst = new GridCell({
          grid: this.grid,
          rowId: this.rowId,
          columnId: colId,
          columnIndex: i,
          rowIndex: this.rowIndex,
          row: this.row,
          rowHeight: this.rowHeight,
          columnWidths: this.columnWidths,
          columnDefMap: this.columnDefMap,
          columnOptionsMap: this.columnOptionsMap,
          cellRegistry: this.cellRegistry,
          // aria-colindex offset — the checkbox column occupies index 1.
          ariaColOffset: this.wantCheckbox ? 1 : 0,
        })
        this.cells.set(colId, inst)
      } else {
        inst.update({
          row: this.row,
          rowIndex: this.rowIndex,
          columnIndex: i,
          rowHeight: this.rowHeight,
          columnWidths: this.columnWidths,
          columnDefMap: this.columnDefMap,
          columnOptionsMap: this.columnOptionsMap,
        })
      }
      const expectedSibling = cursor ? cursor.nextSibling : this.el.firstChild
      if (inst.el !== expectedSibling) {
        this.el.insertBefore(inst.el, expectedSibling)
      }
      cursor = inst.el
    }
  }

  // ── Row-level click handlers ───────────────────────────────────────
  // Cells stop their own click propagation. These handlers fire only when
  // the click was on a non-cell area of the row (padding, etc.) — they
  // still invoke developer callbacks.

  private onRowClick(e: MouseEvent): void {
    const { options } = this.grid
    const selectionMode = options.selection?.mode ?? 'none'
    const selectOnRowClick = options.selection?.selectOnRowClick ?? true
    const checkboxOnly = options.selection?.checkboxOnly ?? false
    if (selectionMode !== 'none' && selectOnRowClick && !checkboxOnly) {
      this.grid.kernel.eventBus.emit(GridEvent.ROW_CLICK_SELECTION, {
        rowId: this.rowId,
        shiftKey: e.shiftKey,
        ctrlKey: e.ctrlKey,
        metaKey: e.metaKey,
      })
    }
    options.events?.onRowClick?.(this.row as any, e)
  }

  private onRowDoubleClick(e: MouseEvent): void {
    this.grid.options.events?.onRowDoubleClick?.(this.row as any, e)
  }
}
