// ============================================
// @elitegrid/vanilla — GridFilterPopover
// Per-column filter popover. Renders into document.body
// using position:fixed so it escapes any clipping ancestor.
// ============================================

import type {
  TextFilterOperator,
  NumberFilterOperator,
  DateFilterOperator,
  BooleanFilterOperator,
} from '@elitegrid/core'
import type { GridInstance } from '../create-grid'
import { h } from '../utils/dom'
import { parseLocalDate } from '../utils/date'

export type FilterType = 'text' | 'number' | 'date' | 'boolean'

const TEXT_OPERATORS: { value: TextFilterOperator; label: string }[] = [
  { value: 'contains', label: 'Contains' },
  { value: 'notContains', label: 'Does not contain' },
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'startsWith', label: 'Starts with' },
  { value: 'endsWith', label: 'Ends with' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]
const NUMBER_OPERATORS: { value: NumberFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'greaterThan', label: 'Greater than' },
  { value: 'greaterThanOrEqual', label: 'Greater than or equal' },
  { value: 'lessThan', label: 'Less than' },
  { value: 'lessThanOrEqual', label: 'Less than or equal' },
  { value: 'between', label: 'Between' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]
const DATE_OPERATORS: { value: DateFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'before', label: 'Before' },
  { value: 'after', label: 'After' },
  { value: 'between', label: 'Between' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]
const BOOLEAN_OPERATORS: { value: BooleanFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const NO_INPUT_OPERATORS = ['isEmpty', 'isNotEmpty']
const TWO_INPUT_OPERATORS = ['between']

const INPUT_STYLE: Partial<CSSStyleDeclaration> = {
  width: '100%',
  height: '32px',
  padding: '0 8px',
  border: '1px solid var(--eg-border, #e5e7eb)',
  borderRadius: '6px',
  fontSize: '0.875rem',
  color: 'var(--eg-text, #111827)',
  backgroundColor: 'var(--eg-surface, #ffffff)',
  boxSizing: 'border-box',
  outline: 'none',
  fontFamily: 'inherit',
}
const LABEL_STYLE: Partial<CSSStyleDeclaration> = {
  fontSize: '0.75rem',
  fontWeight: '600',
  color: 'var(--eg-muted-text, #6b7280)',
  marginBottom: '4px',
  display: 'block',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
}

export interface FilterPopoverProps {
  grid: GridInstance<unknown>
  columnId: string
  filterType: FilterType
  // Getter — not a direct element reference. GridHeader rebuilds its DOM on
  // every store change (sort/filter/scroll), which detaches the previous
  // anchor element. The getter always returns the *current* anchor in the
  // DOM so position() stays correct across header re-renders.
  getAnchor: () => HTMLElement | null
  onClose: () => void
  placement?: 'bottom' | 'top' | 'auto'
}

export class GridFilterPopover {
  el: HTMLElement
  private operator: string
  private value = ''
  private valueTo = ''
  private boolValue = 'true'
  private betweenError: string | null = null
  private errorEl: HTMLElement | null = null
  private valueSectionEl: HTMLElement | null = null
  private opSelectEl: HTMLSelectElement | null = null
  private positionRaf: number | null = null
  private unsubs: Array<() => void> = []

  constructor(private p: FilterPopoverProps) {
    const current = (
      p.grid.kernel.store.read('filtered').filterModel.columns as Record<
        string,
        any
      >
    )[p.columnId]
    this.operator = current?.operator ?? this.defaultOperator()
    if (current?.value != null) this.value = String(current.value)
    if (current?.valueTo != null) this.valueTo = String(current.valueTo)
    if (p.filterType === 'boolean' && current?.value != null) {
      this.boolValue = String(current.value)
    }

    this.el = h('div', {
      style: {
        position: 'fixed',
        // Start off-screen so the popover never flashes at (0, 0) before
        // position() runs. position() always overwrites top/left.
        top: '-9999px',
        left: '-9999px',
        width: '260px',
        backgroundColor: 'var(--eg-surface, #ffffff)',
        border: '1px solid var(--eg-border, #e5e7eb)',
        borderRadius: '8px',
        boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
        zIndex: '1000',
        padding: '12px',
        display: 'flex',
        flexDirection: 'column',
        gap: '10px',
      },
    })

    document.body.appendChild(this.el)
    this.render()
    this.position()

    // RAF-throttled reposition — prevents a forced reflow on every scroll tick.
    const calc = () => {
      if (this.positionRaf !== null) return
      this.positionRaf = requestAnimationFrame(() => {
        this.positionRaf = null
        this.position()
      })
    }
    window.addEventListener('resize', calc, { passive: true })
    window.addEventListener('scroll', calc, { passive: true, capture: true })
    this.unsubs.push(() => window.removeEventListener('resize', calc))
    this.unsubs.push(() => window.removeEventListener('scroll', calc, true))

    const onDoc = (e: MouseEvent) => {
      const tgt = e.target as Node
      const anchor = p.getAnchor()
      if (!this.el.contains(tgt) && !anchor?.contains(tgt)) p.onClose()
    }
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') p.onClose()
    }
    document.addEventListener('mousedown', onDoc)
    document.addEventListener('keydown', onKey)
    this.unsubs.push(() => document.removeEventListener('mousedown', onDoc))
    this.unsubs.push(() => document.removeEventListener('keydown', onKey))
  }

  private defaultOperator(): string {
    switch (this.p.filterType) {
      case 'text':
        return 'contains'
      default:
        return 'equals'
    }
  }

  private operators() {
    switch (this.p.filterType) {
      case 'text':
        return TEXT_OPERATORS
      case 'number':
        return NUMBER_OPERATORS
      case 'date':
        return DATE_OPERATORS
      case 'boolean':
        return BOOLEAN_OPERATORS
    }
  }

  // Public — called by GridHeader after re-render so the popover follows
  // its anchor when the surrounding column layout changes (resize, sort,
  // filter applied elsewhere).
  reposition(): void {
    this.position()
  }

  private position(): void {
    const anchor = this.p.getAnchor()
    // A detached anchor (hover-only icon pruned on header re-render) has a
    // zero rect — treat it like a missing anchor and park off-screen.
    if (!anchor || !anchor.isConnected) {
      this.el.style.top = '-9999px'
      this.el.style.left = '-9999px'
      return
    }
    const rect = anchor.getBoundingClientRect()
    // Measure the real height — the boolean/no-input variants are much
    // shorter than the two-input ones, and the flip-above heuristic should
    // use the actual size. Falls back to the historical estimate pre-layout.
    const POPOVER_HEIGHT = this.el.offsetHeight || 280
    const POPOVER_WIDTH = 260
    const spaceBelow = window.innerHeight - rect.bottom
    const spaceAbove = rect.top
    const left = Math.min(rect.left, window.innerWidth - POPOVER_WIDTH - 8)
    const openAbove =
      this.p.placement === 'top' ||
      (this.p.placement === 'auto' &&
        spaceBelow < POPOVER_HEIGHT &&
        spaceAbove > spaceBelow)
    const top = openAbove ? rect.top - POPOVER_HEIGHT - 4 : rect.bottom + 4
    this.el.style.top = `${top}px`
    this.el.style.left = `${left}px`
  }

  // Build the full popover DOM on first render. On subsequent operator changes
  // only the value section is rebuilt — the header, operator select, and action
  // buttons stay alive, avoiding repeated option-element creation.
  private render(): void {
    const isFirstRender = this.opSelectEl === null

    if (isFirstRender) {
      while (this.el.firstChild) this.el.removeChild(this.el.firstChild)

      // Header bar
      const header = h(
        'div',
        {
          style: {
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            paddingBottom: '8px',
            borderBottom: '1px solid var(--eg-border, #e5e7eb)',
          },
        },
        [
          h('span', {
            style: {
              fontSize: '0.875rem',
              fontWeight: '600',
              color: 'var(--eg-text, #111827)',
            },
            text: 'Filter',
          }),
          h('button', {
            style: {
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              fontSize: '1rem',
              color: 'var(--eg-muted-text, #6b7280)',
              padding: '0',
              lineHeight: '1',
            },
            text: '✕',
            on: { click: () => this.p.onClose() },
          }),
        ]
      )
      this.el.appendChild(header)

      // Operator selector — built once, kept alive across operator changes.
      const opSelect = h('select', {
        style: { ...INPUT_STYLE, height: '34px' },
        on: {
          change: (e) => {
            this.operator = (e.target as HTMLSelectElement).value
            this.renderValueSection()
            this.position()
          },
        },
      }) as HTMLSelectElement
      this.operators().forEach((op) => {
        const o = document.createElement('option')
        o.value = op.value
        o.textContent = op.label
        if (op.value === this.operator) o.selected = true
        opSelect.appendChild(o)
      })
      this.opSelectEl = opSelect
      this.el.appendChild(
        h('div', {}, [
          h('label', { style: LABEL_STYLE, text: 'Condition' }),
          opSelect,
        ])
      )

      // Value section placeholder — only this part is replaced on operator change.
      this.valueSectionEl = h('div')
      this.el.appendChild(this.valueSectionEl)

      // Action buttons
      this.el.appendChild(
        h(
          'div',
          { style: { display: 'flex', gap: '6px', paddingTop: '4px' } },
          [
            h('button', {
              style: {
                flex: '1',
                height: '32px',
                border: '1px solid var(--eg-border, #e5e7eb)',
                borderRadius: '6px',
                backgroundColor: 'var(--eg-surface, #ffffff)',
                color: 'var(--eg-muted-text, #6b7280)',
                fontSize: '0.875rem',
                cursor: 'pointer',
                fontFamily: 'inherit',
              },
              text: 'Clear',
              on: { click: () => this.clear() },
            }),
            h('button', {
              style: {
                flex: '1',
                height: '32px',
                border: 'none',
                borderRadius: '6px',
                backgroundColor: 'var(--eg-primary, #6366f1)',
                color: 'var(--eg-primary-text, #ffffff)',
                fontSize: '0.875rem',
                fontWeight: '600',
                cursor: 'pointer',
                fontFamily: 'inherit',
              },
              text: 'Apply',
              on: { click: () => this.apply() },
            }),
          ]
        )
      )

      // Error element — always present, shown/hidden via display.
      this.errorEl = h('div', {
        attrs: { role: 'alert' },
        style: {
          display: 'none',
          marginTop: '6px',
          fontSize: '0.75rem',
          color: 'var(--eg-error, #dc2626)',
          padding: '4px 0',
        },
      })
      this.el.appendChild(this.errorEl)
    } else {
      // Subsequent calls: sync operator select value only.
      if (this.opSelectEl) this.opSelectEl.value = this.operator
    }

    this.renderValueSection()
    this.updateErrorDisplay()
  }

  // Rebuild only the value input section (below the operator select).
  private renderValueSection(): void {
    const container = this.valueSectionEl
    if (!container) return
    while (container.firstChild) container.removeChild(container.firstChild)

    const needsNoInput = NO_INPUT_OPERATORS.includes(this.operator)
    const needsTwoInputs = TWO_INPUT_OPERATORS.includes(this.operator)
    if (needsNoInput) return

    if (this.p.filterType === 'boolean') {
      const sel = h('select', {
        style: { ...INPUT_STYLE, height: '34px' },
        on: {
          change: (e) => {
            this.boolValue = (e.target as HTMLSelectElement).value
          },
        },
      })
      ;['true', 'false'].forEach((v) => {
        const o = document.createElement('option')
        o.value = v
        o.textContent = v === 'true' ? 'True' : 'False'
        if (v === this.boolValue) o.selected = true
        sel.appendChild(o)
      })
      container.appendChild(
        h('div', {}, [h('label', { style: LABEL_STYLE, text: 'Value' }), sel])
      )
    } else {
      const inputType =
        this.p.filterType === 'number'
          ? 'number'
          : this.p.filterType === 'date'
            ? 'date'
            : 'text'
      const fromInput = h('input', {
        attrs: {
          type: inputType,
          placeholder: needsTwoInputs ? 'From...' : 'Filter value...',
          value: this.value,
        },
        style: INPUT_STYLE,
        on: {
          input: (e) => {
            this.value = (e.target as HTMLInputElement).value
          },
          keydown: (e) => {
            if ((e as KeyboardEvent).key === 'Enter') this.apply()
          },
        },
      })
      const wrap = h(
        'div',
        { style: { display: 'flex', flexDirection: 'column', gap: '6px' } },
        [
          h('div', {}, [
            h('label', {
              style: LABEL_STYLE,
              text: needsTwoInputs ? 'From' : 'Value',
            }),
            fromInput,
          ]),
        ]
      )
      if (needsTwoInputs) {
        const toInput = h('input', {
          attrs: {
            type: inputType,
            placeholder: 'To...',
            value: this.valueTo,
          },
          style: INPUT_STYLE,
          on: {
            input: (e) => {
              this.valueTo = (e.target as HTMLInputElement).value
            },
            keydown: (e) => {
              if ((e as KeyboardEvent).key === 'Enter') this.apply()
            },
          },
        })
        wrap.appendChild(
          h('div', {}, [
            h('label', { style: LABEL_STYLE, text: 'To' }),
            toInput,
          ])
        )
      }
      container.appendChild(wrap)
      queueMicrotask(() => fromInput.focus())
    }
  }

  private updateErrorDisplay(): void {
    if (!this.errorEl) return
    if (this.betweenError) {
      this.errorEl.textContent = this.betweenError
      this.errorEl.style.display = 'block'
    } else {
      this.errorEl.style.display = 'none'
    }
  }

  private apply(): void {
    this.betweenError = null
    const { grid, columnId, filterType, onClose } = this.p
    const currentModel = grid.kernel.store.read('filtered').filterModel
    const needsTwoInputs = TWO_INPUT_OPERATORS.includes(this.operator)
    const needsNoInput = NO_INPUT_OPERATORS.includes(this.operator)

    // Empty input handling — Number('') is 0, so applying an empty number
    // filter would silently filter for 0. Treat fully-empty input as "remove
    // this column's filter"; a half-filled 'between' is a validation error.
    if (!needsNoInput && filterType === 'number') {
      const fromEmpty = this.value.trim() === ''
      const toEmpty = this.valueTo.trim() === ''
      if (needsTwoInputs ? fromEmpty && toEmpty : fromEmpty) {
        this.clear()
        return
      }
      if (needsTwoInputs && (fromEmpty || toEmpty)) {
        this.betweenError = 'Both "From" and "To" values are required'
        this.updateErrorDisplay()
        return
      }
    }
    if (!needsNoInput && filterType === 'date') {
      if (needsTwoInputs ? !this.value && !this.valueTo : !this.value) {
        this.clear()
        return
      }
    }

    if (needsTwoInputs && filterType === 'number') {
      const from = Number(this.value)
      const to = Number(this.valueTo)
      if (!isNaN(from) && !isNaN(to) && from > to) {
        this.betweenError = '"From" must be less than or equal to "To"'
        this.updateErrorDisplay()
        return
      }
    }
    if (needsTwoInputs && filterType === 'date' && this.value && this.valueTo) {
      const from = parseLocalDate(this.value)
      const to = parseLocalDate(this.valueTo)
      if (from && to && from > to) {
        this.betweenError = '"From" date must be before or equal to "To" date'
        this.updateErrorDisplay()
        return
      }
    }

    if (needsNoInput) {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: { type: filterType, operator: this.operator } as any,
        },
      })
    } else if (filterType === 'boolean') {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'boolean',
            operator: this.operator,
            value: this.boolValue === 'true',
          } as any,
        },
      })
    } else if (filterType === 'number') {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'number',
            operator: this.operator,
            value: Number(this.value),
            ...(needsTwoInputs ? { valueTo: Number(this.valueTo) } : {}),
          } as any,
        },
      })
    } else if (filterType === 'date') {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'date',
            operator: this.operator,
            value: parseLocalDate(this.value),
            ...(needsTwoInputs
              ? { valueTo: parseLocalDate(this.valueTo) }
              : {}),
          } as any,
        },
      })
    } else {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'text',
            operator: this.operator,
            value: this.value,
          } as any,
        },
      })
    }
    onClose()
  }

  private clear(): void {
    const { grid, columnId, onClose } = this.p
    const currentModel = grid.kernel.store.read('filtered').filterModel
    const newColumns = { ...currentModel.columns }
    delete newColumns[columnId]
    grid.plugins.filter.setFilterModel({ columns: newColumns })
    onClose()
  }

  destroy(): void {
    if (this.positionRaf !== null) {
      cancelAnimationFrame(this.positionRaf)
      this.positionRaf = null
    }
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.el.remove()
  }
}
