// ============================================
// @elitegrid/vanilla — GridCellEditor
// Editor for an active cell. Handles text, number,
// select, date, and boolean editor types, plus the
// validation tooltip rendered into document.body.
// ============================================

import { GridEvent } from '@elitegrid/core'
import type {
  CellPosition,
  ColumnEditorConfig,
  EditingNamespace,
} from '@elitegrid/core'
import type { GridInstance } from '../create-grid'
import { applyStyle, h, type Unsub } from '../utils/dom'
import { formatDateInput, parseLocalDate } from '../utils/date'

export interface GridCellEditorProps {
  grid: GridInstance<unknown>
  cell: CellPosition
  editorConfig: ColumnEditorConfig | null
  rowHeight: number
}

export class GridCellEditor {
  el: HTMLElement
  private input: HTMLInputElement | HTMLSelectElement | null = null
  private tooltipEl: HTMLElement | null = null
  private tooltipRaf: number | null = null
  private tooltipListenersAttached = false
  private unsubs: Unsub[] = []
  private committed = false
  private boolTimer: ReturnType<typeof setTimeout> | null = null
  private lastTooltipMessage = ''

  constructor(private props: GridCellEditorProps) {
    const { editorConfig, rowHeight } = props
    const editorType = editorConfig?.type ?? 'text'

    this.el = h('div', { style: { position: 'relative', width: '100%' } })

    const baseStyle: Partial<CSSStyleDeclaration> = {
      width: '100%',
      height: `${rowHeight - 4}px`,
      boxSizing: 'border-box',
      border: '2px solid var(--eg-primary, #6366f1)',
      borderRadius: '4px',
      padding: '0 8px',
      fontSize: '0.875rem',
      color: 'var(--eg-cell-text, #111827)',
      backgroundColor: 'var(--eg-row-bg, #ffffff)',
      outline: 'none',
    }

    // ── Boolean: no UI, just toggle and commit ───────────────────────
    if (editorType === 'boolean') {
      const editing = this.props.grid.kernel.store.read(
        'editing'
      ) as EditingNamespace
      this.emitChange(!editing.currentValue)
      this.boolTimer = setTimeout(() => this.emitCommit(), 0)
      return
    }

    // ── Build the right input ────────────────────────────────────────
    let inputEl: HTMLInputElement | HTMLSelectElement

    if (editorType === 'select') {
      const sel = document.createElement('select')
      applyStyle(sel, { ...baseStyle, cursor: 'pointer' })
      const selectOptions = Array.isArray(editorConfig?.options)
        ? editorConfig.options
        : []
      selectOptions.forEach((opt: any) => {
        const o = document.createElement('option')
        o.value = String(opt.value)
        o.textContent = opt.label
        sel.appendChild(o)
      })
      inputEl = sel
    } else if (editorType === 'date') {
      const inp = document.createElement('input')
      inp.type = 'date'
      if (editorConfig?.minDate) inp.min = formatDateInput(editorConfig.minDate)
      if (editorConfig?.maxDate) inp.max = formatDateInput(editorConfig.maxDate)
      applyStyle(inp, baseStyle)
      inputEl = inp
    } else if (editorType === 'number') {
      const inp = document.createElement('input')
      inp.type = 'number'
      if (editorConfig?.min !== undefined) inp.min = String(editorConfig.min)
      if (editorConfig?.max !== undefined) inp.max = String(editorConfig.max)
      inp.step = String((editorConfig as any)?.step ?? 1)
      applyStyle(inp, baseStyle)
      inputEl = inp
    } else {
      const inp = document.createElement('input')
      inp.type = 'text'
      applyStyle(inp, baseStyle)
      inputEl = inp
    }

    this.input = inputEl

    inputEl.addEventListener('keydown', (e) =>
      this.onKeyDown(e as KeyboardEvent)
    )
    inputEl.addEventListener('blur', () => this.emitCommit())
    if (inputEl instanceof HTMLSelectElement) {
      inputEl.addEventListener('change', () => {
        this.emitChange(inputEl.value)
      })
    } else {
      inputEl.addEventListener('input', () => this.onInput())
    }

    this.el.appendChild(inputEl)

    // Subscribe to editing state to keep value + validation in sync.
    const syncFromStore = () => this.syncFromStore()
    syncFromStore()
    this.unsubs.push(
      this.props.grid.kernel.store.subscribe('editing', syncFromStore)
    )

    queueMicrotask(() => {
      inputEl.focus()
      if (inputEl instanceof HTMLInputElement) inputEl.select()
    })
  }

  private onInput(): void {
    if (!this.input) return
    const editorType = this.props.editorConfig?.type ?? 'text'
    const v = (this.input as HTMLInputElement).value
    if (editorType === 'date') {
      this.emitChange(v ? parseLocalDate(v) : null)
    } else if (editorType === 'number') {
      this.emitChange(v === '' ? null : Number(v))
    } else {
      this.emitChange(v)
    }
  }

  private onKeyDown(e: KeyboardEvent): void {
    if (e.key === 'Enter') {
      e.preventDefault()
      this.emitCommit()
    } else if (e.key === 'Escape') {
      e.preventDefault()
      this.emitCancel()
    } else if (e.key === 'Tab') {
      e.preventDefault()
      this.emitCommit()
      this.props.grid.kernel.eventBus.emit(GridEvent.FOCUS_MOVE_REQUESTED, {
        direction: e.shiftKey ? 'prev' : 'next',
        editableOnly: true,
      })
    }
  }

  private emitChange(value: unknown): void {
    this.props.grid.kernel.eventBus.emit(GridEvent.EDIT_VALUE_CHANGED, {
      cell: this.props.cell,
      value,
    })
  }

  private emitCommit(): void {
    if (this.committed) return
    this.committed = true
    this.props.grid.kernel.eventBus.emit(GridEvent.EDIT_COMMIT_REQUESTED, {
      cell: this.props.cell,
    })
  }

  private emitCancel(): void {
    if (this.committed) return
    this.committed = true
    this.props.grid.kernel.eventBus.emit(GridEvent.EDIT_CANCEL_REQUESTED, {
      cell: this.props.cell,
    })
  }

  private syncFromStore(): void {
    if (!this.input) return
    const editing = this.props.grid.kernel.store.read(
      'editing'
    ) as EditingNamespace
    const editorType = this.props.editorConfig?.type ?? 'text'
    const current = editing.currentValue

    // If we just tried to commit but the engine rejected the value, the
    // engine keeps the editor open (isEditing=true, isValid=false). Reset
    // the double-commit guard so the user can re-press Enter after fixing
    // the input instead of being silently ignored.
    if (this.committed && editing.isEditing && !editing.isValid) {
      this.committed = false
    }

    if (this.input instanceof HTMLSelectElement) {
      const next = String(current ?? '')
      if (this.input.value !== next) this.input.value = next
    } else {
      let next: string
      if (editorType === 'date') {
        next = formatDateInput(current)
      } else if (current === null || current === undefined) {
        next = ''
      } else {
        next = String(current)
      }
      if (this.input.value !== next) this.input.value = next
    }

    // Border colour mirrors validity
    const valid = editing.isValid
    this.input.style.borderColor = valid
      ? 'var(--eg-primary, #6366f1)'
      : 'var(--eg-error, #ef4444)'

    if (!valid && editing.validationError) {
      this.showTooltip(editing.validationError)
    } else {
      this.hideTooltip()
    }
  }

  private showTooltip(message: string): void {
    if (this.tooltipEl && this.lastTooltipMessage === message) {
      this.positionTooltip()
      return
    }
    this.hideTooltip()
    this.lastTooltipMessage = message
    const tip = h('div', {
      attrs: { role: 'alert' },
      style: {
        position: 'fixed',
        zIndex: '9999',
        backgroundColor: 'var(--eg-error, #ef4444)',
        color: 'var(--eg-error-text, #ffffff)',
        fontSize: '0.75rem',
        padding: '3px 8px',
        borderRadius: '4px',
        whiteSpace: 'nowrap',
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
        pointerEvents: 'none',
      },
      text: message,
    })
    document.body.appendChild(tip)
    this.tooltipEl = tip
    this.positionTooltip()
    // Attach scroll/resize listeners once for the lifetime of this editor.
    // Re-adding on every showTooltip call was leaking listeners when the
    // user alternated between valid and invalid values.
    if (!this.tooltipListenersAttached) {
      this.tooltipListenersAttached = true
      const reposition = () => {
        if (!this.tooltipEl) return
        if (this.tooltipRaf !== null) return
        this.tooltipRaf = requestAnimationFrame(() => {
          this.tooltipRaf = null
          this.positionTooltip()
        })
      }
      window.addEventListener('resize', reposition, { passive: true })
      window.addEventListener('scroll', reposition, { passive: true, capture: true })
      this.unsubs.push(() => window.removeEventListener('resize', reposition))
      this.unsubs.push(() =>
        window.removeEventListener('scroll', reposition, true)
      )
    }
  }

  private positionTooltip(): void {
    if (!this.tooltipEl || !this.input) return
    const rect = this.input.getBoundingClientRect()
    this.tooltipEl.style.top = `${rect.bottom + 2}px`
    this.tooltipEl.style.left = `${rect.left}px`
  }

  private hideTooltip(): void {
    if (this.tooltipEl) {
      this.tooltipEl.remove()
      this.tooltipEl = null
      this.lastTooltipMessage = ''
    }
  }

  destroy(): void {
    if (this.boolTimer) clearTimeout(this.boolTimer)
    if (this.tooltipRaf !== null) {
      cancelAnimationFrame(this.tooltipRaf)
      this.tooltipRaf = null
    }
    this.hideTooltip()
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.el.remove()
  }
}
