// ============================================
// @elitegrid/core — Selection Plugin
// Manages row selection state
// Owns the 'selection' namespace in Data Store
// ============================================
//
// Supported modes:
//   'none'     — selection disabled entirely
//   'single'   — one row at a time
//   'multiple' — many rows via checkbox / Ctrl+Click / Shift+Click
//
// Select All scope (config.selectAllScope):
//   'page' — selects paginated.rows (current page only)
//   'all'  — selects sorted.rows (all filtered rows in memory)
//
// Page change always clears selection.
// Data reload (DATA_SET) always clears selection.
// Row deletion removes that row from selection.
//
// Events this plugin LISTENS to:
//   ROW_CLICK_SELECTION   — row click with modifier key state (from adapter)
//   CHECKBOX_ROW_CHANGED  — checkbox toggled on a row (from adapter)
//   SELECT_ALL_TOGGLED    — header checkbox toggled (from adapter)
//   PAGINATED_DATA_CHANGED — recompute header checkbox state when visible rows change
//   DATA_SET              — clear selection on data reload
//   ROW_DELETED           — remove deleted row from selection
//
// Events this plugin EMITS:
//   SELECTION_CHANGED     — any selection change
//   SELECT_ALL_CHANGED    — isAllSelected / isIndeterminate state

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { RowId, SelectionMode } from '../../types/index'
import { ROW_MODEL_PLUGIN_ID } from '../row-model/index'
import type { RowModelPlugin } from '../row-model/index'

// ── Plugin ID ─────────────────────────────────

export const SELECTION_PLUGIN_ID = 'selection'

// ── Config ────────────────────────────────────

export interface SelectionConfig {
  // Selection mode — default: 'none'
  mode?: SelectionMode

  // What the Select All header checkbox selects
  // 'page' — only rows on the current paginated page (default)
  // 'all'  — all filtered rows in memory (sorted namespace)
  selectAllScope?: 'page' | 'all'

  // In single mode: clicking an already-selected row deselects it
  // Default: true
  deselectOnClick?: boolean
}

// ── Adapter Payloads ──────────────────────────
// These are emitted by the adapter and consumed here

export interface RowClickSelectionPayload {
  rowId: RowId
  // Modifier key state at time of click
  shiftKey: boolean
  ctrlKey: boolean
  metaKey: boolean
}

export interface CheckboxRowChangedPayload {
  rowId: RowId
  checked: boolean
}

export interface SelectAllToggledPayload {
  checked: boolean
}

// ── Implementation ─────────────────────────────

export class SelectionPlugin implements Plugin {
  readonly id = SELECTION_PLUGIN_ID

  private context!: PluginContext
  private config: SelectionConfig = {}

  // Active selection mode
  private mode: SelectionMode = 'none'

  // Core selection state
  private selectedIds: Set<RowId> = new Set()

  // O(1) select-all flag — when true, every row is considered selected
  // without storing individual IDs. Individual deselections after a
  // select-all are tracked in _deselectedAfterSelectAll.
  private _selectAllActive: boolean = false
  private _deselectedAfterSelectAll: Set<RowId> = new Set()

  // Anchor row for Shift+Click range selection
  // Always the last row clicked WITHOUT shift held
  private anchorId: RowId | null = null

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: SelectionConfig): void {
    this.config = config
    this.mode = config.mode ?? 'none'
  }

  // ── Extract Row ID ─────────────────────────
  // sorted/paginated rows are plain data objects — not NormalizedRows.
  // Use RowModelPlugin to get the correctly-extracted engine ID for a row.
  // Falls back to reading r['id'] directly only when RowModelPlugin is
  // unavailable (standalone unit-test use).

  private extractRowId(row: unknown): RowId {
    // Try _id shortcut first — set by RowModelPlugin on NormalizedRows
    const data = row as Record<string, unknown>
    if (data['_id'] !== undefined && data['_id'] !== null) {
      return String(data['_id'])
    }

    // Use RowModelPlugin's O(1) reverse WeakMap index — getIdForData(row)
    // is a direct WeakMap lookup, not a scan of all rows.
    const rowModel =
      this.context?.getPlugin<RowModelPlugin>(ROW_MODEL_PLUGIN_ID)
    if (rowModel) {
      const id = rowModel.getIdForData(row)
      if (id !== null) return id
    }

    // Last fallback: direct 'id' field (default rowId, no RowModelPlugin)
    return String(data['id'] ?? '')
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // Write initial empty state
    this.syncToStore()

    // Row clicked with optional modifier keys
    this.cleanups.push(
      context.eventBus.on(GridEvent.ROW_CLICK_SELECTION, this.handleRowClick)
    )

    // Checkbox toggled on a single row
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.CHECKBOX_ROW_CHANGED,
        this.handleCheckboxRow
      )
    )

    // Header select-all checkbox toggled
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.SELECT_ALL_TOGGLED,
        this.handleSelectAllToggled
      )
    )

    // Recompute header checkbox state whenever paginated rows change
    // Covers: page change, page size change, filter change
    // Selection itself is never cleared here — only the header state updates
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.PAGINATED_DATA_CHANGED,
        this.handlePageChanged
      )
    )

    // New data loaded — clear selection
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_SET, this.handleDataSet)
    )

    // Row deleted — remove it from selection if present
    this.cleanups.push(
      context.eventBus.on(GridEvent.ROW_DELETED, this.handleRowDeleted)
    )
  }

  // ── Event Handlers ─────────────────────────

  private handleRowClick = (payload: RowClickSelectionPayload): void => {
    if (this.mode === 'none') return

    const { rowId, shiftKey, ctrlKey, metaKey } = payload
    const isMultiKey = ctrlKey || metaKey

    if (this.mode === 'single') {
      this.applySingleClick(rowId)
      return
    }

    // ── Multiple mode ─────────────────────────

    if (shiftKey && this.anchorId !== null) {
      // Shift+Click — select range from anchor to clicked row
      this.applyShiftClick(rowId)
    } else if (isMultiKey) {
      // Ctrl/Cmd+Click — toggle individual row, update anchor
      this.applyCtrlClick(rowId)
    } else {
      // Plain click — select only this row, reset anchor
      this.selectedIds.clear()
      this.selectedIds.add(rowId)
      this.anchorId = rowId
      this.commit()
    }
  }

  private handleCheckboxRow = (payload: CheckboxRowChangedPayload): void => {
    if (this.mode === 'none') return

    const { rowId, checked } = payload

    if (this.mode === 'single') {
      // Checkbox in single mode — select/deselect this row only
      this.selectedIds.clear()
      if (checked) {
        this.selectedIds.add(rowId)
        this.anchorId = rowId
      } else {
        this.anchorId = null
      }
      this.commit()
      return
    }

    // Multiple mode — toggle without affecting other selections
    if (checked) {
      this.selectedIds.add(rowId)
      this.anchorId = rowId
    } else {
      this.selectedIds.delete(rowId)
      if (this.anchorId === rowId) {
        this.anchorId = null
      }
    }
    this.commit()
  }

  private handleSelectAllToggled = (payload: SelectAllToggledPayload): void => {
    if (this.mode !== 'multiple') return

    const scope = this.config.selectAllScope ?? 'page'
    const paginated = this.context.store.read('paginated').rows
    const sorted = this.context.store.read('sorted').rows
    const referenceRows =
      scope === 'all' || paginated.length === 0 ? sorted : paginated

    if (payload.checked) {
      if (scope === 'all' || paginated.length === 0) {
        // O(1) flag-based select-all for full dataset
        this._selectAllActive = true
        this._deselectedAfterSelectAll.clear()
      } else {
        // scope=page: page is small (≤ pageSize), iterate its rows — O(page)
        // Do NOT set the flag — rows outside this page must not appear selected
        this._selectAllActive = false
        this._deselectedAfterSelectAll.clear()
        referenceRows.forEach((r) => {
          const id = this.extractRowId(r)
          if (id) this.selectedIds.add(id)
        })
      }
    } else {
      if (this._selectAllActive) {
        // Clear flag and remove only reference rows from effective selection
        if (scope === 'all' || paginated.length === 0) {
          // Deselect all — just clear the flag
          this._selectAllActive = false
          this._deselectedAfterSelectAll.clear()
        } else {
          // scope=page with flag: deselect page rows via deselected set
          referenceRows.forEach((r) => {
            const id = this.extractRowId(r)
            if (id) this._deselectedAfterSelectAll.add(id)
          })
        }
      } else {
        // No flag — just remove reference rows from selectedIds
        referenceRows.forEach((r) => {
          const id = this.extractRowId(r)
          if (id) this.selectedIds.delete(id)
        })
      }
      this.anchorId = null
    }

    this.commit()
  }

  private handlePageChanged = (): void => {
    // Selection persists — just recompute the header checkbox state
    // because paginated.rows has changed to the new page
    this.syncToStore()
    this.context.eventBus.emit(GridEvent.SELECT_ALL_CHANGED, {
      ...this.computeSelectAllState(),
    })
  }

  private handleDataSet = (): void => {
    // New data — previous row IDs are meaningless, reset all selection state
    this._selectAllActive = false
    this._deselectedAfterSelectAll.clear()
    this.selectedIds.clear()
    this.anchorId = null
    this.commit()
  }

  private handleRowDeleted = (payload: { rowId: RowId }): void => {
    if (this._selectAllActive) {
      // When all are selected, a deleted row was selected — track its absence
      this._deselectedAfterSelectAll.delete(payload.rowId)
    } else {
      if (!this.selectedIds.has(payload.rowId)) return
      this.selectedIds.delete(payload.rowId)
    }
    if (this.anchorId === payload.rowId) {
      this.anchorId = null
    }
    this.commit()
  }

  // ── Click Strategies ───────────────────────

  private applySingleClick(rowId: RowId): void {
    const alreadySelected = this.selectedIds.has(rowId)
    const deselectOnClick = this.config.deselectOnClick ?? true

    if (alreadySelected && deselectOnClick) {
      this.selectedIds.clear()
      this.anchorId = null
    } else {
      this.selectedIds.clear()
      this.selectedIds.add(rowId)
      this.anchorId = rowId
    }

    this.commit()
  }

  private applyCtrlClick(rowId: RowId): void {
    if (this.isSelected(rowId)) {
      // Deselect without commit
      if (this._selectAllActive) {
        this._deselectedAfterSelectAll.add(rowId)
      } else {
        this.selectedIds.delete(rowId)
      }
      if (this.anchorId === rowId) {
        const remaining = [...this.selectedIds]
        this.anchorId =
          remaining.length > 0
            ? (remaining[remaining.length - 1] ?? null)
            : null
      }
    } else {
      // Select without commit
      if (this._selectAllActive) {
        this._deselectedAfterSelectAll.delete(rowId)
      } else {
        this.selectedIds.add(rowId)
      }
      this.anchorId = rowId
    }

    this.commit()
  }

  private applyShiftClick(rowId: RowId): void {
    // Determine row order — use paginated if available, else sorted (pagination disabled)
    const paginated = this.context.store.read('paginated').rows
    const rows =
      paginated.length > 0 ? paginated : this.context.store.read('sorted').rows

    // Build O(n) id map upfront to avoid O(n²) from calling getAllRows() per row
    const rowModel = this.context.getPlugin<RowModelPlugin>(ROW_MODEL_PLUGIN_ID)
    let dataToId: Map<unknown, string> | null = null
    if (rowModel) {
      dataToId = new Map(rowModel.getAllRows().map((nr) => [nr._data, nr._id]))
    }

    const rowIds = rows.map((r) => {
      if (dataToId) {
        const id = dataToId.get(r)
        if (id !== undefined) return id
      }
      return this.extractRowId(r)
    })

    const anchorIndex = rowIds.indexOf(this.anchorId!)
    const clickedIndex = rowIds.indexOf(rowId)

    if (anchorIndex === -1 || clickedIndex === -1) {
      // Either anchor or clicked row is not in current page — fallback to simple select
      this.selectedIds.add(rowId)
      this.commit()
      return
    }

    // Select the range — anchor stays fixed
    const from = Math.min(anchorIndex, clickedIndex)
    const to = Math.max(anchorIndex, clickedIndex)

    this.selectedIds.clear()
    for (let i = from; i <= to; i++) {
      this.selectedIds.add(rowIds[i]!)
    }

    // Anchor does NOT change on shift-click
    this.commit()
  }

  // ── Commit ─────────────────────────────────
  // Write to store and emit both selection events

  private commit(): void {
    this.syncToStore()
    this.emitEvents()
  }

  // ── Sync To Store ──────────────────────────
  // Writes selection state to the store.
  // selectedIds is written as the live internal Set — the store's shallow-copy
  // semantics (object spread on the namespace) produce a new namespace object
  // so React sees the change, but we don't pay for a full Set clone on every
  // commit. Public API callers that need a snapshot (getSelectedIds, emitEvents)
  // copy explicitly only when required.

  private syncToStore(): void {
    const { isAllSelected, isIndeterminate } = this.computeSelectAllState()

    // When _selectAllActive, avoid calling getSelectedCount() which iterates
    // all row IDs via RowModelPlugin — that would be O(n) on every commit.
    // Instead derive count from the store's own row totals directly.
    let count: number
    if (this._selectAllActive) {
      const sorted = this.context.store.read('sorted').rows
      const paginated = this.context.store.read('paginated').rows
      const total = sorted.length > 0 ? sorted.length : paginated.length
      count = total - this._deselectedAfterSelectAll.size
    } else {
      count = this.selectedIds.size
    }

    this.context.store.write('selection', {
      selectedIds: this.selectedIds,
      mode: this.mode,
      isAllSelected,
      isIndeterminate,
      count,
      anchorId: this.anchorId,
    })
  }

  // ── Emit Events ────────────────────────────
  // Clones selectedIds only here — external consumers (onSelectionChanged
  // callbacks) should receive an immutable snapshot, not the live internal Set.

  private emitEvents(): void {
    const { isAllSelected, isIndeterminate } = this.computeSelectAllState()

    // Mirror syncToStore — avoid O(n) getSelectedCount() when flag is active
    let count: number
    if (this._selectAllActive) {
      const sorted = this.context.store.read('sorted').rows
      const paginated = this.context.store.read('paginated').rows
      const total = sorted.length > 0 ? sorted.length : paginated.length
      count = total - this._deselectedAfterSelectAll.size
    } else {
      count = this.selectedIds.size
    }

    this.context.eventBus.emit(GridEvent.SELECTION_CHANGED, {
      selectedIds: new Set(this.selectedIds),
      count,
    })

    this.context.eventBus.emit(GridEvent.SELECT_ALL_CHANGED, {
      isAllSelected,
      isIndeterminate,
    })
  }

  // ── Select All State ───────────────────────
  // Computed against the configured scope

  private computeSelectAllState(): {
    isAllSelected: boolean
    isIndeterminate: boolean
  } {
    // O(1) short-circuit when select-all flag is active
    if (this._selectAllActive) {
      const hasDeselections = this._deselectedAfterSelectAll.size > 0
      return {
        isAllSelected: !hasDeselections,
        isIndeterminate: hasDeselections,
      }
    }

    const scope = this.config.selectAllScope ?? 'page'
    const paginated = this.context.store.read('paginated').rows
    const sorted = this.context.store.read('sorted').rows

    // For 'all' scope — compare against all rows in memory
    // For 'page' scope — compare against current page rows only
    // If pagination is disabled, paginated.rows is empty — fall back to sorted
    const referenceRows =
      scope === 'all' || paginated.length === 0 ? sorted : paginated

    const total = referenceRows.length

    // Count how many of the reference rows are currently selected
    const selectedInReference = referenceRows.filter((r) =>
      this.selectedIds.has(this.extractRowId(r))
    ).length

    const isAllSelected = total > 0 && selectedInReference === total
    const isIndeterminate = selectedInReference > 0 && !isAllSelected

    return { isAllSelected, isIndeterminate }
  }

  // ── Public API ─────────────────────────────
  // Called by Grid API — not by adapter directly

  selectRow(rowId: RowId): void {
    if (this.mode === 'none') return
    if (this.mode === 'single') {
      // Single mode always clears the flag
      this._selectAllActive = false
      this._deselectedAfterSelectAll.clear()
      this.selectedIds.clear()
    }
    if (this._selectAllActive) {
      // Row is already effectively selected — just un-deselect it if it was deselected
      this._deselectedAfterSelectAll.delete(rowId)
    } else {
      this.selectedIds.add(rowId)
    }
    this.anchorId = rowId
    this.commit()
  }

  deselectRow(rowId: RowId): void {
    if (this._selectAllActive) {
      this._deselectedAfterSelectAll.add(rowId)
    } else {
      if (!this.selectedIds.has(rowId)) return
      this.selectedIds.delete(rowId)
    }
    if (this.anchorId === rowId) this.anchorId = null
    this.commit()
  }

  toggleRow(rowId: RowId): void {
    if (this.isSelected(rowId)) {
      this.deselectRow(rowId)
    } else {
      this.selectRow(rowId)
    }
  }

  selectAll(): void {
    if (this.mode !== 'multiple') return
    this.handleSelectAllToggled({ checked: true })
  }

  deselectAll(): void {
    this._selectAllActive = false
    this._deselectedAfterSelectAll.clear()
    this.selectedIds.clear()
    this.anchorId = null
    this.commit()
  }

  isSelected(rowId: RowId): boolean {
    if (this._selectAllActive) {
      return !this._deselectedAfterSelectAll.has(rowId)
    }
    return this.selectedIds.has(rowId)
  }

  getSelectedIds(): RowId[] {
    if (this._selectAllActive) {
      // Use sorted namespace — contains only filtered rows, which is what
      // selectAllScope:'all' is documented to mean ("all filtered rows in memory").
      // rowModel.getRowIds() returns ALL rows regardless of filter state and
      // would incorrectly include rows hidden by an active filter.
      const sorted = this.context.store.read('sorted').rows as Array<
        Record<string, unknown>
      >
      const allIds = sorted.map((r) => this.extractRowId(r))
      return allIds.filter((id) => !this._deselectedAfterSelectAll.has(id))
    }
    return [...this.selectedIds]
  }

  getSelectedCount(): number {
    if (this._selectAllActive) {
      // Use sorted namespace to count only filtered rows (mirrors getSelectedIds fix)
      const sorted = this.context.store.read('sorted').rows
      const paginated = this.context.store.read('paginated').rows
      const total = sorted.length > 0 ? sorted.length : paginated.length
      return total - this._deselectedAfterSelectAll.size
    }
    return this.selectedIds.size
  }

  getMode(): SelectionMode {
    return this.mode
  }

  setMode(mode: SelectionMode): void {
    this.mode = mode
    // Enforce mode constraints on existing selection
    if (mode === 'none') {
      this.selectedIds.clear()
      this.anchorId = null
    } else if (mode === 'single' && this.selectedIds.size > 1) {
      // Keep only anchor row (or first selected)
      const keep = this.anchorId ?? [...this.selectedIds][0]
      this.selectedIds.clear()
      if (keep) this.selectedIds.add(keep)
    }
    this.commit()
  }

  getSelectionState() {
    return this.context.store.read('selection')
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
    this.selectedIds.clear()
    this.anchorId = null
  }
}
