// ============================================
// @elitegrid/vanilla — GridBody
// Scroll container that virtualises rows. Mirrors the
// React adapter's GridBody.tsx — shimmer loader, scrollbar
// compensation, scroll sync, keyboard focus management,
// and reset-on-sort/filter/page.
// ============================================

import { GridEvent } from '@elitegrid/core'
import type {
  ColumnDefinition,
  ColumnId,
  ViewportNamespace,
} from '@elitegrid/core'
import type { GridInstance } from '../create-grid'
import { makeRowIdAccessor } from '../create-grid'
import { h, type Unsub } from '../utils/dom'
import { calculateColumnWidths } from '../utils/columnWidths'
import { GridRow } from './GridRow'
import { GridOverlay } from './GridOverlay'

const CHECKBOX_WIDTH = 48

export class GridBody {
  el: HTMLElement
  private spacer: HTMLElement
  private translated: HTMLElement
  private shimmerEl: HTMLElement | null = null
  private overlay: GridOverlay

  private rowInstances = new Map<string, GridRow>()

  // Cached lookup maps — built once per definition change
  private columnDefMap = new Map<string, ColumnDefinition>()
  private columnOptionsMap = new Map<string, any>()
  private columnWidths = new Map<string, number>()
  private visibleColumnIds: ColumnId[] = []

  // Column-width cache — invalidated in rebuildColumnMaps() when definitions
  // change, so renderRows() skips recalculation on every scroll event.
  private cachedWidthsContainerWidth = -1
  private cachedWidthsMap = new Map<string, number>()

  // Shared cell registry — GridBody owns two store subscribers (focus + editing)
  // and routes changes to the single affected cell, replacing 200+ per-cell
  // subscriptions with O(1) Map lookups.
  private cellRegistry = new Map<string, import('./GridCell').GridCell>()
  private focusedCellKey: string | null = null
  private editingCellKey: string | null = null

  // P-03: delegated selection — single subscriber routes to affected rows only.
  private prevSelectedIds = new Set<string>()

  // P-02: pure-transform scroll fast-path — skip row diff when visible set unchanged.
  // Tracking first+last row IDs (not just count/start) so that sort/filter
  // reorders within the same window still trigger a re-render.
  private prevStartRowIndex = -1
  private prevVisibleCount = -1
  private prevFirstRowId = '\0'
  private prevLastRowId = '\0'
  // Set when the column maps/widths are rebuilt (e.g. a column resize). Forces
  // the next renderRows() to bypass the pure-scroll fast-path so the visible
  // rows re-apply the new column widths — otherwise resized columns and their
  // data cells fall out of alignment.
  private columnsDirty = false
  // Set when row DATA changed without the visible window changing (edit commit,
  // updateRow, setData with same shape). The fast-path only compares window
  // dims + first/last row IDs, so without this flag a committed edit would
  // never repaint its cell.
  private rowsDirty = false
  // Set when column widths were recalculated (containerWidth changed). The
  // header re-renders on its own containerWidth guard; the body rows must do a
  // full pass too or they keep stale widths and drift out of alignment.
  private widthsDirty = false

  // P-13: guard spacer/translated minWidth writes.
  private lastTotalWidth = -1
  private lastTotalHeight = -1

  // Row-id accessor — resolved once from options (never changes after
  // construction). Honours string field, function form, and the 'id' default.
  private getRowId: (row: Record<string, unknown>) => string | undefined

  private unsubs: Unsub[] = []
  // P-12: single ResizeObserver handles both emitSize and scrollbar compensation.
  private bodyResizeObserver: ResizeObserver | null = null
  private scrollRaf: number | null = null
  private initialSizeRaf: number | null = null
  // Last position emitted to the engine. iOS momentum scroll keeps firing
  // 'scroll' after scrollTop stops changing; treat identical consecutive
  // positions as no-ops so we don't re-run the viewport pipeline for nothing.
  private lastScrollTop = -1
  private lastScrollLeft = -1

  // Loading-shimmer state: hide the shimmer the moment we know data is loaded.
  private hasAttemptedLoad: boolean
  private isLoading: boolean
  // Shimmer dimension cache — avoids rebuilding DOM if rowHeight/column count unchanged.
  private shimmerRowHeight = -1
  private shimmerColCount = -1

  constructor(
    private grid: GridInstance<unknown>,
    private headerEl: HTMLElement
  ) {
    this.getRowId = makeRowIdAccessor(grid.options.rowId) as (
      row: Record<string, unknown>
    ) => string | undefined

    this.el = h('div', {
      class: 'yg-body',
      attrs: { role: 'presentation', tabindex: '0' },
      style: {
        flex: '1',
        // Always reserve the vertical scrollbar track so clientWidth stays
        // stable — the column width math must not jump when the scrollbar
        // appears or disappears.
        overflowY: 'scroll',
        overflowX: 'auto',
        position: 'relative',
        WebkitOverflowScrolling: 'touch',
        outline: 'none',
      },
      on: {
        keydown: (e) => this.onKeyDown(e as KeyboardEvent),
      },
    })

    // Spacer reserves the full virtual height so the scrollbar reflects total rows.
    this.spacer = h('div', {
      attrs: { role: 'presentation' },
      style: {
        height: '0px',
        minWidth: '0px',
        position: 'relative',
        pointerEvents: 'none',
        // contain:strict isolates this subtree from the rest of the page;
        // the browser will only repaint inside it, never the scroll container
        // background, during virtualisation transforms.
        contain: 'strict',
      },
    })

    // Translated wrapper — translateY positions visible rows. role=rowgroup
    // keeps the ARIA grid tree intact (grid → rowgroup → row → gridcell)
    // despite the presentational spacer/scroll wrappers in between.
    this.translated = h('div', {
      attrs: { role: 'rowgroup' },
      style: {
        position: 'absolute',
        top: '0',
        left: '0',
        minWidth: '0px',
        transform: 'translateY(0px)',
        pointerEvents: 'auto',
        // Promote to GPU layer so transform updates don't repaint the
        // scroll container background each frame.
        willChange: 'transform',
      },
    })

    // Sticky header lives INSIDE this scroll container (first child) so
    // horizontal scroll moves the header and rows as a single native unit —
    // no JS scroll-sync needed. The header pins to the top during vertical
    // scroll via position:sticky (set in GridHeader).
    this.el.appendChild(this.headerEl)

    this.spacer.appendChild(this.translated)
    this.el.appendChild(this.spacer)

    this.overlay = new GridOverlay(grid)
    this.el.appendChild(this.overlay.el)

    // Inject the shimmer keyframes once per document.
    this.ensureShimmerStyle()

    // ── Loading state — flash-prevention parity with React adapter ──────
    this.hasAttemptedLoad =
      (this.grid.kernel.store.read('raw').rows as unknown[]).length > 0
    this.isLoading =
      (this.grid.kernel.store.read('viewport').visibleRows as unknown[])
        .length === 0 && !this.hasAttemptedLoad

    // ── Wire engine subscriptions ───────────────────────────────────────
    // viewport is the canonical signal for "what to render" — it's derived
    // from raw → filtered → sorted → paginated and updates whenever any
    // upstream pipeline stage changes. Subscribing here once avoids
    // running renderRows twice on a single pipeline pass.
    this.unsubs.push(
      grid.kernel.store.subscribe('viewport', () => this.renderRows()),
      grid.kernel.store.subscribe('columns', () => {
        this.rebuildColumnMaps()
        this.renderRows()
      })
    )

    // ── Loading-state event wiring ───────────────────────────────────────
    this.unsubs.push(
      grid.kernel.eventBus.on(GridEvent.VIEWPORT_CHANGED, () => {
        const { visibleRows } = grid.kernel.store.read('viewport')
        if ((visibleRows as unknown[]).length > 0 && this.isLoading) {
          this.isLoading = false
          this.renderRows()
        }
      }),
      grid.kernel.eventBus.on(GridEvent.DATA_LOADING, () => {
        this.hasAttemptedLoad = true
        if (!this.isLoading) {
          this.isLoading = true
          this.renderRows()
        }
      }),
      // Terminal load events — clear the shimmer even when the source resolves
      // with ZERO rows (VIEWPORT_CHANGED above only clears on >0 rows) or when
      // the load fails. Otherwise the shimmer animates forever beneath the
      // semi-transparent empty/error overlay.
      grid.kernel.eventBus.on(GridEvent.DATA_SET, () => {
        this.isLoading = false
        this.rowsDirty = true
        this.renderRows()
      }),
      grid.kernel.eventBus.on(GridEvent.DATA_LOAD_ERROR, () => {
        if (this.isLoading) {
          this.isLoading = false
          this.renderRows()
        }
      })
    )

    // ── Data-change dirty tracking ──────────────────────────────────────
    // Row data can change while the visible window (start index, count,
    // first/last IDs) stays identical — e.g. a committed edit or updateRow().
    // The pipeline's viewport pass may have already run (and hit the
    // fast-path) before this listener fires, so we must both mark the rows
    // dirty AND run a render pass ourselves. DATA_CHANGED is emitted after
    // the raw write on every mutation path (edit commit, updateRow, addRow,
    // deleteRow/deleteRows), so it is the single reliable signal.
    this.unsubs.push(
      grid.kernel.eventBus.on(GridEvent.DATA_CHANGED, () => {
        this.rowsDirty = true
        this.renderRows()
      })
    )

    // ── Focus DOM management ────────────────────────────────────────────
    this.unsubs.push(
      grid.kernel.eventBus.on(
        GridEvent.FOCUS_CHANGED,
        (payload: unknown) => this.handleFocusChanged(payload)
      )
    )

    // ── Delegated cell focus/editing subscribers (OPT-03) ───────────────
    // Two subscribers replace 200+ per-cell subscriptions. Each change only
    // touches the 1–2 affected cells via O(1) Map lookups.
    this.unsubs.push(
      grid.kernel.store.subscribe('focus', () => {
        const { focusedCell } = grid.kernel.store.read('focus')
        const newKey = focusedCell
          ? `${focusedCell.rowId}:${focusedCell.columnId}`
          : null
        if (newKey !== this.focusedCellKey) {
          if (this.focusedCellKey)
            this.cellRegistry.get(this.focusedCellKey)?.setFocused(false)
          if (newKey)
            this.cellRegistry.get(newKey)?.setFocused(true)
          this.focusedCellKey = newKey
        }
      }),
      grid.kernel.store.subscribe('editing', () => {
        const state = grid.kernel.store.read('editing')
        const newKey =
          state.isEditing && state.editingCell
            ? `${state.editingCell.rowId}:${state.editingCell.columnId}`
            : null
        if (newKey !== this.editingCellKey) {
          if (this.editingCellKey)
            this.cellRegistry.get(this.editingCellKey)?.setEditing(false)
          if (newKey)
            this.cellRegistry.get(newKey)?.setEditing(true)
          this.editingCellKey = newKey
        }
      })
    )

    // ── Reset scroll on sort/filter/page change ─────────────────────────
    this.unsubs.push(
      grid.kernel.eventBus.on(GridEvent.SORT_COMPLETED, () => {
        // Only vertical reset — preserving scrollLeft matches the React
        // adapter and keeps the user's horizontal position when sorting.
        this.el.scrollTop = 0
      }),
      grid.kernel.eventBus.on(GridEvent.PAGE_CHANGED, () => {
        this.el.scrollTop = 0
      }),
      grid.kernel.eventBus.on(GridEvent.FILTER_COMPLETED, () => {
        this.el.scrollTop = 0
      })
    )

    // ── Scroll → engine sync + header scroll sync ───────────────────────
    const onScroll = () => this.onScroll()
    this.el.addEventListener('scroll', onScroll, { passive: true })
    this.unsubs.push(() => this.el.removeEventListener('scroll', onScroll))

    // ResizeObserver keeps the engine's container size in sync. No header
    // scrollbar compensation needed — the sticky header lives inside this same
    // scroll container, so it never overlaps the vertical scrollbar.
    this.bodyResizeObserver = new ResizeObserver(() => {
      this.emitSize()
    })
    this.bodyResizeObserver.observe(this.el)
    this.unsubs.push(() => {
      this.bodyResizeObserver?.disconnect()
      this.bodyResizeObserver = null
    })

    // Browser-zoom fallback: Safari (and some Chromium versions) don't
    // reliably fire ResizeObserver on cmd+/- because the element's CSS
    // pixel size changes are reported asynchronously or coalesced. The
    // window 'resize' event fires reliably on zoom in all browsers, so
    // use it as a safety net to keep column widths in sync with the
    // viewport. RAF-debounced so we don't thrash the engine.
    let zoomRaf: number | null = null
    const onWindowResize = () => {
      if (zoomRaf !== null) return
      zoomRaf = requestAnimationFrame(() => {
        zoomRaf = null
        this.emitSize()
      })
    }
    window.addEventListener('resize', onWindowResize, { passive: true })
    this.unsubs.push(() => {
      window.removeEventListener('resize', onWindowResize)
      if (zoomRaf !== null) cancelAnimationFrame(zoomRaf)
    })

    // Initial size — must fire after layout so the scrollbar track is laid
    // out and clientWidth correctly excludes it.
    this.initialSizeRaf = requestAnimationFrame(() => {
      this.initialSizeRaf = null
      this.emitSize()
    })

    // P-03: delegated selection — single subscriber diffs prev vs next and
    // routes setSelected() only to the 1-2 affected rows, instead of every
    // visible row subscribing independently.
    this.unsubs.push(
      grid.kernel.store.subscribe('selection', () => {
        const nextIds: Set<string> = grid.kernel.store.read('selection').selectedIds
        for (const id of nextIds) {
          if (!this.prevSelectedIds.has(id)) {
            this.rowInstances.get(id)?.setSelected(true)
          }
        }
        for (const id of this.prevSelectedIds) {
          if (!nextIds.has(id)) {
            this.rowInstances.get(id)?.setSelected(false)
          }
        }
        this.prevSelectedIds = new Set(nextIds)
      })
    )

    this.rebuildColumnMaps()
    this.renderRows()
  }

  // ── Public ──────────────────────────────────────────────────────────

  destroy(): void {
    if (this.scrollRaf != null) cancelAnimationFrame(this.scrollRaf)
    if (this.initialSizeRaf != null) cancelAnimationFrame(this.initialSizeRaf)
    this.unsubs.forEach((fn) => fn())
    this.unsubs.length = 0
    this.rowInstances.forEach((r) => r.destroy())
    this.rowInstances.clear()
    this.prevSelectedIds.clear()
    this.overlay.destroy()
    this.el.remove()
  }

  // ── Internal helpers ────────────────────────────────────────────────

  private rebuildColumnMaps(): void {
    const { definitions } = this.grid.kernel.store.read('columns')
    this.columnDefMap = new Map(definitions.map((d) => [d.id, d]))
    this.columnOptionsMap = new Map(
      this.grid.options.columns.map((c) => [c.field as string, c])
    )
    // Invalidate the column-width cache — structure/widths may have changed.
    this.cachedWidthsContainerWidth = -1
    // Force the next renderRows() to re-apply widths to the visible rows even
    // when the row window is unchanged (a resize keeps the same rows visible).
    this.columnsDirty = true
  }

  private showCheckboxes(): boolean {
    const sel = this.grid.options.selection
    return sel?.mode !== 'none' && (sel?.showCheckboxes ?? true)
  }

  private emitSize(): void {
    const width =
      this.el.clientWidth - (this.showCheckboxes() ? CHECKBOX_WIDTH : 0)
    const height = this.el.clientHeight
    if (width > 0 && height > 0) {
      this.grid.kernel.eventBus.emit(GridEvent.CONTAINER_RESIZED, {
        width,
        height,
      })
    }
  }

  private onScroll(): void {
    if (this.scrollRaf !== null) return
    this.scrollRaf = requestAnimationFrame(() => {
      this.scrollRaf = null
      // Read on rAF only (not on the event) so the value is settled, and
      // clamp negatives from Safari's rubber-band overscroll to 0.
      const scrollTop = Math.max(0, this.el.scrollTop)
      const scrollLeft = Math.max(0, this.el.scrollLeft)
      // No-op when the position hasn't actually changed (iOS momentum fires
      // extra scroll events after scrollTop settles).
      if (scrollTop === this.lastScrollTop && scrollLeft === this.lastScrollLeft)
        return
      this.lastScrollTop = scrollTop
      this.lastScrollLeft = scrollLeft
      // No header scroll sync needed — the sticky header is inside this scroll
      // container and moves horizontally with the rows natively.
      // onScrollChange fires from the create-grid SCROLL_CHANGED listener —
      // not here — so the developer callback isn't double-called.
      this.grid.kernel.eventBus.emit(GridEvent.SCROLL_CHANGED, {
        scrollTop,
        scrollLeft,
      })
    })
  }

  private handleFocusChanged(payload: unknown): void {
    const { cell } = payload as {
      cell: { rowId: string; columnId: string } | null
    }
    if (!cell) return
    // rAF gives the row map a chance to commit DOM cells for newly scrolled rows.
    requestAnimationFrame(() => {
      // P-09: use O(1) cellRegistry lookup instead of a DOM attribute scan.
      const cellInst = this.cellRegistry.get(`${cell.rowId}:${cell.columnId}`)
      if (!cellInst) return
      const el = cellInst.el
      // If the cell already owns focus (e.g., the cell editor's input is the
      // current activeElement after a Tab-edit chain), do not call .focus()
      // on the cell wrapper — that would steal focus from the editor input.
      if (el.contains(document.activeElement)) return
      el.focus({ preventScroll: false })
    })
  }

  private onKeyDown(e: KeyboardEvent): void {
    // No-op while editing — the active editor owns the keystrokes.
    const { isEditing } = this.grid.kernel.store.read('editing')
    if (isEditing) return

    const keyMap: Record<string, { direction: string }> = {
      ArrowUp: { direction: 'up' },
      ArrowDown: { direction: 'down' },
      ArrowLeft: { direction: 'left' },
      ArrowRight: { direction: 'right' },
      Tab: { direction: e.shiftKey ? 'prev' : 'next' },
      Home: { direction: e.ctrlKey ? 'first' : 'rowStart' },
      End: { direction: e.ctrlKey ? 'last' : 'rowEnd' },
      Enter: { direction: 'none' },
    }
    const mapping = keyMap[e.key]
    if (!mapping) return

    // No keyboard trap (WCAG 2.1.2): let Tab escape the grid at its
    // boundaries — Tab on the last cell / Shift+Tab on the first cell falls
    // through to the browser's native focus order.
    if (e.key === 'Tab') {
      const { focusedCell } = this.grid.kernel.store.read('focus')
      if (!focusedCell) return
      const rowCount = (
        this.grid.kernel.store.read('paginated').rows as unknown[]
      ).length
      const colCount = this.visibleColumnIds.length
      const atFirst =
        focusedCell.rowIndex === 0 && focusedCell.columnIndex === 0
      const atLast =
        focusedCell.rowIndex === rowCount - 1 &&
        focusedCell.columnIndex === colCount - 1
      if ((e.shiftKey && atFirst) || (!e.shiftKey && atLast)) return
    }

    e.preventDefault()

    if (e.key === 'Enter') {
      const { focusedCell } = this.grid.kernel.store.read('focus')
      if (focusedCell) {
        this.grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, {
          cell: focusedCell,
        })
      }
      return
    }

    this.grid.kernel.eventBus.emit(GridEvent.FOCUS_MOVE_REQUESTED, {
      direction: mapping.direction,
      editableOnly: false,
    })
  }

  // ── Rendering ───────────────────────────────────────────────────────

  private renderRows(): void {
    const viewport = this.grid.kernel.store.read(
      'viewport'
    ) as ViewportNamespace
    const {
      visibleRows,
      visibleColumnIds,
      offsetTop,
      totalHeight,
      rowHeight,
      containerWidth,
      totalWidth,
      startRowIndex,
    } = viewport

    const { definitions } = this.grid.kernel.store.read('columns')

    this.visibleColumnIds = visibleColumnIds
    // Reuse cached widths when containerWidth is unchanged (most scroll events).
    // rebuildColumnMaps() resets cachedWidthsContainerWidth on column changes.
    if (containerWidth !== this.cachedWidthsContainerWidth) {
      this.cachedWidthsContainerWidth = containerWidth
      this.cachedWidthsMap = calculateColumnWidths(
        definitions,
        this.grid.options.columns,
        containerWidth
      )
      // Widths just changed — the visible rows must re-apply them even when
      // the row window is otherwise identical (e.g. width-only container
      // resize), or header and body columns drift out of alignment.
      this.widthsDirty = true
    }
    this.columnWidths = this.cachedWidthsMap

    // P-13: guard spacer/translated dimension writes — skip when unchanged.
    if (totalHeight !== this.lastTotalHeight) {
      this.lastTotalHeight = totalHeight
      this.spacer.style.height = `${totalHeight}px`
    }
    if (totalWidth !== this.lastTotalWidth) {
      this.lastTotalWidth = totalWidth
      // Include the checkbox column (rendered outside the engine model) so the
      // scrollable area matches the actual row width and the sticky header's
      // minWidth — keeps header and rows aligned when scrolled to the far right.
      const scrollableWidth =
        totalWidth + (this.showCheckboxes() ? CHECKBOX_WIDTH : 0)
      this.spacer.style.minWidth = `${scrollableWidth}px`
      this.translated.style.minWidth = `${scrollableWidth}px`
    }
    this.translated.style.transform = `translateY(${offsetTop}px)`

    // P-02: fast path — when the visible row window AND its first/last row
    // identities haven't changed, only the translateY offset changed (pure
    // scroll). Skip the entire row-diff and update loops.
    // First/last IDs catch sort/filter reorders that preserve window dims.
    const nextRows = visibleRows as Array<Record<string, unknown>>
    const firstRowId =
      nextRows.length > 0
        ? (this.getRowId(nextRows[0]!) ?? `__row_${startRowIndex}`)
        : '\0'
    const lastRowId =
      nextRows.length > 0
        ? (this.getRowId(nextRows[nextRows.length - 1]!) ??
          `__row_${startRowIndex + nextRows.length - 1}`)
        : '\0'
    if (
      !this.isLoading &&
      !this.columnsDirty &&
      !this.rowsDirty &&
      !this.widthsDirty &&
      startRowIndex === this.prevStartRowIndex &&
      nextRows.length === this.prevVisibleCount &&
      firstRowId === this.prevFirstRowId &&
      lastRowId === this.prevLastRowId
    ) {
      return
    }
    // A full pass is running — clear the dirty flags (row data and widths get
    // applied to every reused row via inst.update() below).
    this.columnsDirty = false
    this.rowsDirty = false
    this.widthsDirty = false
    this.prevFirstRowId = firstRowId
    this.prevLastRowId = lastRowId

    // ── Shimmer skeleton (loading) ─────────────────────────────────────
    if (this.isLoading) {
      this.ensureShimmer(rowHeight)
    } else if (this.shimmerEl) {
      // Hide instead of removing — avoids recreating 100+ DOM nodes next time.
      this.shimmerEl.style.display = 'none'
    }

    // ── Reconcile rows (keyed diff) ────────────────────────────────────
    this.prevStartRowIndex = startRowIndex
    this.prevVisibleCount = nextRows.length

    const nextOrder: string[] = new Array(nextRows.length)
    const nextIds = new Set<string>()

    for (let i = 0; i < nextRows.length; i++) {
      const row = nextRows[i]!
      const rowId = this.getRowId(row) ?? `__row_${startRowIndex + i}`
      nextOrder[i] = rowId
      nextIds.add(rowId)
    }

    // Remove rows that are no longer visible.
    for (const [id, inst] of this.rowInstances) {
      if (!nextIds.has(id)) {
        inst.destroy()
        this.rowInstances.delete(id)
      }
    }

    // Reuse / create + place in correct order.
    let cursor: Node | null = null
    for (let i = 0; i < nextRows.length; i++) {
      const row = nextRows[i]!
      const rowId = nextOrder[i]!
      const rowIndex = startRowIndex + i
      let inst = this.rowInstances.get(rowId)
      if (!inst) {
        inst = new GridRow({
          grid: this.grid,
          rowId,
          row,
          rowIndex,
          rowHeight,
          visibleColumnIds: this.visibleColumnIds,
          columnWidths: this.columnWidths,
          columnDefMap: this.columnDefMap,
          columnOptionsMap: this.columnOptionsMap,
          cellRegistry: this.cellRegistry,
        })
        this.rowInstances.set(rowId, inst)
      } else {
        inst.update({
          row,
          rowIndex,
          rowHeight,
          visibleColumnIds: this.visibleColumnIds,
          columnWidths: this.columnWidths,
          columnDefMap: this.columnDefMap,
          columnOptionsMap: this.columnOptionsMap,
        })
      }
      const nextSibling: Node | null = cursor
        ? cursor.nextSibling
        : this.translated.firstChild
      if (inst.el !== nextSibling) {
        this.translated.insertBefore(inst.el, nextSibling)
      }
      cursor = inst.el
    }
  }

  private ensureShimmerStyle(): void {
    if (document.getElementById('yg-shimmer-style')) return
    const style = document.createElement('style')
    style.id = 'yg-shimmer-style'
    style.textContent =
      '@keyframes yg-shimmer { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } }'
    document.head.appendChild(style)
  }

  private ensureShimmer(rowHeight: number): void {
    const colCount = this.visibleColumnIds.length
    // Reuse the cached shimmer element when dimensions are unchanged.
    if (
      this.shimmerEl &&
      this.shimmerRowHeight === rowHeight &&
      this.shimmerColCount === colCount
    ) {
      this.shimmerEl.style.display = 'flex'
      if (!this.el.contains(this.shimmerEl)) this.el.appendChild(this.shimmerEl)
      return
    }
    // Dimensions changed — rebuild and cache.
    this.shimmerEl?.remove()
    this.shimmerEl = null
    this.shimmerRowHeight = rowHeight
    this.shimmerColCount = colCount

    const skeletonRowCount = Math.ceil(
      (this.el.clientHeight || 400) / rowHeight
    )
    const wrap = h('div', {
      attrs: { 'aria-hidden': 'true' },
      style: {
        position: 'absolute',
        top: '0',
        left: '0',
        right: '0',
        bottom: '0',
        backgroundColor: 'var(--eg-row-bg, #ffffff)',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden',
        // Below the sticky header (zIndex 2) so column names stay visible
        // while rows load.
        zIndex: '1',
      },
    })

    for (let i = 0; i < skeletonRowCount; i++) {
      const row = h('div', {
        style: {
          height: `${rowHeight}px`,
          minHeight: `${rowHeight}px`,
          display: 'flex',
          alignItems: 'center',
          borderBottom: '1px solid var(--eg-row-border, #f3f4f6)',
          backgroundColor:
            i % 2 === 0
              ? 'var(--eg-row-striped-bg, #f9fafb)'
              : 'var(--eg-row-bg, #ffffff)',
          boxSizing: 'border-box',
          flexShrink: '0',
        },
      })
      for (const colId of this.visibleColumnIds) {
        const colWidth = this.columnWidths.get(colId) ?? 150
        const cell = h('div', {
          style: {
            width: `${colWidth}px`,
            minWidth: `${colWidth}px`,
            maxWidth: `${colWidth}px`,
            height: '100%',
            display: 'flex',
            alignItems: 'center',
            padding: '0 12px',
            boxSizing: 'border-box',
            flexShrink: '0',
          },
        })
        const bar = h('div', {
          style: {
            width: '100%',
            height: '12px',
            borderRadius: '6px',
            background:
              'linear-gradient(90deg, var(--eg-skeleton-base, #e5e7eb) 25%, var(--eg-skeleton-highlight, #f3f4f6) 50%, var(--eg-skeleton-base, #e5e7eb) 75%)',
            backgroundSize: '200% 100%',
            animation: 'yg-shimmer 1.2s infinite',
          },
        })
        cell.appendChild(bar)
        row.appendChild(cell)
      }
      wrap.appendChild(row)
    }
    this.shimmerEl = wrap
    this.el.appendChild(wrap)
  }
}
