// ============================================
// @elitegrid/vanilla — GridCell
// Single cell in a virtualised row. Owns:
//   • per-cell selectors for focus + editing state
//   • formatter / cell class application
//   • click-to-edit, double-click-to-edit
//   • cell-click selection (with edit-protection like React)
//   • mounts/unmounts GridCellEditor when this cell is editing
// ============================================

import { GridEvent } from '@elitegrid/core'
import type {
  CellPosition,
  ColumnDefinition,
  ColumnId,
} from '@elitegrid/core'
import type { ColumnDef, GridInstance } from '../create-grid'
import { h } from '../utils/dom'
import { GridCellEditor } from './GridCellEditor'

export interface GridCellOptions {
  grid: GridInstance<unknown>
  rowId: string
  columnId: ColumnId
  columnIndex: number
  rowIndex: number
  row: Record<string, unknown>
  rowHeight: number
  columnWidths: Map<string, number>
  columnDefMap: Map<string, ColumnDefinition>
  columnOptionsMap: Map<string, ColumnDef>
  // Shared registry — GridBody subscribes once and routes focus/editing changes
  // to the affected cell only, instead of every cell subscribing independently.
  cellRegistry: Map<string, GridCell>
  // Added to aria-colindex so data cells account for the checkbox column
  // (which is rendered outside the engine's column model at index 1).
  ariaColOffset?: number
}

export interface GridCellUpdate {
  row?: Record<string, unknown>
  rowIndex?: number
  columnIndex?: number
  rowHeight?: number
  columnWidths?: Map<string, number>
  columnDefMap?: Map<string, ColumnDefinition>
  columnOptionsMap?: Map<string, ColumnDef>
}

export class GridCell {
  el: HTMLElement

  private text: HTMLElement
  private editor: GridCellEditor | null = null

  private grid: GridInstance<unknown>
  private rowId: string
  private columnId: ColumnId
  private columnIndex: number
  private rowIndex: number
  private row: Record<string, unknown>
  private rowHeight: number
  private columnWidths: Map<string, number>
  private columnDefMap: Map<string, ColumnDefinition>
  private columnOptionsMap: Map<string, ColumnDef>

  private isFocused: boolean
  private isEditing: boolean
  private cellRegistry: Map<string, GridCell>
  private ariaColOffset: number

  // Row-identity + column-map guard for renderDisplay(). Its outputs (display
  // value, cellClass, aria-readonly) are derived purely from the row data and
  // the column maps. The engine creates a NEW row object on any data change
  // (ROW_UPDATED spreads a fresh object in create-grid.ts), and column changes
  // produce new map references, so reference equality is a sound signal for
  // "nothing renderable changed" — letting reused cells skip the formatter,
  // cellClass, and editable work during incremental scroll.
  private lastRowRef: unknown = undefined
  private lastOptionsMapRef: Map<string, ColumnDef> | null = null
  private lastDefMapRef: Map<string, ColumnDefinition> | null = null
  private lastEditable: boolean | null = null

  // Last rendered display value (memo equivalent — skip text write when unchanged)
  private lastDisplay = '�'
  private lastClass = '�'
  private lastWidth = -1
  private lastOutline = '�'

  constructor(opts: GridCellOptions) {
    this.grid = opts.grid
    this.rowId = opts.rowId
    this.columnId = opts.columnId
    this.columnIndex = opts.columnIndex
    this.rowIndex = opts.rowIndex
    this.row = opts.row
    this.rowHeight = opts.rowHeight
    this.columnWidths = opts.columnWidths
    this.columnDefMap = opts.columnDefMap
    this.columnOptionsMap = opts.columnOptionsMap
    this.cellRegistry = opts.cellRegistry
    this.ariaColOffset = opts.ariaColOffset ?? 0

    const focusState = this.grid.kernel.store.read('focus')
    this.isFocused =
      focusState.focusedCell?.rowId === this.rowId &&
      focusState.focusedCell?.columnId === this.columnId
    const editingState = this.grid.kernel.store.read('editing')
    this.isEditing =
      editingState.isEditing &&
      editingState.editingCell?.rowId === this.rowId &&
      editingState.editingCell?.columnId === this.columnId

    this.el = h('div', {
      class: 'yg-cell',
      attrs: {
        role: 'gridcell',
        'aria-colindex': String(this.columnIndex + 1 + this.ariaColOffset),
        'data-rowid': this.rowId,
        'data-columnid': this.columnId,
        tabindex: this.isFocused ? '0' : '-1',
      },
      style: {
        display: 'flex',
        alignItems: 'center',
        overflow: 'hidden',
        whiteSpace: 'nowrap',
        textOverflow: 'ellipsis',
        flexShrink: '0',
        boxSizing: 'border-box',
        position: 'relative',
        fontSize: '0.875rem',
        color: 'var(--eg-cell-text, #111827)',
        padding: '0 12px',
        height: '100%',
        outlineOffset: '-2px',
      },
      on: {
        focus: () => this.onFocus(),
        click: (e) => this.onClick(e as MouseEvent),
        dblclick: (e) => this.onDoubleClick(e as MouseEvent),
      },
    })

    this.text = h('span', {
      class: 'yg-cell__text',
      style: {
        overflow: 'hidden',
        textOverflow: 'ellipsis',
        whiteSpace: 'nowrap',
        width: '100%',
      },
    })
    this.el.appendChild(this.text)

    // Register in the shared cell registry so GridBody's single focus/editing
    // subscribers can route changes directly here instead of broadcasting to all
    // 200+ cells. Deregistered in destroy().
    this.cellRegistry.set(`${this.rowId}:${this.columnId}`, this)

    this.applySize()
    this.applyBorder()
    this.applyOutline()
    this.renderDisplay()
    if (this.isEditing) this.applyEditingState()
  }

  update(opts: GridCellUpdate): void {
    let needsBorder = false
    if (opts.columnWidths) this.columnWidths = opts.columnWidths
    if (opts.columnDefMap) {
      this.columnDefMap = opts.columnDefMap
      needsBorder = true
    }
    if (opts.columnOptionsMap) this.columnOptionsMap = opts.columnOptionsMap
    if (opts.rowHeight !== undefined && opts.rowHeight !== this.rowHeight) {
      this.rowHeight = opts.rowHeight
    }
    if (opts.rowIndex !== undefined && opts.rowIndex !== this.rowIndex) {
      this.rowIndex = opts.rowIndex
    }
    if (
      opts.columnIndex !== undefined &&
      opts.columnIndex !== this.columnIndex
    ) {
      this.columnIndex = opts.columnIndex
      this.el.setAttribute(
        'aria-colindex',
        String(this.columnIndex + 1 + this.ariaColOffset)
      )
    }
    if (opts.row) {
      this.row = opts.row
    }
    this.applySize()
    if (needsBorder) this.applyBorder()
    this.renderDisplay()
  }

  destroy(): void {
    this.cellRegistry.delete(`${this.rowId}:${this.columnId}`)
    if (this.editor) {
      this.editor.destroy()
      this.editor = null
    }
    this.el.remove()
  }

  // Called by GridBody's single delegated focus subscriber.
  setFocused(focused: boolean): void {
    if (focused === this.isFocused) return
    this.isFocused = focused
    this.el.setAttribute('tabindex', focused ? '0' : '-1')
    this.applyOutline()
  }

  // Called by GridBody's single delegated editing subscriber.
  setEditing(editing: boolean): void {
    if (editing === this.isEditing) return
    this.isEditing = editing
    this.applyEditingState()
  }

  // ── Rendering pieces ───────────────────────────────────────────────

  private applySize(): void {
    const colDef = this.columnDefMap.get(this.columnId)
    const colWidth =
      this.columnWidths.get(this.columnId) ?? colDef?.width ?? 150
    if (colWidth !== this.lastWidth) {
      this.lastWidth = colWidth
      this.el.style.width = `${colWidth}px`
      this.el.style.minWidth = `${colWidth}px`
      this.el.style.maxWidth = `${colWidth}px`
    }
  }

  private applyBorder(): void {
    const showColumnBorders =
      this.grid.options.appearance?.showColumnBorders ?? false
    this.el.style.borderRight = showColumnBorders
      ? 'var(--eg-cell-border, 1px solid #e5e7eb)'
      : ''
  }

  private applyOutline(): void {
    const value = this.isFocused && !this.isEditing
      ? '2px solid var(--eg-primary, #6366f1)'
      : 'none'
    if (value !== this.lastOutline) {
      this.lastOutline = value
      this.el.style.outline = value
    }
  }

  private renderDisplay(): void {
    // Guard: skip the whole formatter/cellClass/editable pass when none of its
    // inputs changed. Reused cells on incremental scroll keep the same row
    // reference and column maps, so this short-circuits ~all cells per frame.
    if (
      this.row === this.lastRowRef &&
      this.columnOptionsMap === this.lastOptionsMapRef &&
      this.columnDefMap === this.lastDefMapRef
    ) {
      return
    }
    this.lastRowRef = this.row
    this.lastOptionsMapRef = this.columnOptionsMap
    this.lastDefMapRef = this.columnDefMap

    // Resolve display value via CellValuePlugin (formatter → raw fallback).
    const cellValuePlugin = this.grid.plugins.cellValue
    let displayValue: string
    if (cellValuePlugin) {
      displayValue = cellValuePlugin.getDisplayValue(this.row, this.columnId)
    } else {
      const v = this.row[this.columnId]
      displayValue = v === null || v === undefined ? '' : String(v)
    }

    if (displayValue !== this.lastDisplay) {
      this.lastDisplay = displayValue
      this.text.textContent = displayValue
      this.text.title = displayValue
    }

    // cellClass — string or function(value, row).
    const colOptions = this.columnOptionsMap.get(this.columnId)
    const cellClassOption = colOptions?.display?.cellClass
    const value = this.row[this.columnId]
    const extra =
      typeof cellClassOption === 'function'
        ? cellClassOption(value, this.row as any)
        : (cellClassOption ?? '')
    const next = ['yg-cell', extra].filter(Boolean).join(' ')
    if (next !== this.lastClass) {
      this.lastClass = next
      this.el.className = next
    }

    // ARIA — readonly status reflects per-row editable resolution. Cached so a
    // per-row editable function isn't re-invoked and the attribute isn't
    // rewritten when the resolved value is unchanged.
    const editable = this.resolveEditable()
    if (editable !== this.lastEditable) {
      this.lastEditable = editable
      this.el.setAttribute('aria-readonly', editable ? 'false' : 'true')
    }
  }

  private resolveEditable(): boolean {
    const colOptions = this.columnOptionsMap.get(this.columnId)
    const enabledConfig = colOptions?.edit?.enabled
    if (typeof enabledConfig === 'function') {
      return enabledConfig(this.row as any)
    }
    const colDef = this.columnDefMap.get(this.columnId) as
      | { editable?: boolean }
      | undefined
    return colDef?.editable ?? false
  }

  private applyEditingState(): void {
    if (this.isEditing) {
      // Hide display text and mount the editor.
      this.text.style.display = 'none'
      if (!this.editor) {
        const cell: CellPosition = {
          rowId: this.rowId,
          columnId: this.columnId,
          rowIndex: this.rowIndex,
          columnIndex: this.columnIndex,
        }
        const editorConfig =
          this.grid.plugins.edit.getColumnEditor(this.columnId) ?? null
        this.editor = new GridCellEditor({
          grid: this.grid,
          cell,
          editorConfig,
          rowHeight: this.rowHeight,
        })
        this.el.appendChild(this.editor.el)
      }
    } else {
      this.text.style.display = ''
      if (this.editor) {
        this.editor.destroy()
        this.editor = null
      }
    }
    this.applyOutline()
  }

  // ── Interaction ────────────────────────────────────────────────────

  private onFocus(): void {
    if (this.isFocused) return
    this.grid.kernel.eventBus.emit(GridEvent.FOCUS_SET_REQUESTED, {
      cell: {
        rowId: this.rowId,
        columnId: this.columnId,
        rowIndex: this.rowIndex,
        columnIndex: this.columnIndex,
      },
    })
  }

  private onDoubleClick(e: MouseEvent): void {
    e.stopPropagation()
    if (!this.resolveEditable()) return
    const trigger = this.grid.options.editing?.trigger ?? 'doubleClick'
    if (trigger !== 'doubleClick') return
    const cell: CellPosition = {
      rowId: this.rowId,
      columnId: this.columnId,
      rowIndex: this.rowIndex,
      columnIndex: this.columnIndex,
    }
    this.grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
  }

  private onClick(e: MouseEvent): void {
    // Cell owns its own click — never delegate to row.
    e.stopPropagation()

    if (e.detail > 1) return // second click of a double-click — skip
    if (this.isEditing) return // editor open — preserve selection

    const trigger = this.grid.options.editing?.trigger ?? 'doubleClick'
    if (
      trigger === 'click' &&
      this.resolveEditable() &&
      !e.shiftKey &&
      !e.ctrlKey &&
      !e.metaKey
    ) {
      const cell: CellPosition = {
        rowId: this.rowId,
        columnId: this.columnId,
        rowIndex: this.rowIndex,
        columnIndex: this.columnIndex,
      }
      this.grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
      return
    }

    const selection = this.grid.options.selection
    const selectionMode = selection?.mode ?? 'none'
    const selectOnRowClick = selection?.selectOnRowClick ?? true
    const checkboxOnly = selection?.checkboxOnly ?? false
    if (selectionMode === 'none' || !selectOnRowClick || checkboxOnly) return

    const editingEnabled = this.grid.options.editing?.enabled ?? false
    const hasModifier = e.shiftKey || e.ctrlKey || e.metaKey
    // If editing is enabled, preserve selection for plain clicks on an already
    // selected row — user may be about to double-click to edit.
    if (editingEnabled && !hasModifier) {
      const { selectedIds } = this.grid.kernel.store.read('selection')
      if (selectedIds.has(this.rowId)) return
    }

    this.grid.kernel.eventBus.emit(GridEvent.ROW_CLICK_SELECTION, {
      rowId: this.rowId,
      shiftKey: e.shiftKey,
      ctrlKey: e.ctrlKey,
      metaKey: e.metaKey,
    })
  }
}
